pfDB["quests"]["enUS-turtle"] = {
  [1] = "_",
  [73] = "_",
  [105] = {
    ["D"] =
    "Alas, the time to attack Andorhal and drive out the lich that controls it is upon us!$B$BInside the ruins of the city is where the lich - Araj the Summoner - holds dominion.  He is guarded by numerous Scourge surrounding the remains of city\'s center, and his personal retinue of guardians attached to him directly is formidable.  You will need numerous allies to even stand a chance of facing him successfully.$B$BDestroy Araj, $N, and bring me a shard from his phylactery as proof!",
    ["O"] = "Bring Araj\'s Phylactery Shard to High Executor Derrington at the Bulwark, Western Plaguelands.",
    ["T"] = "Alas, Andorhal",
  },
  [108] = "_",
  [129] = {
    ["D"] =
    "Can you do me a favor? I\'ve prepared a lunch for Guard Parker, but he\'s out on patrol... he\'s a big, strong Stormwind guard who can defend himself, but it\'s much too dangerous out there for a townsperson like me.$B$BSo if you deliver his lunch for me and come back here, I\'ll give you a free lunch! Parker patrols the stretch of road leading to Duskwood.",
    ["O"] = "Bring Parker\'s lunch to Guard Parker.  He patrols the road leading to Darkshire.",
    ["T"] = "A Free Lunch",
  },
  [137] = "_",
  [172] = {
    ["D"] =
    "You\'re willing to help us here at the orphanage?  Bless you, friend; your aid during Children\'s Week will be invaluable.$B$BTake this whistle.  You will only be able to use it for a short amount of time - typically not longer than Children\'s Week itself.  When you use it, you will be able to talk with the child you\'ve agreed to look after.  Using it again will dismiss the child.$B$BBy all means $N - use the whistle and meet your ward!  I\'m sure the child will be most eager to meet you.",
    ["O"] = "Use the Orcish Orphan Whistle to talk with the child you will be looking after during Children\'s Week.",
    ["T"] = "Children\'s Week",
  },
  [211] = {
    ["D"] =
    "Alas, the time to attack Andorhal and drive out the lich that controls it is upon us!$B$BInside the ruins of the city is where the lich - Araj the Summoner - holds dominion.  He is guarded by numerous Scourge surrounding the remains of city\'s center, and his personal retinue of guardians attached to him directly is formidable.  You will need numerous allies to even stand a chance of facing him successfully.$B$BDestroy Araj, $N, and bring me a shard from his phylactery as proof!",
    ["O"] = "Bring Araj\'s Phylactery Shard to Commander Ashlam Valorfist at Chillwind Camp, Western Plaguelands.",
    ["T"] = "Alas, Andorhal",
  },
  [236] = {
    ["D"] =
    "A few weeks ago, I dispatched Watcher Callahan and a few others to the northern border of Duskwood to deal with the wolf infestation. I haven\'t heard word from him for quite some time. If he followed my instructions, he\'ll be camped out on the road north from Darkshire. $B$BIf it\'s on your way, please check up on him and inform him that I am awaiting a progress report from him.",
    ["O"] = "Speak with Watcher Callahan.",
    ["T"] = "Watcher Callahan",
  },
  [241] = "_",
  [242] = "_",
  [259] = "_",
  [260] = "_",
  [279] = {
    ["D"] =
    "Murlocs are crawling out from the deep waters and building their villages on the coastline.  They are harassing our fishers and merchants and must be stopped.$B$BOne of these murlocs, Gobbler, skulks with other bluegill murlocs and harries merchants along the road, always then retreating to the safety of the nearby murloc hovels.  Our merchants are in jeopardy, and we will pay to secure them.$B$BGobbler prowls the river inlet north of here.  Find him, slay his kin, and bring me his head.",
    ["O"] =
    "Kill 12 Bluegill Murlocs.$B$BSlay Gobbler and take his head.$B$BBring Gobbler\'s Head to Karl Boran in Menethil Harbor.",
    ["T"] = "Claws from the Deep",
  },
  [316] = "_",
  [352] = "_",
  [390] = "_",
  [406] = "_",
  [462] = "_",
  [490] = "_",
  [497] = "_",
  [534] = "_",
  [539] = {
    ["D"] =
    "The Hillsbrad Town Registry indicates that the Azurelode Mine is under Alliance control. Furthermore, the mine is a prime source of iron ore for the Alliance armories.$b$bEven though we\'ve struck a decisive blow to the town of Hillsbrad, the Alliance still supports and protects the Azurelode Mine fervently.$b$bThe mine lies due south of Hillsbrad. Go there and slay the foreman, a human by the name of Bonds. Kill his miners as well. That should send a clear message to the Alliance.",
    ["O"] = "Kill Foreman Bonds and 10 Hillsbrad Miners and report back to Darthalia in Tarren Mill.",
    ["T"] = "Battle of Hillsbrad",
  },
  [548] = "_",
  [551] = {
    ["D"] =
    "This parchment is enchanted with a spell, rendering it indecipherable.  But one word at the top of the paper can be read:$B$B$B     Nagaz$B$B",
    ["O"] = "Take the Ensorcelled Parchment to Loremaster Dibbs in Southshore.",
    ["T"] = "The Ensorcelled Parchment",
  },
  [620] = "_",
  [774] = "_",
  [785] = "_",
  [790] = {
    ["D"] =
    "$C! I thought I would die out here with none to know of it. While I was hunting the scorpids of the Valley, I came across a particularly vicious-looking one. Hurling myself at it, I managed to inflict a massive blow to its claw before it closed around my leg.$b$bI wasn\'t ready for its stinger though, and it sliced down and into my chest, cutting into my flesh and letting my blood.$b$bPlease, you must kill the scorpid for me! My honor must be upheld! I fought it up on the plateau to the south.",
    ["O"] = "Kill Sarkoth and bring his claw back to Hana\'zua.",
    ["T"] = "Sarkoth",
  },
  [796] = "_",
  [797] = "_",
  [798] = "_",
  [799] = "_",
  [800] = "_",
  [801] = "_",
  [802] = "_",
  [803] = "_",
  [807] = {
    ["D"] =
    "My scouts report that some of the wildlife has become infected with a demonic taint. They wander among their brethren as normal beasts, but evil power flows through them. Burning inside each is a heart scorched by dark magic. These beasts must be destroyed!$B$BIf you find such an animal while you explore, kill it and collect its scorched heart. Bring me what you find through your travels for study and then I\'ll have them destroyed.",
    ["O"] = "Bring 5 Scorched Hearts to Orgnil Soulscar in Razor Hill.",
    ["T"] = "[Deprecated] Durotar Scouring",
  },
  [810] = {
    ["D"] =
    "You would do well to learn how dangerous this land can be, $c. The wildlife here can teach us incredible things, if we are wise enough to listen to their lessons.$B$BThe scorpids are a perfect example of survival in Durotar. While the land has become harsh and more unforgiving, their hardened carapaces protect them from the brutal sun and the deadly weapons of hunters. We could be wise to take on some of their strength as they now dominate the environment.$B$BBring me 6 Small Scorpid Carapaces from the Clattering Scorpids, $N, and I will see to your reward.",
    ["O"] = "Bring 6 Small Scorpid Carapaces to Kor\'ghan in Sen\'jin Village.",
    ["T"] = "Study to Survive",
  },
  [811] = {
    ["D"] =
    "One of the other traits of the scorpids is their fierce loyalty. They will protect one another at personal risk - you\'ve probably already seen this behavior during your first hunt. You\'d do well to heed that lesson and adapt it to yourself: we are stronger as one; we are weak when divided.$B$BBring me 8 Large Scorpid Carapaces from Armored Scorpids and I\'ll grant you another reward.",
    ["O"] = "Bring 8 Large Scorpid Carapaces to Kor\'ghan in Cleft of Shadows.",
    ["T"] = "Unity is Strength",
  },
  [814] = {
    ["D"] =
    "Cook and clean--that\'s all I do!$B$BYou want to eat, you get me some more meat! I don\'t have all day to hunt and prepare food for all these louses. You got to learn to pull your own weight around here if you wanna be treated equal.$B$BGet me some Chunks of Boar Meat if you want to make yourself useful... or you don\'t want to starve to death.",
    ["O"] = "Bring 10 Chunks of Boar Meat to Cook Torka in Razor Hill.",
    ["T"] = "Work for Food",
  },
  [820] = {
    ["D"] =
    "Truly a spirit of strength resides in your body, willing to help an old man brew his potions.$B$BThe generosity found in our new home and the strength of relying on our allies is what sets us apart from others, $c.$B$BI need one more thing to begin brewing a batch of my potion, eight shimmerweed.$B$BYou can find the herbs northwest of Razor Hill in Thunder Ridge, and be careful, $N.",
    ["O"] = "Bring 8 Shimmerweed to Master Vornal in Sen\'jin Village.",
    ["T"] = "What Do You Rely On?",
  },
  [832] = {
    ["D"] =
    "<Words emanate from the pendant and into your mind.>$B$BGazz\'uz?$B$BGazz\'uz... report!$B$BThere is word of your discovery in Skull Rock. You must prepare for an attack!$B$BGazz\'uz, I order you to speak!$B$BSpeak or I will make sure Neeru Fireblade knows of your presence, and he will descend on you with swift brutality.$B$BDo not test your skills against Neeru...$B$B...Gazz\'uz, are you there...?",
    ["O"] = "Take this eye to Neeru Fireblade.",
    ["T"] = "Burning Shadows",
  },
  [839] = "_",
  [856] = "_",
  [881] = {
    ["D"] =
    "Whitemist, Echeyakee in the Tauren tongue, is the king of the savannah cats. He hunts with such stealth, they say he\'s like a thin, white mist on the earth. And he kills so fast his prey have no time for fear, or pain.$B$BThe Tauren say he is both mercy and death.$B$BYou will learn if that\'s true, for I now set you on the path to hunt Echeyakee. His lair is northeast of the Crossroads, among the bones of giant Kodo.$B$BGo. Blow this horn when you reach his lair. Blow the horn, and he will come.",
    ["O"] = "Bring Echeyakee\'s Hide to Sergra Darkthorn at the Crossroads.",
    ["T"] = "Echeyakee",
  },
  [904] = "_",
  [912] = "_",
  [942] = {
    ["D"] =
    "This fossil bears a striking resemblance to one I once saw in Ironforge. An archaeologist by the name of Flagongut brought it to our annual Explorers\' League conference. He believed the fossil had a power which could be unlocked somehow.$b$bLast I heard Flagongut had holed up in the Deepwater Tavern in Menethil Harbor, awaiting escort to the Whelgar Excavation Site. Seek him out and show him Remtravel\'s fossil. Perhaps he can reveal the secrets of the past.$b$bThe ship to Menethil departs from Theramore.",
    ["O"] = "Take the mysterious fossil to Archaeologist Flagongut in Menethil Harbor.",
    ["T"] = "The Absent Minded Prospector",
  },
  [946] = "_",
  [969] = {
    ["D"] =
    "Ah, I can tell just by lookin\' at ya -- you be wantin\' to make a lucky charm. Mau\'ari always knows!$B$BTo da south. you\'ll find a canyon, an\' giants made a\' solid ice. The giants sometimes be carryin\' dem, but ya can always gather da shards yerself from da canyon. These shards have a powerful reflective quality.$B$BBring back 10 frostmaul shards, and my lucky charm will be yours.",
    ["O"] = "Collect 10 Frostmaul Shards for Witch Doctor Mau\'ari in Everlook.",
    ["T"] = "Luck Be With You",
  },
  [987] = "_",
  [999] = "_",
  [1005] = "_",
  [1006] = "_",
  [1032] = {
    ["D"] =
    "I can\'t believe that Anilia is gone... We used to play together in the forests all the time. I almost feel... sad.$B$BI know something that might make me feel better. Please, slay the satyrs that took Anilia from me! Bring me their horns as proof of your actions and you will forever have my gratitude.$B$B",
    ["O"] = "Bring 16 Satyr Horns to Illiyana in the Shrine of Aessina.",
    ["T"] = "Satyr Slaying!",
  },
  [1072] = {
    ["D"] =
    "The device I\'m thinking about is my most advanced version to date. But we\'ll need a special potion if it\'s to work. I\'m thinking we might as well get the good stuff since this mission could be your last.$B$BAnd for that, we\'re going to need some potent explosives: Nitromirglyceronium.$B$BThe only person who can make NG-5 is an old friend of mine: Lomac Gearstrip. Look for him in the Gnomeregan Reclamation Facility.$B$BYou talk him into making us some NG-5, I\'ll get to work on placement for my devices.",
    ["O"] = "Speak to Lomac Gearstrip at the Gnomeregan Reclamation Facility in Dun Morogh.",
    ["T"] = "An Old Colleague",
  },
  [1073] = {
    ["D"] =
    "Hahaha... you need Nitromirglyceronium to stop goblins from destroying a forest?!$B$BI don\'t care if you know Gaxim or not... I\'ll give you the stuff just to see you or them explode into itty bitty pieces.$B$BThere\'s a problem though: I\'m all out.$B$BBut I\'ll tell you what, you bring me the correct potions, and I\'ll make some up for you right away.$B$BThe least you can do is prove you\'ve got some skill as an alchemist before I just give you a sample of my greatest creation.",
    ["O"] =
    "Bring 4 Minor Mana Potions and 2 Elixirs of Fortitude to Lomac Gearstrip at the Gnomeregan Reclamation Facility in Dun Morogh.",
    ["T"] = "Ineptitude + Chemicals = Fun",
  },
  [1099] = "_",
  [1155] = "_",
  [1156] = "_",
  [1157] = {
    ["D"] = "TODO",
    ["O"] = "TODO",
    ["T"] = "Alexstrasza",
