  [8411] = {
    ["D"] =
    "Welcome, $c.  You bring me the elements and then we do the talkin\'.$b$bThe fire, the air, the water, and the earth I be needin\' before I trust ya, mon.  I gots to know you be knowledgeable.",
    ["O"] = "Bring the elements earth, air, fire and water to Bath\'rah the Windwatcher.",
    ["T"] = "Mastering the Elements",
  },
  [8415] = {
    ["D"] =
    "Commander Ashlam Valorfist has sent out a call for a paladin of your purity and valor, $n.  You can find him at Chillwind Camp in the southern part of the Western Plaguelands.  Seek him and aid in his cause for the Light!",
    ["O"] = "Speak to Commander Ashlam Valorfist at Chillwind Camp.",
    ["T"] = "Chillwind Point",
  },
  [8426] = {
    ["D"] =
    "The battle in Warsong Gulch against the Silverwing Sentinels is of great importance.  Under the guise of protecting a forest that doesn\'t belong to them, the Alliance seeks to deny the Horde one of our largest sources for lumber.$B$BDo not let this happen, $N!  Come back to me with proof of serving the Horde in a worthy manner!",
    ["O"] = "Bring 3 Warsong Marks of Honor to a Horde Warbringer outside the battlegrounds.",
    ["T"] = "Battle of Warsong Gulch",
  },
