  [41467] = {
    ["D"] =
    "As a Watcher, I was allowed access to many of Medivh\'s personal effects. Among those items, I found the tomes most enlightening. While the majority of the books were filled with - to put it bluntly - tripe, there were some gems. One of those tomes documented the creation of a set of armor fit for an archmage: Frostfire.$B$B<Angela points to her head.>$B$BYou might be able to find a ring bearing that name, were it not to suit your abilities–with the knowledge I hold we can mold it for you.",
    ["O"] = "Trade in your current item for the item that best suits your needs.",
    ["T"] = "Frostfire Ring",
  },
