  [41515] = {
    ["D"] =
    "You have claimed the garments of Earthfury, $C. I can sense the will of the elements and your might, yet it seems rather dim. Perhaps the ones you carry are not suited for the tasks you are willing to perform.$B$B<Kazud hums for a few seconds.>$B$BHand it here and tell me, how should the elements aid you?",
    ["O"] = "Trade in your current item for the item that best suits your needs.",
    ["T"] = "Earthfury Legs",
  },
  [41516] = {
    ["D"] =
    "You have claimed the garments of Earthfury, $C. I can sense the will of the elements and your might, yet it seems rather dim. Perhaps the ones you carry are not suited for the tasks you are willing to perform.$B$B<Kazud hums for a few seconds.>$B$BHand it here and tell me, how should the elements aid you?",
    ["O"] = "Trade in your current item for the item that best suits your needs.",
    ["T"] = "Earthfury Boots",
  },
  [41517] = {
    ["D"] =
    "Would you honor me by returning the armor of those that fell in the defense of these lands?$B$BIn your many hardships you will also find a desecrated signet. With it, your armor will be complete.$B$BIt may have not been forged to mold around the use of your skills, fret not. Return it to me and I will change it for you.",
    ["O"] = "Trade in your current item for the item that best suits your needs.",
    ["T"] = "Ring of the Earthshatterer",
  },
  [41518] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Staves",
  },
  [41519] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. Who would have thought that something as simple as fighting with staves could fill entire volumes? What captures your interest most is a brief section about the Pandaren, an enigmatic race of bear-like humanoids from across the sea. Apparently, they are renowned as the unparalleled masters of staff combat. Intrigued, you decide to bring the book to Nora.>",
    ["O"] = "Bring the Mastery of Staves book to Nora Steamsight on Fray Island.",
    ["T"] = "Staff Meeting",
  },
  [41520] = {
    ["D"] =
    "We are often visited by the Theramore soldiers, and they always tell this story.$B$BPicture this: during the siege, those who stood by Jaina and Thrall\'s New Horde had an extraordinary ally—a pandaren Brewmaster named Chen Stormstout. I\'m talking about someone who fought with such passion and skill, it was like watching a whirlwind of power and precision! Chen\'s mastery with his staff was nothing short of legendary.$B$BBut get this—after the battle, the guy just planted his Brewmaster staff right into the ground and walked off into the horizon. Can you believe it? They say the fight was so brutal and intense that he just couldn\'t bear to be reminded of it ever again.$B$BNow, I\'m not saying this story is gospel, but if there\'s any truth to it, Master Brightheart would be over the moon if we could recover that Pandaren staff! Just imagine what we could learn from its design and construction. It could totally revolutionize our understanding of weapon craftsmanship!",
    ["O"] = "Recover the Staff of Chen for Mathias Brightheart on Fray Island in the Barrens.",
    ["T"] = "Stormstout Legacy",
  },
  [41521] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Thrown",
  },
  [41522] = {
    ["D"] =
    "<The weighty tome stands as a testament to Master Mathias\' unwavering dedication to the art of war. Merely flipping through its pages leaves a formidable impression, showcasing meticulous accounts of Amani trolls, techniques for wielding various thrown weapons, and the intricate art of throwing glaives. However, historical knowledge alone does not equate to mastery. Since you must return the book to Nora, perhaps she can aid you in applying its teachings practically.>",
    ["O"] = "Bring the Mastery of Thrown book to Nora Steamsight on Fray Island.",
    ["T"] = "Throwing Hands",
  },
  [41523] = {
    ["D"] =
    "Master Brightheart has expressed a keen interest in obtaining a set of peculiar throwing axes crafted by the Amani trolls. Regrettably, ever since Arthas ravaged Quel\'Thalas, news from Zul\'Aman has been scarce, and no merchant in their right mind ventures there to trade with the Amani. These axes were rare even before the war; now, they are almost unattainable.$B$BHowever, there is a glimmer of hope. These axes are typically wielded by high-ranking Amani Chieftains. One such chieftain, War Master Voone, is loyal to the Old Horde rather than Zul\'Jin. It is rumored that he possesses these coveted weapons, though he is unlikely to part with them willingly.$B$BShould you succeed in acquiring them, deliver them to Master Brightheart. He will provide you with further instructions for sure!",
    ["O"] = "Acquire the Throwing Axes of the Amani and offer it to Mathias Brightheart on Fray Island in the Barrens.",
    ["T"] = "Throwing Axes of the Amani",
  },
  [41524] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Guns",
  },
  [41525] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. The book goes on and on contradicting itself most of the time since it claims the gun is both useful and flawed. While its destruction power is grandly considered its loudness and requirement of powder is a considerable drawback. As a researcher, Nora might have more insight to offer.>",
    ["O"] = "Bring the Mastery of Guns book to Nora Steamsight on Fray Island.",
    ["T"] = "One Bullet at a Time",
  },
  [41526] = {
    ["D"] =
    "I am rather confused, truth be told. It is true guns are loud yet still effective, but how does one accept that and willingly use them? We must see someone using this in action, perhaps it will inspire you to use them as well.$B$BInformation I hold speaks plainly about the most logical place to find a gun user–Blackrock Depths, it holds the capital of the Dark Irons dwarves. Bound to have at least one gun user, but just so that I don\'t send you blindly inside I know the name of the man that you must hunt. Journey to the Blackrock Depths, find and slay Houndmaster Grebmar and return some blackrock powder to the master if you happen to find some.",
    ["O"] = "Return the Blackrock Powder to Mathias Brightheart, on Fray Island.",
    ["T"] = "Blackrock Powder",
  },
  [41527] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Crossbows",
  },
  [41528] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. A detailed history of the crossbow\'s invention and refinement can be surmised from it, yet you feel like the true essence and connections of it all elude you. As you need to return the book to this Nora either way, perhaps she can assist you in comprehending it more.>",
    ["O"] = "Bring the Mastery of Crossbows book to Nora Steamsight on Fray Island.",
    ["T"] = "Crossing The Line",
  },
  [41529] = {
    ["D"] =
    "You might\'ve read about them already in the book before, but there are a whole of three chapters dedicated to the achievements of the Willey family and their breakthroughs in crossbow development. None other manufacturers in recent history perfected the creation of crossbows like they did. Formerly in service to King Tereneas II of Lordaeron, they fell victim to his son\'s crusade and were soon forgotten about. A legacy of generations, wiped out in an instant. Atleast we assumed so - with the rise of the Scarlet Crusade, the name Willey rose up again. Now a general within said zealous organisation, he commands their artillery; utilizing the knowledge of countless generations before him.$B$BMaster Mathias showed interest in one of his family\'s crossbows, but never came to find a way to find one - until now. Willey is holding the Scarlet Bastion against the undead hordes of Stratholme. Seek his armory and find a Willey family crossbow; once you have it, bring it directly to Mathias!",
    ["O"] = "Present Mathias Brightheart on Fray Island with a Willey family crossbow.",
    ["T"] = "A Crimson Stake Through Their Heart",
  },
  [41530] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Bows",
  },
  [41531] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. A manifesto over centuries of Night Elf archery, the early beginnings of Arathi bow crafting and the strange techniques used by the Zandalari trolls are but a fraction of the wisdom contained in these pages. Feeling overwhelmed, you ponder if this Nora Sakgoth mentioned could help you make the most use out of it.>",
    ["O"] = "Bring the Mastery of Bows book to Nora Steamsight on Fray Island.",
    ["T"] = "Let The Arrow Fly",
  },
  [41532] = {
    ["D"] =
    "I have read about an ancient bow, a weapon from times long forgotten. It dates way back to the time before the Sundering! A certain type of Highborne bow that forces the wielder to adapt to a specific technique, otherwise it would not properly shoot its arrows! It seems the archers of that time used this method to achieve incredible speed and accuracy - exactly what the master\'s looking for.$B$BWhile I arrange a lesson with the master, it\'s up to you to actually get your hands on one of those bows. But a Highborne weapon… There are many of their ruins strewn about Kalimdor, the largest being the Ruins of Dire Maul. I\'d say those are your best bet. Best of luck to you, zealous student. Should you succeed, please bring the bow directly to Master Mathias!",
    ["O"] = "Acquire the Highborne bow and offer it to Mathias Brightheart on Fray Island in the Barrens.",
    ["T"] = "The Bow of Oaks",
  },
  [41533] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Polearms",
  },
  [41534] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. Polearms are described as effective and strong. Due to their long shaft the wielder can strike without engaging in direct close combat. It is stated that human armies preferred using them in battle against orcs due to their difference in size. You feel like this type of weapon isn\'t given the respect it deserves and such you seek Nora to learn more.>",
    ["O"] = "Bring the Mastery of Polearms book to Nora Steamsight on Fray Island.",
    ["T"] = "Polearm, Polearm...",
  },
  [41535] = {
    ["D"] =
    "I believe I can understand the way you feel. Perhaps in truth the polearms aren\'t given the respect they deserve since other warriors would claim it as a last choice. But it is a matter of preference and skill. You see, Mathias says every type of weapon serves a purpose and its strength comes from its wielder.$B$BFriend of mine from Tanaris sent me a word. It seems the local dragon population has opened its caverns to adventurers, seeking to send them beyond the reason of time and space. This friend of mine is a great gossiper you see. Whispers speak of a tall dragonkin holding a spear, one that appears like a toothpick in its hands.$B$BIt appears this creature called Chronar claimed the weapon after he was stabbed with it by a human in one of his personal time shenanigan adventures. Forgive my nonchalance when it comes to it but I hold no dear interest in time travel magic and whatever includes it. Journey there and see how Chronar wields it.",
    ["O"] = "Return the Time-Worn Spear to Mathias Brightheart, on Fray Island.",
    ["T"] = "Appreciated in Time",
  },
  [41536] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Swords",
  },
  [41537] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. It describes the Battle of Darrowshire and a certain Scourge Warlord that sealed the fate of it. The book describes his actions as vile and cruel yet misses no opportunity to describe the swords that Marduk the Black used. Confused by the admiration offered to such a monster the blood inside your veins begins to boil as you make your way towards Nora.>",
    ["O"] = "Bring the Mastery of Swords book to Nora Steamsight on Fray Island.",
    ["T"] = "Scourge of Darrowshire",
  },
  [41538] = {
    ["D"] =
    "There is little we know about the Battle of Darrowshire. After all, none but few survived it. Whispers claim the Scourge Warlord corrupted a human soul which had in turn ended all the efforts of the protectors. The story is told differently everywhere you go. Which is why it is not our focus.$B$BMarduk holds what any other death knight would, a runeblade. One twisted and darkened by the depravity of the Scourge, one named Mournblade. How do we know? Well, you may see he boldly exclaims its name in battle. Your task will be to find him and return the blade for research. Last we know he has drawn back to Scholomance–as a trainer, nonetheless.",
    ["O"] = "Return Mournblade to Mathias Brightheart, on Fray Island.",
    ["T"] = "Mourning Blade",
  },
  [41539] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Hammers",
  },
  [41540] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. The book speaks of the importance of hammers in dwarven culture. While you aren\'t able to make out most of it, the book ends with a legend. Allegedly dwarves used to claim hills and mountains by tossing their hammers into the air, and wherever it landed that was to be their new home. Intrigued by the legend you make your way to Nora.>",
    ["O"] = "Bring the Mastery of Hammers book to Nora Steamsight on Fray Island.",
    ["T"] = "Hammer, Fall!",
  },
  [41541] = {
    ["D"] =
    "Not all dwarves deserve to be admirable, hence some are devoid of honour and morality. Although it pains me to speak so of others, the Dark Irons have earned a reputation that would make most see as unsalvageable.$B$BOnly the future may tell if this is to be true or not–a concern for tomorrow, then. In a frail attempt to serve the will of their master the dwarves of the Blackrock Mountain have called upon their twilight allies and dug a quarry to the east of their land. A despicable man known as Bargul oversees the work there. Rumours claim he bears a hammer called Fingerbreaker–since he uses it to break the fingers of those that do not meet their quota.$B$BYou are to break his bones and retrieve that hammer. While I do not usually wish for others to meet their end, that one deserves what is coming to him.",
    ["O"] = "Return Fingerbreaker to Mathias Brighthear, on Fray Island.",
    ["T"] = "Fingerbreaker",
  },
  [41542] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Axes",
  },
  [41543] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. A study of the Orcish Horde\'s love for axes. Through the pages one name is being honoured several times. Overwhelmed by the deep respect portrayed between the lines you find yourself eagerly pacing towards Nora, so that you may know more.>",
    ["O"] = "Bring the Mastery of Axes book to Nora Steamsight on Fray Island.",
    ["T"] = "The Warsong Echoes",
  },
  [41544] = {
    ["D"] =
    "To many a villainous enemy, to some a chieftain and for few a brother in arms. That is merely the beginning of a description of the man that Grommash Hellscream was. As Mathias travelled here and there, through towns that allowed both Alliance and Horde, he would sometimes be met with the story of Grom, both plague and hero to his people.$B$BLooking beyond the past and actions of this one orc, only one truth stands atop all others–he was a natural born warrior. Even those that\'d spit at the hearing of his name would not shy away from recognizing his skill in battle. Set your feet straight, $N, and ready yourself to pay homage–return with speck of dirt as proof of your travels. Bearing such a gift would reward you the master\'s attention for a while.",
    ["O"] = "Acquire the Jar of Dirt and offer it to Mathias Brightheart on Fray Island in the Barrens.",
    ["T"] = "Honoring the Warrior",
  },
  [41545] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Fist Weapons",
  },
  [41546] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. You begin to realise that you have always been carrying a weapon. Since the dawn of the first races of Azeroth the beginning of evolution itself started with a fist. How else would they have survived and adapted? You stare at your fists with admiration–you need not a weapon if you are the weapon. You are ready to speak with Nora about your newfound admiration of your fists.>",
    ["O"] = "Bring the Mastery of Fist Weapons book to Nora Steamsight on Fray Island.",
    ["T"] = "Fists Against the World",
  },
  [41547] = {
    ["D"] =
    "Let me tell you a story. The story of a nightsaber called Eskhandar, one that hunted in the lands of Feralas. It was such a prestigious beast that it would claw down all of its enemies within seconds. But as with all living things, death follows. And when this beast met its end it was torn apart to use as items. It is believed you can find its mittens somewhere in this vast world and perhaps borrow the power of its former owner.$B$BI believe finding its grave and paying respect to it might earn you its boon from the world beyond our own–if you believe in that sort of thing of course. It fell near the left twin colossal in Feralas. The night elves say that when it died, its blood wet and nourished a dying sapling, a tree growing there now. Seek it and perhaps you will gain something. Return to Mathias afterwards.",
    ["O"] = "Return the Branch of Eskhandar to Mathias Brightheart, on Fray Island.",
    ["T"] = "Legend of Eskhandar",
  },
  [41548] = {
    ["D"] =
    "Now tell me: How does it feel to be proven worthy by the master? When he chose me as his apprentice, it was the greatest honor I ever felt, you surely feel the same.$B$BIf the master wishes to share his knowledge with you, I can assist you with that - for a price, ofcourse. He may be benevolent, but not foolish enough to act in charity, you have to contribute your share of work as well. Hidden within the most dangerous places of Azeroth you will find texts, those from ancient times, containing long forgotten teachings. Find them and with a bit of gold from your end, I can get you on the right track to unlock new battle strategies for you.",
    ["O"] =
    "Present Sakgoth with an Ancient Warfare Text and 250 Gold to gain access to knowledge of the martial arts. He awaits on Fray Island in the Barrens.",
    ["T"] = "Mastery of Daggers",
  },
  [41549] = {
    ["D"] =
    "<The heavy book is a testament to Master Mathias\' rigorous devotion to the art of war. Just trying to get an overview by flipping through the pages makes a daunting expression on you. While much of it revolves around the different shapes and lengths of daggers, as well as parrying and stabbing techniques, the majority of the book is about anatomy: Placement of vital organs, muscle groups, sinew and arteries. Intrigued and overwhelmed all the same, you decide to talk to this Nora about the work of Master Mathias, in hope of understanding more of it.>",
    ["O"] = "Bring the Mastery of Daggers book to Nora Steamsight on Fray Island.",
    ["T"] = "Vital Anatomy",
  },
  [41550] = {
    ["D"] =
    "We\'ve set our eyes on a peculiar set of daggers for a while now. Most would view them as knives, but to a schooled eye like our master\'s, they are deadly weapons of silent murder. They belong to a man named Damian, although he is most commonly known as The Ripper. His past is draped in a bloody curtain, a monster without morals. Yet, even a monster like him can have its purpose.$B$BDamian is held within the Stormwind Vaults, a high facility prison inside the city of the same name. We\'ve heard its occupants broke free due to some supernatural intervention; leaving him to pursue his desires upon anyone left alive. $N, venture inside, relinquish Damian of this set of daggers and bring them to Mathias. Do so and I will make sure he tutors you.",
    ["O"] = "Deliver the Pouch of Surgical Daggers to Mathias Brightheart on Fray Island in the Barrens.",
    ["T"] = "The Ripper",
  },
  [41551] = {
    ["D"] =
    "A pleasure to see you return, my pupil. Rarely do my old students come back to their master for relearning things they already internalized. But I cannot fault you. One\'s mind has only so much expanse and it is only natural for someone as young as yourself to experience other venues as well. Now then, shall we proceed?",
    ["O"] = "Should you wish to relearn Goldsmithing, speak with The Artificer in Desolace once more.",
    ["T"] = "Pupil Once More",
  },
  [41552] = {
    ["D"] =
    "<An expression of joy muses across Thegren\'s face, atleast you surmise is to be one of glee. His gesticulations suggest him wanting you to kneel before him, like you\'ve done many times. The ancient Earthen is eager to become your mentor once more.>",
    ["O"] = "Should you wish to relearn Gemology, speak with Thegren in the Badlands once more.",
    ["T"] = "Renewed Teachings",
  },
  [41553] = {
    ["D"] =
    "Hear ye, hear ye! A one of a kind competition unfolds in the bustling port of Ratchet! Any connoisseur of fine ale, grog and stouts should not miss out on this unparalleled occasion. Grab you drinking buddies and help out in making the perfect alcohol in all of Azeroth!",
    ["O"] = "Travel to Ratchet and join the Brewing Festival activities!",
    ["T"] = "Welcome to the Brewing Festival!",
  },
  [41554] = {
    ["D"] =
    "Hear ye, hear ye! A one of a kind competition unfolds in the bustling port of Ratchet! Any connoisseur of fine ale, grog and stouts should not miss out on this unparalleled occasion. Grab you drinking buddies and help out in making the perfect alcohol in all of Azeroth!",
    ["O"] = "Travel to Ratchet and join the Brewing Festival activities!",
    ["T"] = "Welcome to the Brewing Festival!",
  },
  [41555] = {
    ["D"] =
    "It is my life-long goal to create the most potent, delicious and savoring beverage known to Azeroth: the Hornfang Reserve! Its rich flavour and unique texture will enchant anyone indulging in its foamy top and bitter taste. That is when I am done getting the formula right. I hate to admit it, but my previous attempts at it were falling flat in one way or another. There is always something missing that really brings all of the ingredients together. I just need to find out what it is! That is why I came here to Ratchet, so I can gather all sorts of rumors and stories about potential components that might be missing for my brew.$B$BApparently the local quillboar of the Razorfen Kraul are brewing their own alcohol. Who would\'ve thought that these primitive pig people are able to produce grog on their own? I need to find out what this grog is all about, how it is made and whether it has the secret ingredient I am looking for!",
    ["O"] = "Bring a sample of Razorfen Grog to Hal\'togg Hornfang in Ratchet.",
    ["T"] = "Razorfen Grog",
  },
  [41556] = {
    ["D"] =
    "I think I have a good understanding of how this grog was made. It\'s not unlike what I used to brew before with briarthorn, however they must be utilizing a different method. Maybe they used a higher temperature...? Yes, that must be it! A higher temperature when brewing the briarthorn could reduce the bitterness to an enjoyable amount. How they achieved such a potent flame I still don\'t understand, however. They surely must\'ve used magic. As I have no magical means on my end, we have to find something else. The elements of this world sometimes leave a flicker of their essence behind. One such thing could potentially heat the flame to the required level. $N, go out and bring me elemental fire from any fire elemental out there - we need it to fan the fire!",
    ["O"] = "Return with six Elemental Fire to Hal\'togg Hornfang in Ratchet.",
    ["T"] = "The Hottest Hot!",
  },
  [41557] = {
    ["D"] =
    "Thaldon over there just blabbered about discovering something groundbreaking about the Lordaeron Ale from the Eastern Kingdoms. I cannot let this little man get an advantage over me, which is why we will go even higher! While he is content with his lousy and boring Lordaeron Ale, our goal is the enigmatic Scarlet Schnapps, a brew that so few had the chance to drink, it is said to be a legend.$B$BA culinary peculiarity of the Scarlet Crusade, I have heard they are brewing it in their monastery in the Tirisfal Glades as some sort of light-inducing drink. If this brew really has these magical properties, then I need to get my hands on it!",
    ["O"] = "Retrieve a bottle of Scarlet Schnapps and bring it to Hal\'togg Hornfang in Ratchet.",
    ["T"] = "Scarlet Schnapps",
  },
  [41558] = {
    ["D"] =
    "The Silverpine Forests have a unique vegetation that thrives in the mountainous and harsh reaches of the area. Their flavour is deceptively bitter, so it is rarely used by inexperienced breweries. We, however, can make ample use of this plant. It might not have the properties needed to replicate the fiery feeling of the Scarlet Schnapps, but with the brewing technique of the quillboar, we might be able to distill it enough to acquire a distinct flavour for our own brew.",
    ["O"] = "Hal\'togg Hornfang in Ratchet needs ten bundles of Silver Hops.",
    ["T"] = "Silver Hops",
  },
  [41559] = {
    ["D"] =
    "Finding a plant with a pungent fiery taste can be difficult. Many I\'ve come across in my brewing adventure had a certain spice to them, but nothing to the level of the Scarlet Schnapps. Luckily I picked up some rumours from the goblins at the docks; you\'d be surprised how many stories they pick up with all the trade happening here.$B$BOver in the Eastern Kingdom, the Badlands are home to a vibrant red type of hops. Apparently the resident ogres pick up these clumps of hops and chew on them - raw! These bulky meatheads surprise me anew every time I have to deal with them. Relieve them of their hops and bring it to me, we\'ll make better use of it.",
    ["O"] = "Hal\'togg Hornfang in Ratchet needs fifteen bundles of Red Hops.",
    ["T"] = "Red Hops",
  },
  [41560] = {
    ["D"] =
    "Let us try something unorthodox. Recreating the heat of the Scarlet Schnapps will prove to be a challenge without the same exact recipe, yet I am certain we can try something different instead. The Searing Gorge is a scalding hot desert with little to no vegetation. Nevertheless, some plants seem to grow splendidly on the vulcanic soil - one of them being the black hops. My assumption is that hops absorb the nutrients from the heated ground, naturally imbuing them with a natural smoky spice. The best way to find it out is to grab some and test it out ourselves!",
    ["O"] = "Collect twelve clumps of Black Hops for Hal\'togg Hornfang in Ratchet.",
    ["T"] = "Black Hops",
  },
  [41561] = {
    ["D"] =
    "Okay, $N. We\'re very close to perfecting the formular, I can feel it! We have the silver hops with its heavy earthen bitter flavour, the spice and smoky texture of the red and black hops, as well as the heat and technique needed to distill it into a clear but pungent brew! All we need is that sweet aftertaste to complete the package; and I know the perfect source for it!$B$BDown in the verdant wilds of Feralas lies the dreaded ruins of Dire Maul. Within its cursed gardens grows a root, I believe they call it the Runn Tum Tuber. This root is said to possess a powerful sweet taste, that even survives the highest of temperatures when cooked. We need this root to complete the Hornfang Reserve! We stand at the precipice of greatness, $N. Don\'t waste time!",
    ["O"] = "To complete the Hornfang Reserve, deliver twenty Runn Tum Tubers to Hal\'togg Hornfang in Ratchet.",
    ["T"] = "Runn Tum Rum And The Perfect Brew",
  },
  [41562] = {
    ["D"] =
    "It is my life-long goal to create the most potent, delicious and savoring beverage known to Azeroth: the Thunderbrew Golden Lager! Its rich flavour and unique texture will enchant anyone indulging in its foamy top and bitter taste. Atleast I wish that was the case, but my previous attempts at it were falling flat in one way or another. There is always something missing that really brings all of the ingredients together. I just need to find out what it is! That is why I came here to Ratchet, those dunderheads in Ironforge are all blabbering nonsense out of their unwashed beards. They can\'t see greatness if it bites them in the arse!$B$BTo brew a truly delicious lager, many different types of hops are needed. Since the more common variants of it did not have the potent kick I desire for my brew, I need to look for something unusual. The Quillboar from the deep south of these lands seem to be versed in the art of brewing, or so I heard. They must have their own hops to brew from!",
    ["O"] = "Thaldon Thunderbrew in Ratchet needs fifteen bundles of Yellow Hops.",
    ["T"] = "Yellow Hops",
  },
  [41563] = {
    ["D"] =
    "A sour flavour is something needed in every ale, some have more, some have less of it. The Lordaeron Ale is of the former kind, you won\'t find any alcohol as sour as this beauty. Personally it\'s not my type of drink, but I can appreciate the variety created by different cultures... Even if the way humans are brewing their alcohol is just child\'s play. Ha!$B$BStill, we can use their resources just the same. In the southeastern hills of Hillsbrad grows the Hillsbrad Hops, a truly unique hops with the most pungent sour flavour in all of the Eastern Kingdom. I will need these for my new brewing attempt!",
    ["O"] = "Thaldon Thunderbrew in Ratchet needs twelve bundles of Hillsbrad Hops.",
    ["T"] = "Hillsbrad Hops",
  },
  [41564] = {
    ["D"] =
    "I may be a proud Ironforge dwarf, but even I have to acknowledge the fine ales and grogs our Wildhammer brethren are producing. Rarely have I had the pleasure of enjoying such an extremely bitter stout. Just one sip blew me off my boots, it was an experience like no other! This kind of bitterness needs to be in my perfect ale, it has to! A good friend of mine told me that the most bitter hops grow in the Hinterlands, just short of Aerie Peak. My brew cannot be complete without the powerful bitter flavour of this hops.",
    ["O"] = "Thaldon Thunderbrew in Ratchet needs ten bundles of Stout Hops.",
    ["T"] = "Stout Hops",
  },
  [41565] = {
    ["D"] =
    "You may have caught on to it already, but this amateur of an orc over there thinks he can create a brew better than what us dwarves can produce. If you ask me, a fool\'s errand. But I am no fool myself, so we have to make sure his ambitions fall flat on its face.$B$BI overheard him eagerly announce using elemental fire to stoke his distillery fire, so we will make use of the elements ourselves. Seems only fair, no? I already began brewing the hops you gave me, but they are not properly blending together. Elemental water may just be the thing to circumvent this problem - and on top of it, it may even add an extra kick to the concoction!",
    ["O"] = "Return with six Elemental Water to Thaldon Thunderbrew in Ratchet.",
    ["T"] = "With A Twist Of Magic!",
  },
  [41566] = {
    ["D"] =
    "I\'ve stumbled on a... let\'s say ‘small\' issue with my current brew. Mixing the three types of hops together was a brilliant idea, yet the bitterness of the stout hops is overpowering every other flavour! If we keep the distillate as is, I might as well just brew with stout hops. Good thing for us, I picked up a rumour down at the port that might be exactly the solution to our problem. Goldthorn Grog is a brew that should taste incredibly bitter as all grogs are, yet its flavour is surprisingly smooth and mild, a perfect afternoon drink! I suspect the secret ingredient for that is the Goldthorn itself. With a few roots, I could test if my theory has any merit.",
    ["O"] = "Bring ten Goldthorn to Thaldon Thunderbrew in Ratchet.",
    ["T"] = "Goldthorn Grog",
  },
  [41567] = {
    ["D"] =
    "$N! It\'s a disaster! I was just checking my tent for more ingredients when I noticed my plans for the Thunderbrew Golden Lager weren\'t there! It must have been those damned Hurley Blackbreath, he and his kin have been rivals to our family since countless years. They can\'t live with the fact that our beer is the superior one, not like their lukewarm sludge soup. We need to get it back. The recipe contains the last few crucial steps required to finalize my perfect brew. Blackbreath surely scuttled back into the Blackrock Depths, find him and bring me back my plans!",
    ["O"] = "Retrieve the Thunderbrew Golden Lager Plans for Thandol Thunderbrew in Ratchet.",
    ["T"] = "Our Dark Iron Rivals",
  },
  [41568] = {
    ["D"] =
    "We have the hops, our magical component and the Goldthorn to reduce the bitterness of it all. With my plans back with me, there is just one thing left to finalize the Thunderbrew Golden Lager: The Golden Hops.$B$B An ingredient of mythological status, many dwarves believe it to be a mere fairy tale told by the drunken mountaineers of Ironforge\'s taverns. But I know better - I have seen it! It appeared to me in a dream, after emptying ten ale kegs on my own. A golden rabbit, shimmering like the finest beer you\'ve ever seen. There it stood, ominously between these great bones in a vast desert, like an omen. Yet I knew what it really meant. It beckoned me to seek it out; to create the Golden Lager with the Golden Hops! Find this rabbit, wherever it may be. The Golden Hops will be ours!",
    ["O"] = "Find the mythical Hoppity Hops Rabbit and acquire the Golden Hops for Thandol Thunderbrew in Ratchet.",
    ["T"] = "Great Golden Hops",
  },
  [41569] = {
    ["D"] =
    "Oy, I\'m telling ya, there\'s nothing more invigorating than pouring beer after beer after beer down your threat and getting into the rhythm of the festival. Come, grab your pint and start shaking those hips! I wanna see you get completely smashed, dancing with everybody here. Cheers!",
    ["O"] = "Dance with members of the Horde and Alliance while completely drunk!",
    ["T"] = "Shut Up And Dance With Me",
  },
  [41570] = {
    ["D"] =
    "Oy, I\'m telling ya, there\'s nothing more invigorating than pouring beer after beer after beer down your threat and getting into the rhythm of the festival. Come, grab your pint and start shaking those hips! I wanna see you get completely smashed, dancing with everybody here. Cheers!",
    ["O"] = "Dance with members of the Horde and Alliance while completely drunk!",
    ["T"] = "Murder On The Dancefloor",
  },
  [41571] = {
    ["D"] =
    "Oy, I\'m telling ya, there\'s nothing more invigorating than pouring beer after beer after beer down your threat and getting into the rhythm of the festival. Come, grab your pint and start shaking those hips! I wanna see you get completely smashed, dancing with everybody here. Cheers!",
    ["O"] = "Dance with members of the Horde and Alliance while completely drunk!",
    ["T"] = "Dance The Night Away",
  },
  [41572] = {
    ["D"] =
    "Oh my, good gracious! Is this how you want to go see the Guardian? Bold, I must say, but perhaps a tad too bold. I cannot for the love of all that encompasses fashion allow you to ascend the tower in those rags. Harsh as it may sound, it is the truth!$B$BJust looking at that headdress you\'re wearing gives me the creeps and shivers. Whoever designed this atrocity deserves to be put to trial. I can help you out and get you the designs of a new, more fashionable one - if you help me out with some of my own supplies. We have a deal?",
    ["O"] = "Bring Pietro Paraveno the needed supplies, he awaits in the Tower of Karazhan.",
    ["T"] = "A Hat For The Occasion",
  },
  [41573] = {
    ["D"] =
    "Oh my, good gracious! Is this how you want to go see the Guardian? Bold, I must say, but perhaps a tad too bold. I cannot for the love of all that encompasses fashion allow you to ascend the tower in those rags. Harsh as it may sound, it is the truth!$B$BJust looking at that legwear you\'ve put on your body gives me the creeps and shivers. Whoever designed this atrocity deserves to be put to trial. I can help you out and get you the designs of a new, more fashionable one - if you help me out with some of my own supplies. We have a deal?",
    ["O"] = "Bring Pietro Paraveno the needed supplies, he awaits in the Tower of Karazhan.",
    ["T"] = "Legs For Days",
  },
  [41574] = {
    ["D"] =
    "Oh my, good gracious! Is this how you want to go see the Guardian? Bold, I must say, but perhaps a tad too bold. I cannot for the love of all that encompasses fashion allow you to ascend the tower in those rags. Harsh as it may sound, it is the truth!$B$BJust looking at these pauldrons you\'re wearing gives me the creeps and shivers. Whoever designed this atrocity deserves to be put to trial. I can help you out and get you the designs of a new, more fashionable one - if you help me out with some of my own supplies. We have a deal?",
    ["O"] = "Bring Pietro Paraveno the needed supplies, he awaits in the Tower of Karazhan.",
    ["T"] = "The Weight Of Fashion On Their Shoulder",
  },
  [41575] = {
    ["D"] =
    "Oh my, good gracious! Is this how you want to go see the Guardian? Bold, I must say, but perhaps a tad too bold. I cannot for the love of all that encompasses fashion allow you to ascend the tower in those rags. Harsh as it may sound, it is the truth!$B$BJust looking at that chestpiece you\'re wearing gives me the creeps and shivers. Whoever designed this atrocity deserves to be put to trial. I can help you out and get you the designs of a new, more fashionable one - if you help me out with some of my own supplies. We have a deal?",
    ["O"] = "Bring Pietro Paraveno the needed supplies, he awaits in the Tower of Karazhan.",
    ["T"] = "The Embrace Of Good Taste",
  },
  [41576] = {
    ["D"] =
    "Oh my, good gracious! Is this how you want to go see the Guardian? Bold, I must say, but perhaps a tad too bold. I cannot for the love of all that encompasses fashion allow you to ascend the tower in those rags. Harsh as it may sound, it is the truth!$B$BThat cloak you\'ve draped around you gives me the creeps and shivers. Whoever designed this atrocity deserves to be put to trial. I can help you out and get you the designs of a new, more fashionable one - if you help me out with some of my own supplies. We have a deal?",
    ["O"] = "Bring Pietro Paraveno the needed supplies, he awaits in the Tower of Karazhan.",
    ["T"] = "A Cloak Of Immaculate Quality",
  },
  [41577] = {
    ["D"] =
    "In your hands lies the still-beating heart of the Dreadlord Mephistroth, ruler of the Rock of Desolation. You and your expedition foiled his plans of using Karazhan as an entry point to invade Azeroth yet again. Expelled into the Great Dark Beyond forever, this is all that remains of the nefarious schemer.$B$BYou should bring it to someone able to expunge its life, just to be sure.",
    ["O"] = "Deliver the Heart of Mephistroth to a sorcerer powerful enough to destroy it.",
    ["T"] = "Sovereign of Desolation",
  },
  [41578] = {
    ["D"] =
    "This crown bears the symbol of the Kingdom of Azeroth, and it closely resembles the one King Llane used to wear. Perhaps even in his madness, Medivh still kept his friend close to his heart.$B$BFractured, almost crumbled—just like the Tower of Karazhan, a lost vigil of history. It is upon this history that we may reforge something anew. Bring me the materials I require, and I will ensure that this crown becomes of use to its new bearer.",
    ["O"] = "Gather the required materials for Hierophant Nerseus near the church outside Karazhan.",
    ["T"] = "Helm of the Talon",
  },
  [41579] = {
    ["D"] =
    "I imagine your journey through a brief glimpse of both the Twisting Nether and Outland was not without its share of trouble. Yet, I sense an item in your possession that carries an otherworldly aura.$B$BAllow me to lay eyes upon this mantle. Hm, as far as I can tell, the enemy you faced was indeed formidable—perhaps powerful enough to shift between planes. No matter; while its previous owner lies dead, some of its magic endures. Were you to bring me the materials I require, I could perhaps mold this item to suit your needs.",
    ["O"] = "Gather the required materials for Anelace the Clairvoyant near the church outside Karazhan.",
    ["T"] = "Shoulderguards of the Talon",
  },
  [41580] = {
    ["D"] =
    "Defeating a Nathrezim of such power is no easy feat. Even beyond the veil of life and death, many cursed the existence of the accursed Mephistroth. You could hear the echoes of the tormented souls in the Twisting Nether rejoice the moment the demon lay dead.$B$BAlas, that is neither more nor less important—for not only did you manage to slay such a formidable foe, but you also retrieved its armor. This armor shall serve as the foundation for your next piece of the puzzle; in truth, it may even be considered the final piece. As before, bring me the materials I require, and claim a prize that will make even the mighty Eredar tremble in their boots.",
    ["O"] = "Gather the required materials for Anelace the Clairvoyant near the church outside Karazhan.",
    ["T"] = "Robes of the Talon",
  },
  [41581] = {
    ["D"] =
    "Doomguards were the elite bodyguards of their master—none could face a fiercer enemy, and yet you confronted one of their best. Surviving the wrath of the Highlord would have been a worthy feat in itself, and yet you managed to defeat him.$B$BI sense that you possess something of his—a memento from a worthy battle, one that we could use as the basis for a piece of your armor. What say you? Bring me the materials I require, and we will ensure that you wear this fight both in spirit and upon your body.",
    ["O"] = "Gather the required materials for Hanvar the Righteous near the church outside Karazhan.",
    ["T"] = "Pants of the Talon",
  },
  [41582] = {
    ["D"] =
    "Your journey through a fleeting glimpse of both the Twisting Nether and Outland was not without its hardships. Still, I can sense an item in your possession—a relic that emanates an otherworldly essence.$B$BAllow me to examine these boots. It seems the adversary you faced was indeed formidable, perhaps even capable of traversing the planes. Yet, while its previous owner now lies dead, remnants of its magic persist. What say you? Bring me the materials I require, and I shall forge this item to suit your needs, ensuring you carry the essence of this battle with you.",
    ["O"] = "Gather the required materials for Hanvar the Righteous near the church outside Karazhan.",
    ["T"] = "Boots of the Talon",
  },
  [41583] = {
    ["D"] =
    "This amulet bears the emblem of House Wrynn, a treasured gift bestowed upon Medivh by his friend, King Llane, for the many noble deeds he performed for the people of Stormwind. Even in his madness, Medivh clung to it.$B$BBroken and battered—much like the Tower itself, a once-mighty sentinel of history. Yet perhaps this fragment of the past still holds value. Bring me the materials I require, and I shall see to it that this amulet serves its new bearer well.",
    ["O"] = "Gather the required materials for Hierophant Nerseus near the church outside Karazhan.",
    ["T"] = "Amulet of the Talon",
  },
  [41584] = {
    ["D"] =
    "This crown bears the symbol of the Kingdom of Azeroth, and it closely resembles the one King Llane used to wear. Perhaps even in his madness, Medivh still kept his friend close to his heart.$B$BFractured, almost crumbled—just like the Tower of Karazhan, a lost vigil of history. It is upon this history that we may reforge something anew. Bring me the materials I require, and I will ensure that this crown becomes of use to its new bearer.",
    ["O"] = "Gather the required materials for Hierophant Nerseus near the church outside Karazhan.",
    ["T"] = "Nathrezim Helm",
  },
  [41585] = {
    ["D"] =
    "I imagine your journey through a brief glimpse of both the Twisting Nether and Outland was not without its share of trouble. Yet, I sense an item in your possession that carries an otherworldly aura.$B$BAllow me to lay eyes upon this mantle. Hm, as far as I can tell, the enemy you faced was indeed formidable—perhaps powerful enough to shift between planes. No matter; while its previous owner lies dead, some of its magic endures. Were you to bring me the materials I require, I could perhaps mold this item to suit your needs.",
    ["O"] = "Gather the required materials for Anelace the Clairvoyant near the church outside Karazhan.",
    ["T"] = "Nathrezim Shoulderguards",
  },
  [41586] = {
    ["D"] =
