  [41591] = {
    ["D"] =
    "I imagine your journey through a brief glimpse of both the Twisting Nether and Outland was not without its share of trouble. Yet, I sense an item in your possession that carries an otherworldly aura.$B$BAllow me to lay eyes upon this mantle. Hm, as far as I can tell, the enemy you faced was indeed formidable—perhaps powerful enough to shift between planes. No matter; while its previous owner lies dead, some of its magic endures. Were you to bring me the materials I require, I could perhaps mold this item to suit your needs.",
    ["O"] = "Gather the required materials for Anelace the Clairvoyant near the church outside Karazhan.",
    ["T"] = "Shoulderguards of the Brotherhood",
  },
  [41592] = {
    ["D"] =
    "Defeating a Nathrezim of such power is no easy feat. Even beyond the veil of life and death, many cursed the existence of the accursed Mephistroth. You could hear the echoes of the tormented souls in the Twisting Nether rejoice the moment the demon lay dead.$B$BAlas, that is neither more nor less important—for not only did you manage to slay such a formidable foe, but you also retrieved its armor. This armor shall serve as the foundation for your next piece of the puzzle; in truth, it may even be considered the final piece. As before, bring me the materials I require, and claim a prize that will make even the mighty Eredar tremble in their boots.",
    ["O"] = "Gather the required materials for Anelace the Clairvoyant near the church outside Karazhan.",
    ["T"] = "Chest of the Brotherhood",
  },
  [41593] = {
    ["D"] =
    "Doomguards were the elite bodyguards of their master—none could face a fiercer enemy, and yet you confronted one of their best. Surviving the wrath of the Highlord would have been a worthy feat in itself, and yet you managed to defeat him.$B$BI sense that you possess something of his—a memento from a worthy battle, one that we could use as the basis for a piece of your armor. What say you? Bring me the materials I require, and we will ensure that you wear this fight both in spirit and upon your body.",
    ["O"] = "Gather the required materials for Hanvar the Righteous near the church outside Karazhan.",
    ["T"] = "Pants of the Brotherhood",
  },
  [41594] = {
    ["D"] =
    "Your journey through a fleeting glimpse of both the Twisting Nether and Outland was not without its hardships. Still, I can sense an item in your possession—a relic that emanates an otherworldly essence.$B$BAllow me to examine these boots. It seems the adversary you faced was indeed formidable, perhaps even capable of traversing the planes. Yet, while its previous owner now lies dead, remnants of its magic persist. What say you? Bring me the materials I require, and I shall forge this item to suit your needs, ensuring you carry the essence of this battle with you.",
    ["O"] = "Gather the required materials for Hanvar the Righteous near the church outside Karazhan.",
    ["T"] = "Boots of the Brotherhood",
  },
  [41595] = {
    ["D"] =
    "This amulet bears the emblem of House Wrynn, a treasured gift bestowed upon Medivh by his friend, King Llane, for the many noble deeds he performed for the people of Stormwind. Even in his madness, Medivh clung to it.$B$BBroken and battered—much like the Tower itself, a once-mighty sentinel of history. Yet perhaps this fragment of the past still holds value. Bring me the materials I require, and I shall see to it that this amulet serves its new bearer well.",
    ["O"] = "Gather the required materials for Hierophant Nerseus near the church outside Karazhan.",
    ["T"] = "Amulet of the Brotherhood",
  },
  [41596] = {
    ["D"] =
