  [3090] = {
    ["D"] =
    "Ah, while you were gone a parchment came for you, $N.$B$BI usually avoid dealing with warlocks if I can help it, but I think you should read it when you have time. If I\'m not mistaken, it came from your newly-appointed trainer Nartok. He would have words with you when you\'re ready.",
    ["O"] = "Read the Tainted Parchment and speak to Nartok inside the Den in the Valley of Trials.",
    ["T"] = "Tainted Parchment",
  },
  [3091] = {
    ["D"] =
    "Just a moment ago a messenger was looking for you, $N. I believe she was sent by the warrior trainer Harutt. If this note is from Harutt, I wouldn\'t take long in reading it\'s contents.",
    ["O"] = "Read the Simple Note and speak to Harutt Thunderhorn in Camp Narache.",
    ["T"] = "Simple Note",
