  },
  [7905] = {
    ["D"] =
    "The Darkmoon Faire is coming!  Be sure to experience all the wonders and excitement of it when it comes to town!$B$BIf you act right now, you can redeem this voucher for free prize tickets!  Just hand your voucher to Gelvas Grimgate located inside the carnival.$B$BRight now, the Faire is outside Goldshire, in the Elwynn Forest.  Don\'t miss out!  Go today!",
    ["O"] = "Deliver the Free Ticket Voucher to Gelvas Grimgate, located inside the Darkmoon Faire carnival.",
    ["T"] = "The Darkmoon Faire",
  },
  [7907] = {
    ["D"] =
    "Now that you have gathered all of the Beast cards together into a deck, a ninth card mysteriously appears with the same backing as the first eight.  On this card is inscribed, \"Return these cards to the Darkmoon Faire and be rewarded.\"  You have heard that this faire alternately stops at Mulgore and Goldshire every few months, so you will have to wait until they are here next.",
    ["O"] = "Return the Beast Deck to the Darkmoon Faire when it comes to town.",
    ["T"] = "Darkmoon Beast Deck",
  },
  [7926] = {
    ["D"] =
    "The Darkmoon Faire is coming!  Be sure to experience all the wonders and excitement of it when it comes to town!$B$BIf you act right now, you can redeem this voucher for free prize tickets!  Just hand your voucher to Gelvas Grimgate located inside the carnival.$B$BRight now, the Faire is just outside Thunder Bluff, in Mulgore.  Don\'t miss out!  Go today!",
    ["O"] = "Deliver the Free Ticket Voucher to Gelvas Grimgate, located inside the Darkmoon Faire carnival.",
    ["T"] = "The Darkmoon Faire",
  },
  [7927] = {
    ["D"] =
    "Now that you have gathered all of the Portal cards together into a deck, a ninth card mysteriously appears with the same backing as the first eight.  On this card is inscribed, \"Return these cards to the Darkmoon Faire and be rewarded.\"  You have heard that this faire alternately stops at Mulgore and Goldshire every few months, so you will have to wait until they are here next.",
    ["O"] = "Return the Portals Deck to the Darkmoon Faire when it comes to town.",
    ["T"] = "Darkmoon Portals Deck",
  },
  [7928] = {
    ["D"] =
    "Now that you have gathered all of the Warlord cards together into a deck, a ninth card mysteriously appears with the same backing as the first eight.  On this card is inscribed, \"Return these cards to the Darkmoon Faire and be rewarded.\"  You have heard that this faire alternately stops at Mulgore and Goldshire every few months, so you will have to wait until they are here next.",
    ["O"] = "Return the Warlords Deck to the Darkmoon Faire when it comes to town.",
    ["T"] = "Darkmoon Warlords Deck",
  },
  [7929] = {
    ["D"] =
    "Now that you have gathered all of the Elemental cards together into a deck, a ninth card mysteriously appears with the same backing as the first eight.  On this card is inscribed, \"Return these cards to the Darkmoon Faire and be rewarded.\"  You have heard that this faire alternately stops at Mulgore and Goldshire every few months, so you will have to wait until they are here next.",
    ["O"] = "Return the Elementals Deck to the Darkmoon Faire when it comes to town.",
    ["T"] = "Darkmoon Elementals Deck",
  },
  [7930] = {
    ["T"] = "5 Tickets - Darkmoon Flower",
  },
  [7931] = {
    ["T"] = "5 Tickets - Minor Darkmoon Prize",
  },
  [7932] = {
    ["T"] = "12 Tickets - Lesser Darkmoon Prize",
  },
  [7933] = {
    ["T"] = "40 Tickets - Greater Darkmoon Prize",
  },
  [7934] = {
    ["T"] = "50 Tickets - Darkmoon Storage Box",
  },
  [7935] = {
    ["T"] = "10 Tickets - Last Month\'s Mutton",
  },
  [7936] = {
    ["T"] = "50 Tickets - Last Year\'s Mutton",
  },
  [7937] = {
    ["D"] =
    "\"Your fortune awaits you in Eastvale.\"$B$BThe fortune Sayge handed you feels slightly warm to the touch.  Grasping it firmly, you see an image of the Eastvale Logging Camp in Elwynn Forest.  Focusing closer in on the image, you see a haystack that sits next to a stable.",
    ["O"] = "Travel to the Eastvale Logging Camp in Elwynn Forest and seek out your fortune.",
    ["T"] = "Your Fortune Awaits You...",
  },
  [7938] = {
    ["D"] =
    "\"Your fortune awaits you inside the Deadmines.\"$B$BThe fortune Sayge handed you feels slightly warm to the touch.  Grasping it firmly, you see an image of the Deadmines inside Westfall\'s ruined hamlet of Moonbrook.  Focusing closer in on the image, you wind about twisty passages until you reach a shimmering portal... one that leads into the heart of the mines itself.  Stepping through it, a strange chest appears out from nowhere.",
    ["O"] = "Travel to the Deadmines in Westfall and seek out your fortune.",
    ["T"] = "Your Fortune Awaits You...",
  },
  [7939] = {
    ["T"] = "More Dense Grinding Stones",
  },
  [7940] = {
    ["T"] = "1200 Tickets - Orb of the Darkmoon",
  },
  [7941] = {
    ["T"] = "More Armor Kits",
  },
  [7942] = {
    ["T"] = "More Thorium Widgets",
  },
  [7943] = {
    ["T"] = "More Bat Eyes",
  },
  [7944] = {
    ["D"] =
    "\"Your fortune awaits you inside Wailing Caverns.\"$B$BThe fortune Sayge handed you feels slightly warm to the touch.  Grasping it firmly, you see an image of a cave to the southwest of the Crossroads in the Barrens.  Focusing closer in on the image, you wind about twisty passages until you reach a shimmering portal... one that leads into the heart of the caverns itself.  Stepping through it, a strange chest appears out from nowhere.",
    ["O"] = "Travel to the Wailing Caverns in the Barrens and seek out your fortune.",
    ["T"] = "Your Fortune Awaits You...",
  },
  [7945] = {
    ["D"] =
    "\"Your fortune awaits you outside Palemane Rock.\"$B$BThe fortune Sayge handed you feels slightly warm to the touch.  Grasping it firmly, you see an image of the Palemane Rock of Mulgore.  Focusing closer in on the image, you see a tree stump that sits close to the cave entrance.",
    ["O"] = "Travel to Palemane Rock in Mulgore and seek out your fortune.",
    ["T"] = "Your Fortune Awaits You...",
  },
  [7946] = {
    ["T"] = "Spawn of Jubjub",
  },
  [7981] = {
    ["T"] = "1200 Tickets - Amulet of the Darkmoon",
  },
  [8001] = {
    ["D"] =
    "I am Corpus and you are a wretched speciman, YES! You will do nicely, It has become overcrowded in this town and it is getting harder to find a empty grave. Can you help me get rid of some of the filthy zombies investing my graves, 5 should be enough to guarantee me a resting space.",
    ["O"] = "Kill 5 Wretched Zombies",
    ["T"] = "Zombie Cleansing",
  },
  [8041] = {
    ["T"] = "Strength of Mount Mugamba",
  },
  [8042] = {
    ["T"] = "Strength of Mount Mugamba",
  },
  [8043] = {
    ["T"] = "Strength of Mount Mugamba",
  },
  [8045] = {
    ["T"] = "The Heathen\'s Brand",
  },
  [8046] = {
    ["T"] = "The Heathen\'s Brand",
  },
  [8047] = {
    ["T"] = "The Heathen\'s Brand",
  },
  [8048] = {
    ["T"] = "The Hero\'s Brand",
  },
  [8049] = {
    ["T"] = "The Eye of Zuldazar",
  },
  [8050] = {
    ["T"] = "The Eye of Zuldazar",
  },
  [8051] = {
    ["T"] = "The Eye of Zuldazar",
  },
  [8052] = {
    ["T"] = "The All-Seeing Eye of Zuldazar",
  },
  [8053] = {
    ["D"] =
    "You are a heathen.  Heathens have a place in the tribe.  Heathens are freethinkers of Zandalar.  Freethinkers do not fear oppression.  Freethinkers die for what they believe in.  We know you would die for what you believe in.  This earns our acknowledgement.  This earns you a chance to prove yourself further.$B$BWe must have the Paragons of Power.  Go to Zul\'Gurub.  Kill the minions of Hakkar.  Return when you have what I seek.  Claim the first battle gear of a Zandalar freethinker.$B$BGo.",
    ["O"] =
    "Bring Jin\'rokh the Breaker Primal Hakkari Bindings.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BJin\'rokh the Breaker is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Freethinker\'s Armguards",
  },
  [8054] = {
    ["D"] =
    "Your beliefs are alien to us, heathen.  Ancient Zandalar were once branded as heretics.  This was when the Gurubashi Empire was strong.  Heathens dared to challenge the priest of Hakkar.  Heathens then were hunted and killed as vermin.  Those heathens never wavered in their fight against the Blood God.  We honor the price they paid.  They are the freethinkers.$B$BDestroy the minions of Hakkar in Zul\'Gurub.  Bring me the Paragons of Power I seek.  Success will be greatly rewarded.$B$BGo.",
    ["O"] =
    "Bring Jin\'rokh the Breaker a Primal Hakkari Shawl.  You must also have a reputation equal to or greater than Honored with the Zandalar Tribe.$B$BJin\'rokh the Breaker is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Freethinker\'s Belt",
  },
  [8055] = {
    ["D"] =
    "Battle gear gives you power in the tribe.  The freethinkers are honored in this way.  They are zealots.  They imbue their breastplates with powerful mojo.  If their beliefs falter in the face of the enemy, their breastplate will not.$B$BYou must be revered amongst us to possess such a breastplate.  Go to Zul\'Gurub.  Take the Paragons of Power I need.  Take the Paragons most painfully from the fools inside.  Bring them to me.  Prove your worth as a freethinker once and for all.",
    ["O"] =
    "Bring Jin\'rokh the Breaker a Primal Hakkari Tabard.  You must also have a reputation equal to or greater than Revered with the Zandalar Tribe.$B$BJin\'rokh the Breaker is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Freethinker\'s Breastplate",
  },
  [8056] = {
    ["D"] =
    "The augurs of our tribe are revered for their gifts of the divine sight, ya mon.  They ain\'t a witch doctor; they spend their time castin\' bones or readin\' the leaves for insight - not hexin\' people.  As a shaman, you already know somethin\' about the power of augury; we Zandalar prize the insight they give to the tribe.$B$BBring me an offerin\' of the Paragons of Power from inside Zul\'Gurub and prove your worth to us.  Do this for us, and I\'ll give ya some bracers that our augurs prize above all others!",
    ["O"] =
    "Bring Maywiki of Zuldazar a Primal Hakkari Armsplint.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BMaywiki of Zuldazar is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Augur\'s Bracers",
  },
  [8057] = {
    ["D"] =
    "A haruspex is a key member of our tribe; you\'ll be wise to listen to their portents.  By communion with animals and givin\' them up to the spirits when needed, they give us divine guidance.  In times past, the haruspex\'s insight and wisdom gave us an edge in the wars against the splintered tribes of the Gurubashi.$B$BBring me an offerin\' of the Paragons of Power from inside Zul\'Gurub and prove your worth to us.  Do this, and I\'ll give ya bracers that any haruspex of the Zandalar would want.",
    ["O"] =
    "Bring Maywiki of Zuldazar a Primal Hakkari Stanchion.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BMaywiki of Zuldazar is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Haruspex\'s Bracers",
  },
  [8058] = {
    ["D"] =
    "Vengeance is power.  The Zandalar vindicator is such power.  The tribe has many enemies.  The vindicator exacts retribution on them.  No crime against us is unpunished.  The vindicator delivers this punishment.  Our enemies fear our vengeance.  They should.  They forever will.$B$BBecome one of our vindicators.  Seek the Paragons of Power inside Zul\'Gurub.  Slay the minions of Hakkar and claim vengeance in the tribe\'s name.  You will be rewarded.",
    ["O"] =
    "Bring Jin\'rokh the Breaker a Primal Hakkari Armsplint.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BJin\'rokh the Breaker is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Vindicator\'s Armguards",
  },
  [8059] = {
    ["D"] =
    "Warlocks tread dangerous ground in dealing with demons, but our demoniacs take this one step further.  Through an ancient and arcane ritual, they allow a demon to enter their being.  Rather than let it possess them though, they enslave the demon from the inside, absorbing the power of the beast for their own command.  It is a feat few are ever able to master.$B$BFor you to learn of the power of the demoniac, I must have Paragons of Power from Zul\'Gurub.  Go there and retrieve that which we seek.",
    ["O"] =
    "Bring Al\'tabim the All-Seeing a Primal Hakkari Stanchion.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BAl\'tabim the All-Seeing is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Demoniac\'s Wraps",
  },
  [8060] = {
    ["D"] =
    "Mages in our tribe are known as illusionists.  They employ powerful mojo in their incantations, often befuddling and confusing the tribe\'s enemies!$B$B$B$BIt is quite the sight to see a powerful illusionist at work, bringing our enemies to their knees from their own madness!$B$BFor you to know the way of our illusionists, go to Zul\'Gurub and bring back to me selected Paragons of Power.  For this, I will give you arm wraps our illusionists use to weave their spells.",
    ["O"] =
    "Bring Al\'tabim the All-Seeing Primal Hakkari Bindings.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BAl\'tabim the All-Seeing is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Illusionist\'s Wraps",
  },
  [8061] = {
    ["D"] =
    "We Zandalar invest power in those who speak with the authority of divinity.  Our priests are more than just healers - they are our confessors.  Evil comes both from outside threats - such as Hakkar - and from within the tribe.  Our confessors act as the judges amongst us, preserving us from the same evil that devoured the Gurubashi from inside itself.$B$BGo to Zul\'Gurub and bring back the Paragons of Power from the Gurubashi.  Learn what it means to be the confessor, and preserve us from evil.",
    ["O"] =
    "Bring Al\'tabim the All-Seeing a Primal Hakkari Stanchion.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BAl\'tabim the All-Seeing is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Confessor\'s Wraps",
  },
  [8062] = {
    ["D"] =
    "In the dark times after the fall of the Gurubashi Empire, Zandalar predators used their prowess to provide sustenance for the tribe.  Hunters claim to be much like our tribe\'s predators - to seek the hunt is to embody the essence of the predator, yes.  Your hunt in Zul\'Gurub, however, will show us how you truly rate amongst our finest predators.$B$BBring to me a sampling of the Paragons of Power from within Zul\'Gurub.  Do so, and you\'ll take first steps in becoming the penultimate predator.",
    ["O"] =
    "Bring the following Paragons of Power from Zul\'Gurub to Falthir the Sightless: A Primal Hakkari Bindings.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BFalthir the Sightless is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Predator\'s Bracers",
  },
  [8063] = {
    ["D"] =
    "The madcaps of Zandalar are similar to rogues, but above all else they embrace madness... chaos... the unpredictability of existence.  A terror to behold on the battlefield, they sowed the seeds of confusion and mayhem amongst our enemies in the savage times after the tribes splintered.  We would not be here today without them.$B$BBring to me the Paragons of Power from Zul\'Gurub that I seek, and I will grant you the first of the madcap\'s prized armors.  Embrace the madness!",
    ["O"] =
    "Bring Falthir the Sightless a Primal Hakkari Armsplint.  You must also have a reputation equal to or greater than Friendly with the Zandalar Tribe.$B$BFalthir the Sightless is located on Yojamba Isle, Stranglethorn Vale.",
    ["T"] = "Paragons of Power: The Madcap\'s Bracers",
  },
  [8064] = {
    ["D"] =
    "We Zandalar know not of druidic ways; nature is to be shaped by our need, not the other way around.  Still, a haruspex is the one of us most in tune with nature, and rightly so.  To give up the ghost of a beastie is to know what it is to be one of them.  That is the real power of nature.$B$BBring me an offerin\' of the Paragons of Power from inside Zul\'Gurub, proving yourself to us.  Do this, and I\'ll give ya a powerful item - a belt used by many of the Zandalar\'s haruspices.$B$BStrong mojo, ya mon!",
    ["O"] =
    "Bring Maywiki of Zuldazar a Primal Hakkari Sash.  Maywiki of Zuldazar is located on Yojamba Isle, Stranglethorn Vale. You must also be Honored with Zandalar.",
    ["T"] = "Paragons of Power: The Haruspex\'s Belt",
  },
  [8065] = {
    ["D"] =
    "The ultimate symbol of a haruspex\'s power is what they wear, $N.  Of these, the tunic symbolizes the connection between themselves and the divine wisdom they seek.  It often weaves parts of the beasties they sacrifice into the tunic; this reminds them of the connection they have to their gifts.$B$BBring me an offerin\' of the Paragons of Power from inside Zul\'Gurub and prove your worth to us.  Do this, and a tunic seeping with the true power of a haruspex is yours.",
    ["O"] =
    "Bring Maywiki of Zuldazar a Primal Hakkari Tabard.  Maywiki of Zuldazar is located on Yojamba Isle, Stranglethorn Vale. You must also be Revered with Zandalar.",
    ["T"] = "Paragons of Power: The Haruspex\'s Tunic",
  },
  [8081] = {
    ["D"] =
    "War must be fought with soldiers, any soldier will tell you. They\'ll also say that a battle fought with poor gear or on an empty stomach is lost before it starts!$B$BThat is why Arathi Basin is important. There are key areas in the basin that hold essential resources. Metals, weapons, food, lumber - all are needed, and all can be gained there.$B$BThat is what I want from you, $N. Enter Arathi Basin, win the battle by holding more bases than the enemy, and return to me with a crate of resources.",
    ["O"] =
    "Win the battle for Arathi Basin, get an Arathi Resource Crate, and return it to Sergeant Maclear at Refuge Pointe.",
    ["T"] = "More Resource Crates",
  },
  [8101] = {
    ["T"] = "The Pebble of Kajaro",
  },
  [8102] = {
    ["T"] = "The Pebble of Kajaro",
  },
  [8103] = {
    ["T"] = "The Pebble of Kajaro",
  },
  [8104] = {
    ["T"] = "The Jewel of Kajaro",
  },
  [8105] = {
    ["D"] =
    "$N, the battle for Arathi Basin is a battle for resources and territory.  Key points in the area must be held and operated in order to supply our forces with much needed raw materials and supplies.  I charge you to assault the points farthest from our Arathi Basin base.$B$BAssault the farm, the mine, the lumber mill and the blacksmith when they are controlled by the enemy.  Find the enemy\'s banner and rip it from its flag post!$B$BWhen you have done this to all four points, return to me.",
    ["O"] =
    "Assault the mine, the lumber mill, the blacksmith and the farm, then return to Field Marshal Oslight in Refuge Pointe.",
    ["T"] = "The Battle for Arathi Basin!",
  },
  [8106] = {
    ["T"] = "Kezan\'s Taint",
  },
  [8107] = {
    ["T"] = "Kezan\'s Taint",
  },
  [8108] = {
    ["T"] = "Kezan\'s Taint",
  },
  [8109] = {
    ["T"] = "Kezan\'s Unstoppable Taint",
  },
  [8110] = {
    ["T"] = "Enchanted South Seas Kelp",
  },
  [8111] = {
    ["T"] = "Enchanted South Seas Kelp",
  },
  [8112] = {
    ["T"] = "Enchanted South Seas Kelp",
  },
  [8113] = {
    ["T"] = "Pristine Enchanted South Seas Kelp",
  },
  [8114] = {
    ["D"] =
    "$N, you have taken the battle of Arathi Basin to our enemies and earned great honors in that field of battle.  You have shown us your worth as a $C, and you have shown our enemies that we will not submit to their villainy!$B$BBecause of your proven value to us, I have a difficult task for you.  I want you to take and hold at least four of the bases in Arathi Basin.  If you can do that, then we will not only secure critical resources, we will show the Horde our dominance!$B$BGo, $N, and good fortune.",
    ["O"] =
    "Enter Arathi Basin, capture and control four bases at the same time, and then return to Field Marshal Oslight at Refuge Pointe.",
    ["T"] = "Control Four Bases",
  },
  [8116] = {
    ["T"] = "Vision of Voodress",
  },
  [8117] = {
    ["T"] = "Vision of Voodress",
  },
  [8118] = {
    ["T"] = "Vision of Voodress",
  },
  [8119] = {
    ["T"] = "The Unmarred Vision of Voodress",
  },
  [8120] = {
    ["D"] =
    "As you no doubt have heard, the League of Arathor is sending large numbers of troops into Arathi Basin.  Eager for food and supplies, these Alliance fools are intent to take and control the rich resources there.  We must show them that Arathi will never again be a home for humans!$B$BGo to Arathi Basin and assault the mine, the lumber mill, the blacksmith and the stables.  Pull down the enemies\' banners, declaring those territories for the Horde.$B$BGo, $N.  Report back to me when this task is complete.",
    ["O"] =
    "Assault the Arathi Basin mine, lumber mill, blacksmith and stable, and then return to Deathmaster Dwire in Hammerfall.",
    ["T"] = "The Battle for Arathi Basin!",
  },
  [8121] = {
    ["D"] =
    "$N, as the battles over Arathi Basin rage, news of your actions have reached many ears.  You are highly regarded among us, which gives me confidence that you will accomplish the mission I now have for you.$B$BIt is time to send a message to the League of Arathor.  We must show them that their holdings in Arathi Basin are tenuous and quickly lost.  We will show them this by holding, all at once, four strategic points in Arathi Basin.$B$BSucceed in this, $N, and earn great respect among the Defilers.",
    ["O"] = "Hold four bases at the same time in Arathi Basin, and then return to Deathmaster Dwire in Hammerfall.",
    ["T"] = "Take Four Bases",
  },
  [8122] = {
    ["D"] =
    "It is difficult to see, so deep we are in the conflict, but our spies report a weakening in the League of Arathor\'s resolve.  We must use this window and strike a brutal blow against them!  Return to Arathi Basin and throw yourself against our foes.  Curse them and kill them and control all five strategic bases!  Send their soldiers screaming and bleeding from the front lines, with stories of your cruelty on their mewling lips.$B$BDo this, and score a great victory for the Defilers.",
    ["O"] = "Hold five bases in Arathi Basin at the same time, then return to Deathmaster Dwire in Hammerfall.",
    ["T"] = "Take Five Bases",
  },
  [8124] = {
    ["D"] =
    "The League of Arathor is sparing no expense in their move to retake Arathi. They, and all the races of the Alliance, now stream to this distant region, intent on expanding their hold from Refuge Pointe. We must stop them, and the best means to stop them is to take their supplies.$B$BYou can help us, $N. Enter Arathi Basin, known for its rich mines, fertile land and skilled craftsman. Capture and control every base you can, win the battle, and return to me with the resources you gain.",
    ["O"] =
    "Win the battle for Arathi Basin, get an Arathi Resource Crate, and return it to Deathstalker Mortis at Hammerfall.",
    ["T"] = "More Resource Crates",
  },
  [8145] = {
    ["T"] = "The Maelstrom\'s Tendril",
  },
  [8146] = {
    ["T"] = "The Maelstrom\'s Tendril",
  },
  [8147] = {
    ["T"] = "The Maelstrom\'s Tendril",
  },
  [8149] = {
    ["D"] =
    "During the Harvest Festival of Azeroth, we give thanks to heroes for the sacrifices - in some cases ultimate sacrifices - they have given on our behalf.  The Alliance acknowledges many heroes, but none weave a more tragic tale than that of Uther Lightbringer.$B$BHelp us honor Uther by taking this offering to his tomb in the Western Plaguelands.  Place it at his statue, and then return to me.  I\'ll only be here through the end of the festival, so waste no time in giving Uther his tribute.",
    ["O"] =
    "Travel to Uther\'s Tomb in Western Plaguelands and use Uther\'s Tribute at his statue, and then return to Wagner Hammerstrike outside Ironforge before the Harvest Festival is over.",
    ["T"] = "Honoring a Hero",
  },
  [8150] = {
    ["D"] =
    "During the Harvest Festival of Azeroth, we give thanks to heroes for the sacrifices - in some cases ultimate sacrifices - they have given on our behalf.  The Horde acknowledges many heroes, but none exemplify strength and sacrifice more than Grom Hellscream.$B$BHelp us honor Grom by taking this offering to his monument in the Demon Fall Canyon of Ashenvale.  Place it at the base, and then return to me.  I\'ll only be here through the end of the festival, so waste no time in giving Grom his tribute.",
    ["O"] =
    "Travel to Grom\'s Monument in the Demon Fall Canyon of Ashenvale and use Grom\'s Tribute at the base of the monument.  Return to Javnir Nashak outside Orgrimmar before the Harvest Festival is over.",
    ["T"] = "Honoring a Hero",
  },
  [8151] = {
    ["D"] =
    "Ogtinc of Azshara has sent out a call for seasoned hunters such as yourself.  He is a furbolg hunter who has left his tribe to aid the Cenarion Circle.  His teachings are meant to enrich the wisdom of others who share his craft, and guide them toward maintaining a balance.  You would do well to speak with him.$B$BOgtinc resides atop the cliffs of Azshara, northeast from the Ruins of Eldarath.",
    ["O"] = "Speak to Ogtinc in Azshara.",
    ["T"] = "The Hunter\'s Charm",
  },
  [8153] = {
    ["D"] =
    "The courser wears the mightiest antlers in the known lands.  Such antlers are used to defend the courser, goring an attacker and often damaging the points.  Perfect, natural antlers are the sign of an animal spirit with supreme confidence.$B$BTo hold such antlers will bestow the same confidence in you.$B$BHunt the mosshoof courser, find the perfect antlers and bring them to me.",
    ["O"] =
    "Bring a pair of Perfect Courser Antlers to Ogtinc in Azshara.  Ogtinc resides atop the cliffs northeast of the Ruins of Eldarath.",
    ["T"] = "Courser Antlers",
  },
  [8157] = {
    ["D"] =
    "War must be fought with soldiers, any soldier will tell you. They\'ll also say that a battle fought with poor gear or on an empty stomach is lost before it starts!$B$BThat is why Arathi Basin is important. There are key areas in the basin that hold essential resources. Metals, weapons, food, lumber - all are needed, and all can be gained there.$B$BThat is what I want from you, $N. Enter Arathi Basin, win the battle by holding more bases than the enemy, and return to me with a crate of resources.",
    ["O"] =
    "Win the battle for Arathi Basin, get an Arathi Resource Crate, and return it to Sergeant Maclear at Refuge Pointe.",
    ["T"] = "More Resource Crates",
  },
