  },
  [8399] = {
    ["D"] =
    "The Silverwing Sentinels are at war with the Warsong Outriders due to the destruction the Orcs are causing to the forest.  There are, however, more reasons to defend this particular forest than plain love for nature.$B$BThe forest forms a strategic barrier that makes Ashenvale defendable against a large-scale attack.  Without it, Astranaar would last a day or two before being annexed to the Barrens.$B$BDo your part in fighting the Warsong Outriders, $N!  For the Alliance!",
    ["O"] = "Bring 3 Warsong Gulch Marks of Honor to an Alliance Brigadier General outside the battlegrounds.",
    ["T"] = "Fight for Warsong Gulch",
  },
  [8400] = {
    ["D"] =
    "The Silverwing Sentinels are at war with the Warsong Outriders due to the destruction the Orcs are causing to the forest.  There are, however, more reasons to defend this particular forest than plain love for nature.$B$BThe forest forms a strategic barrier that makes Ashenvale defendable against a large-scale attack.  Without it, Astranaar would last a day or two before being annexed to the Barrens.$B$BDo your part in fighting the Warsong Outriders, $N!  For the Alliance!",
    ["O"] = "Bring 3 Warsong Gulch Marks of Honor to an Alliance Brigadier General outside the battlegrounds.",
    ["T"] = "Fight for Warsong Gulch",
  },
  [8401] = {
    ["D"] =
    "The Silverwing Sentinels are at war with the Warsong Outriders due to the destruction the Orcs are causing to the forest.  There are, however, more reasons to defend this particular forest than the preservationist philosophy the Silverwings espouse.$B$BThe forest forms a strategic barrier that makes Ashenvale defendable against a large-scale attack.  Without it, Astranaar would last a day or two before being annexed to the Barrens.  Do your part in fighting the Warsong Outriders!  For the Alliance!",
    ["O"] = "Bring 3 Warsong Gulch Marks of Honor to an Alliance Brigadier General outside the battlegrounds.",
    ["T"] = "Fight for Warsong Gulch",
  },
  [8402] = {
    ["D"] =
    "The Silverwing Sentinels are at war with the Warsong Outriders due to the destruction the Orcs are causing to the forest.  There are, however, more reasons to defend this particular forest than plain love for nature.$B$BThe forest forms a strategic barrier that makes Ashenvale defendable against a large-scale attack.  Without it, Astranaar would last a day or two before being annexed to the Barrens.$B$BDo your part in fighting the Warsong Outriders, $N!  For the Alliance!",
    ["O"] = "Bring 3 Warsong Gulch Marks of Honor to an Alliance Brigadier General outside the battlegrounds.",
    ["T"] = "Fight for Warsong Gulch",
  },
  [8403] = {
    ["D"] =
    "The Silverwing Sentinels are at war with the Warsong Outriders due to the destruction the Orcs are causing to the forest.  There are, however, more reasons to defend this particular forest than plain love for nature.$B$BThe forest forms a strategic barrier that makes Ashenvale defendable against a large-scale attack.  Without it, Astranaar would last a day or two before being annexed to the Barrens.$B$BDo your part in fighting the Warsong Outriders, $N!  For the Alliance!",
    ["O"] = "Bring 3 Warsong Gulch Marks of Honor to an Alliance Brigadier General outside the battlegrounds.",
    ["T"] = "Fight for Warsong Gulch",
  },
  [8409] = {
    ["D"] =
    "The rotten eggs have been successfully placed inside the keg.  Future batches of ale from the Southshore Inn are sure to be ruined!$B$BYou should now report back to Darkcaller Yanka at the Wickerman Festival in Tirisfal Glade and report your success.",
    ["O"] = "Return to Darkcaller Yanka at the Wickerman Festival in Tirisfal Glade.",
    ["T"] = "Ruined Kegs",
  },
  [8410] = {
    ["D"] =
    "Bath\'rah the Windwatcher has sent out a summons for a shaman of your wisdom.  He requests you bring a sample of each of the elements to show you are ready.$B$BTo find Bath\'rah, go to the river east of Tarren Mill.  Follow the river north until you come across the ruins where Bath\'rah resides.",
    ["O"] = "Collect a sample of air, fire, earth and water for Bath\'rah the Windwatcher.",
    ["T"] = "Elemental Mastery",
  },
  [8412] = {
    ["D"] =
    "The elemental spirits of this place don\'t be likin\' me any more.$B$BYou know about the totems more than any, and I be needin\' a spirit totem to protect me.  We already got the elements, now we need somethin\' more with more nature.  More primal.$B$BIn the Western Plaguelands you can kill bears for claws and spiders for their eyes.  The carrion birds eat everything, so they might have either one.",
    ["O"] = "Bring the pieces for the spirit totem to Bath\'rah the Windwatcher.",
    ["T"] = "Spirit Totem",
  },
  [8413] = {
    ["D"] =
    "The spirit totem just isn\'t enough.  We be needin\' some voodoo magic to make it work jus\' right.$B$BThe trolls in the sunken temple have feathers strong with voodoo magics.  Go there and kill Gasher, Mijan, Zolo, Hukku, Zul\'lor, and Loro.  Then we have magic enough for a real spirit totem.",
    ["O"] = "Bring the voodoo feathers to Bath\'rah the Windwatcher.",
    ["T"] = "Da Voodoo",
  },
  [8414] = {
    ["D"] =
    "Greetings, $C.  Crusaders like you are a welcome sight in these desolate reaches.$B$BYour holy strength is needed to help fight the endless undead here.  We need you to collect a large number of scourgestones and bring them to High Priest Thel\'danis.  The high priest can be found guarding Uther\'s Tomb in Sorrow Hill, not far from here.$B$BOnly one with an Argent Dawn Commission can hope to find scourgestones, so speak to Officer Pureheart if you haven\'t already.",
    ["O"] = "Collect 20 Minion\'s Scourgestones and bring them to High Priest Thel\'danis in the Western Plaguelands.",
    ["T"] = "Dispelling Evil",
  },
  [8416] = {
    ["D"] =
    "The evil has been purged from the stones, $N.$B$BI am aware of Commander Ashlam\'s plans, and he will require only a single inert stone.  Bring it to him so we may bathe the Scourge in righteous fire.",
    ["O"] = "Bring the Inert Scourgestone to Commander Ashlan Valorfist in Chillwind Point.",
    ["T"] = "Inert Scourgestones",
  },
  [8417] = {
    ["D"] =
    "In the Blasted Lands, there is a troubled spirit who was once a great hero of the horde.  A warrior\'s honor does not die with the body, and it would serve you well to speak with him.",
    ["O"] = "Speak with the Fallen Hero of the Horde at the entrance to the Blasted Lands.",
    ["T"] = "A Troubled Spirit",
  },
  [8418] = {
    ["D"] =
    "Now we must combine the inert scourgestones and create a weapon to shatter the ranks of undead.  This is no trivial task, $N.  Only the trolls of the sunken temple carry the kind of rare magic able to turn the evil of something against itself.$B$BIn the temple, the trolls are known as Gasher, Mijan, Zolo, Hukku, Zul\'lor, and Loro.  Do not feel remorse for their corrupt souls... they are not without evil.",
    ["O"] = "Bring the voodoo feathers to Ashlam Valorfist.",
    ["T"] = "Forging the Mightstone",
  },
  [8419] = {
    ["D"] =
    "$N, an imp in Felwood by the name of Impsy has requested your presence.  It is somewhat strange, as he has asked that you bring a piece of felcloth as a sign of good faith.  Considering the power you already wield as a warlock, I can only assume you know the satyrs of Felwood carry this felcloth.$B$BYou can find Impsy just north of the Bloodvenom Falls, which I\'ve heard is quite lovely this time of year.",
    ["O"] = "Bring a piece of felcloth to Impsy in Felwood.",
    ["T"] = "An Imp\'s Request",
  },
  [8420] = {
    ["D"] =
    "Maybe this sounds strange coming from an imp, but I\'d like a pet of my own.  I really would.  It\'s just not fair that Niby gets me and I get nothing!$B$BIn fact, it doesn\'t even need to be a living pet.  I\'d need something to start making it with, like some felcloth.  The satyrs here in Felwood sometimes have felcloth, so you\'d just have to kill enough of them until you find some.  That doesn\'t sound so bad, does it?",
    ["O"] = "Bring a piece of felcloth to Impsy in Felwood.",
    ["T"] = "Hot and Itchy",
  },
  [8421] = {
    ["D"] =
    "Now that I have my felcloth, I can really begin making *my* pet.$B$BIt\'s going to need some eyes though.  Perhaps you could rip some rotting wood from the irontree folk for me, so I can carve out some lovely eyes.  They\'re up north in the Irontree Woods.$B$BI\'ll also need some bloodvenom essence to give it that new demon smell.  The tainted oozes carry the essence, and they hang out right here near Niby and me.",
    ["O"] = "Bring 10 Rotting Wood and 4 Bloodvenom Essence to Impsy in Felwood.",
    ["T"] = "The Wrong Stuff",
  },
  [8422] = {
    ["D"] =
    "My pet is almost done.  Now I just need something to stuff it with.$B$BOnly the voodoo feathers from the trolls in the sunken temple will do.  They go by the names Gasher, Mijan, Zolo, Hukku, Zul\'lor, and Loro.  Kill them.  Kill them all.$B$BThis is no trivial task $N, so I\'ll make it worth your while by giving you something of Niby\'s -- he probably doesn\'t need it anyhow.",
    ["O"] = "Bring a total of 6 Voodoo Feathers from the trolls in sunken temple.",
    ["T"] = "Trolls of a Feather",
  },
  [8423] = {
    ["D"] =
    "$B$BYou are a $C, no doubt.  I would ask an honorable task of you, but I must test your strength.$B$BIt is said that Rexxar would measure the sharpness of his blades by killing a helboar with a single, swift strike.  Now I will measure your strength by killing them.",
    ["O"] = "Kill 7 Helboar in the Blasted Lands and return to the Fallen Hero of the Horde.",
    ["T"] = "Warrior Kinship",
  },
  [8424] = {
    ["D"] =
    "The continued presence of the shadowsworn in the Blasted Lands bring great pain to me.  Their dark rituals and spells cause agony unlike any I felt while alive.$B$BThrough you I can deliver my own message of pain.  Go forth and deliver my wrath.",
    ["O"] = "Slaughter the Shadowsworn in the Blasted Lands and return to the Fallen Hero of the Horde.",
    ["T"] = "War on the Shadowsworn",
  },
  [8425] = {
    ["D"] =
    "Your honor has brought some peace to me.  It is only right that I offer you something in return.$B$BMy weapons and armor were splendid in life, and yet they are of no use to me now.  They would be better served in your possession.$B$BTravel to the sunken temple and destroy the troll guardians Gasher, Mijan, Zolo, Hukku, Zul\'lor, and Loro.  They carry magic feathers that can reform my physical body long enough to grant you a reward.",
    ["O"] = "Bring the Voodoo Feathers from the trolls in the Sunken Temple to the Fallen Hero of the Horde.",
    ["T"] = "Voodoo Feathers",
  },
  [8436] = {
    ["D"] =
    "Our conflict with the Alliance has escalated to a true war.  No longer are false pretenses to enter into battle used or expected by either side at this point.$B$BThe battle for the Arathi Basin is one of resources, plain and simple.  Either the Alliance gets the resources and uses them against us or we get them and use them to keep our war efforts going.  Help the Defilers maintain the flow of resources we need, $N!",
    ["O"] = "Bring 3 Arathi Basin Mark of Honor to a Horde Warbringer outside the battlegrounds.",
    ["T"] = "Conquering Arathi Basin",
  },
  [8437] = {
    ["D"] =
    "Our conflict with the Alliance has escalated to a true war.  No longer are false pretenses to enter into battle used or expected by either side at this point.$B$BThe battle for the Arathi Basin is one of resources, plain and simple.  Either the Alliance gets the resources and uses them against us or we get them and use them to keep our war efforts going.  Help the Defilers maintain the flow of resources we need, $N!",
    ["O"] = "Bring 3 Arathi Basin Mark of Honor to a Horde Warbringer outside the battlegrounds.",
    ["T"] = "Conquering Arathi Basin",
  },
  [8438] = {
    ["D"] =
    "Our conflict with the Alliance has escalated to a true war.  No longer are false pretenses to enter into battle used or expected by either side at this point.$B$BThe battle for the Arathi Basin is one of resources, plain and simple.  Either the Alliance gets the resources and uses them against us or we get them and use them to keep our war efforts going.  Help the Defilers maintain the flow of resources we need, $N!",
    ["O"] = "Bring 3 Arathi Basin Mark of Honor to a Horde Warbringer outside the battlegrounds.",
    ["T"] = "Conquering Arathi Basin",
  },
  [8439] = {
    ["D"] =
    "Our conflict with the Alliance has escalated to a true war.  No longer are false pretenses to enter into battle used or expected by either side at this point.$B$BThe battle for the Arathi Basin is one of resources, plain and simple.  Either the Alliance gets the resources and uses them against us or we get them and use them to keep our war efforts going.  Help the Defilers maintain the flow of resources we need, $N!",
    ["O"] = "Bring 3 Arathi Basin Mark of Honor to a Horde Warbringer outside the battlegrounds.",
    ["T"] = "Conquering Arathi Basin",
  },
  [8446] = {
    ["D"] =
    "Corruption seeps from this object.$B$BThere may be a link between this object and the dragons coming forth from the Dream. You must find someone that can decipher the meaning of this item. Perhaps the druids of the Moonglade or Cenarion Hold could assist you further.",
    ["O"] =
    "Find someone capable of deciphering the meaning behind the Nightmare Engulfed Object.$B$BPerhaps a druid of great power could assist you.",
    ["T"] = "Shrouded in Nightmare",
  },
  [8447] = {
    ["D"] =
    "The waters of Lake Elune\'ara should dissolve the nightmares engulfing this object. Give me a moment to perform the cleansing, $N.",
    ["O"] = "Wait for Keeper Remulos at the Moonglade to cleanse the Nightmare Engulfed Object.",
    ["T"] = "Waking Legends",
  },
  [8460] = {
    ["D"] =
    "The Timbermaw are the only furbolg tribe to escape the corruption. However, many other races kill furbolg blindly now, without bothering to see if they are friend or foe. For this reason, the Timbermaw furbolg trust very few.$B$BAre you interested in proving yourself? Drive back the corrupted Deadwood tribe of Felwood and we may one day consider you an ally. You\'ll find the first Deadwood tribe - warriors, pathfinders and gardeners - to my west.",
    ["O"] =
    "Grazle wants you to prove yourself by killing 6 Deadwood Warriors, 6 Deadwood Pathfinders, and 6 Deadwood Gardeners.  Return to him in southern Felwood near the Emerald Sanctuary when you are done.",
    ["T"] = "Timbermaw Ally",
  },
  [8461] = {
    ["D"] =
    "There is a camp of Deadwood furbolgs directly to our southwest.  Corruption permeates the camp, and I wish to put an end to it before they become a problem.$B$BThe Deadwood tribe is evil, but it is the effects of the fel that pollutes their minds.  Their hostility is not truly an innate quality, yet they cannot be helped.  It saddens me that we must fight our own brethren.$B$BPlease, $N - I ask you to do what must be done.  Simply spare me the details; such troublesome images upset me far too much.",
    ["O"] =
    "Nafien would like you to kill 6 Deadwood Den Watchers, 6 Deadwood Avengers, and 6 Deadwood Shamans.  Return to him in northern Felwood near the entrance to Timbermaw Hold.",
    ["T"] = "Deadwood of the North",
  },
  [8462] = {
    ["D"] =
    "Perhaps you are capable of handling a larger threat that we Timbermaw face.  You certainly have shown yourself capable here...$B$BAnother of my kind stands guard outside the entrance to Timbermaw Hold, along this road far to the north.  His name is Nafien; while he may appear to be a feral and unsavory beast, fear him not.  He only seeks aid against the malign forces that threaten our home.",
    ["O"] =
    "Travel north along the main road in Felwood and speak with the furbolg named Nafien.  He stands guard outside the entrance to Timbermaw Hold.",
    ["T"] = "Speak to Nafien",
  },
  [8464] = {
    ["D"] =
    "The Timbermaw tend to stay to themselves, $N.  While we do allow safe passage to those we trust, we try to avoid other furbolg tribes if at all possible.$B$BThe Winterfall tribe as of late has become increasingly hostile towards us.  They seem to be in a state of rage, completely engulfed by their own fear and hatred of anything they do not understand.$B$BI must ask you to thin their numbers as to lessen the threat against us.  Seek them out in Winterfall Village, far to the east of here.",
    ["O"] =
    "Salfa wants you to kill 8 Winterfall Shaman, 8 Winterfall Den Watchers, and 8 Winterfall Ursa.  Salfa is located just outside the entrance to Timbermaw Hold in Winterspring.",
    ["T"] = "Winterfall Activity",
  },
  [8465] = {
    ["D"] =
    "The threat of corruption comes not only from the Deadwood furbolgs to the south, but also from the east and the Winterfall furbolgs of Winterspring.  If you wish to further aid us, speak with Salfa on the other side of the Hold, by the Winterspring entrance.  Follow the path to the left to reach it.$B$BBe warned - if my kind inside considers you hostile or hated, they will attack.  Travel as quick as you can, avoiding conflict.  To kill a Timbermaw - even in self defense - will only alienate you further.",
    ["O"] =
    "Travel through Timbermaw Hold and exit into Winterspring.  Speak with Salfa, who stands guard outside the entrance to Timbermaw Hold.",
    ["T"] = "Speak to Salfa",
  },
  [8466] = {
    ["T"] = "Feathers for Grazle",
  },
  [8467] = {
    ["T"] = "Feathers for Nafien",
  },
  [8469] = {
    ["T"] = "Beads for Salfa",
  },
  [8470] = {
    ["D"] =
    "You have found one of the Deadwood furbolg\'s ritual totems.  The totem itself is of non-descript construction, but a palpable sense of despair emanates from it.  If there were any object that might best exemplify the corruption that the Deadwood furbolg suffer under, this item would clearly be it.$B$BOne of the furbolgs inside Timbermaw Hold may have a use for such an item... that is, if you\'ve earned their trust enough for them to speak with you.",
    ["O"] =
    "Take the Deadwood Ritual Totem inside Timbermaw Hold and see if one of the furbolgs there will find a use for the item.  The Timbermaw will not speak with you unless you are of Neutral reputation or greater with them.",
    ["T"] = "Deadwood Ritual Totem",
  },
  [8471] = {
    ["D"] =
    "You have found one of the Winterfall furbolg\'s ritual totems.  The totem itself is of non-descript construction, but it seems to emanate an almost tangible sense of dread and despair.  If many of the Winterfall furbolgs do indeed carry these, it certainly would go a long way in explaining their current condition.$B$BOne of the furbolgs inside Timbermaw Hold may have a use for such an item... that is, if you\'ve earned their trust enough for them to speak with you.",
    ["O"] =
    "Take the Winterfall Ritual Totem inside Timbermaw Hold and see if one of the furbolgs there will find a use for the item.  The Timbermaw will not speak with you unless you are of Neutral reputation or greater with them.",
    ["T"] = "Winterfall Ritual Totem",
  },
  [8481] = {
    ["D"] =
    "$N, thanks to you we have devised a way to summon forth the root of all evil for the Winterfall tribe - the corrupting demon that dominates them!$B$BTake this torch to the mouth of High Chief Winterfall\'s personal cave and plant it there.  Doing so will force the demon to reveal itself and investigate.  This is when you and your allies must strike it down!  Only the essence of the fallen demon will begin the lengthy healing process of the Winterfall tribe... and the salvation of Timbermaw Hold.",
    ["O"] =
    "Plant the Demon Summoning Torch in the mouth of High Chief Winterfall\'s cave in the Winterfall furbolg village.  Defeat the demon and retrieve the Essence of Xandivious for Gorn One Eye in Timbermaw Hold.",
    ["T"] = "The Root of All Evil",
  },
  [8484] = {
    ["D"] =
    "Your deeds go beyond the tale of a simple hero, $N.  If you are a representative of your people, then your people are ones we would work to make peace with.$B$BPlease - take this offering to the dwarven king that resides in a mountain of iron; I believe you call this city Ironforge.  In times past, he had tried to make contact with us on behalf of his Alliance.  It is now only fitting to acknowledge you as the key in your Alliance\'s efforts in brokering peace.",
    ["O"] = "Bring the Timbermaw Offering of Peace to King Magni Bronzebeard in Ironforge.",
    ["T"] = "The Brokering of Peace",
  },
  [8485] = {
    ["D"] =
    "Your deeds go beyond the tale of a simple hero, $N.  If you are a representative of your people, then your people are ones we would work to make peace with.$B$BPlease - take this offering to the orcish warchief that resides in the lands of Durotar; I believe you call this city Orgrimmar.  In times past, he had tried to make contact with us on behalf of his Horde.  It is now only fitting to acknowledge you as the key in your Horde\'s efforts in brokering peace.",
    ["O"] = "Bring the Timbermaw Offering of Peace to Thrall in Orgrimmar.",
    ["T"] = "The Brokering of Peace",
  },
  [8492] = {
    ["D"] =
    "Hey there, $C, you look fit enough to contribute to the war effort! We need all of the help that we can get here to put together the materiel needed for the Ahn\'Qiraj War and it\'s your lucky day.$B$BI\'m collecting copper bars in stacks of twenty. It\'s for a worthy cause, what do you say? Do you think you could help out the Alliance?",
    ["O"] = "Bring 20 Copper Bars to Sergeant Stonebrow at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Copper Bars!",
  },
  [8493] = {
    ["D"] =
    "Back again $C? Outstanding! We still need more stacks of copper bars if you can procure them for the Ahn\'Qiraj war effort.  Will you help us out?",
    ["O"] = "Bring 20 copper bars to Sergeant Stonebrow at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Copper Bars!",
  },
  [8494] = {
    ["D"] =
    "Well hello there,  Mr.  Fancypants, aren\'t you a sight for sore eyes. In case you hadn\'t heard while you were out there \"adventuring\", the Alliance has been gearing up for a war in Ahn\'Qiraj and is in need of iron bars... a whole mess of \'em. Bring them to me in stacks of twenty. We can count on you, right, $C?",
    ["O"] = "Bring 20 Iron Bars to Corporal Carnes at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Iron Bars!",
  },
  [8495] = {
    ["D"] =
    "Back so soon? Stop making me re-evaluate my low opinion of you $C, you\'re making me feel all gooey inside. So, as you can tell we still don\'t have enough iron bars for all of the weapons, armor, steam tanks and whatnot that need building for the bug hunt. Think you have it in you to bring back another stack of twenty iron bars in between all of those trips to Zul\'Gurub, or wherever it is that you kids hang out these days?",
    ["O"] = "Bring 20 iron bars to Corporal Carnes at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Iron Bars!",
  },
  [8496] = {
    ["D"] =
    "Our supply of bandages in the battlefield is running dangerously low after the recent casualties we have incurred.  Obtain a batch of first-aid supplies and deliver them to Windcaller Proudhorn in Cenarion Hold.",
    ["O"] =
    "Bring 30 Heavy Runecloth Bandages, 30 Heavy Silk Bandages and 30 Heavy Mageweave Bandages to Windcaller Proudhorn at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing X in order to complete this quest.",
    ["T"] = "Bandages for the Field",
  },
  [8497] = {
    ["D"] =
    "With the arrival of fresh recruits to Cenarion Hold comes the problem of keeping them alive in the desert.  Dehydration as well as numerous poisonous creatures present a serious threat to inexperienced volunteers.  Gather the supplies necessary for a desert survival kit and bring them to Calandrath in Cenarion Hold.",
    ["O"] =
    "Bring 4 Globes of Water, 4 Powerful Anti-Venom and 4 Smoked Desert Dumplings to Calandrath at the inn in Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing I in order to complete this quest.",
    ["T"] = "Desert Survival Kits",
  },
  [8498] = {
    ["D"] =
    "Our scouts have reported new battle orders being issued by the Twilight\'s Hammer leaders.  The orders are being distributed by Twilight Prophets under heavy escort.  Intercept the orders and bring them to Commander Mar\'alith.",
    ["O"] =
    "Obtain the Twilight Battle Orders and bring them Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Tactical Task Briefing X in order to complete this quest.",
    ["T"] = "Twilight Battle Orders",
  },
  [8499] = {
    ["D"] =
    "It is very kind of you to inquire about the needs that the Alliance has. In addition to all of the other collection efforts underway, we are in need of a great quantity of thorium bars, which is the task that I am in charge of. The thorium will be used in the creation of many different things for the war, foremost of which is the construction of a battalion of steam tanks to be airlifted into Silithus as soon as they are completed. Can you aid us in this endeavor, $C?",
    ["O"] = "Bring 20 Thorium Bars to Dame Twinbraid at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Thorium Bars!",
  },
  [8500] = {
    ["D"] =
    "It is so good to see you again $N. I hope that you\'ve been doing well. It\'s true that we are still in need of thorium bars. If you have them to spare I am collecting them for the Ahn\'Qiraj war effort.",
    ["O"] = "Bring 20 thorium bars to Dame Twinbraid at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Thorium Bars!",
  },
  [8501] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Ashi where your primary target will consist of the airborne Hive\'Ashi stingers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Kill 30 Hive\'Ashi Stingers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing XII in order to complete this quest.",
    ["T"] = "Target: Hive\'Ashi Stingers",
  },
  [8502] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Ashi where your primary target will consist of Hive\'Ashi workers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Slay 30 Hive\'Ashi Workers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing III in order to complete this quest.",
    ["T"] = "Target: Hive\'Ashi Workers",
  },
  [8503] = {
    ["D"] =
    "So, $C, did I already tell you about all of the fabulous uses stranglekelp has? I did? Oh well... in any case we need a lot of it, and when I say a lot, I mean A LOT! Do you think that you could help us out? I know that it means going without all of those wonderful things that you can make with it, but it\'s for a good cause!",
    ["O"] = "Bring 20 Stranglekelp to Private Draxlegauge at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Stranglekelp!",
  },
  [8504] = {
    ["D"] =
    "Well hello again there... what was it? Ah yes, $N! Come to see if I still need more stranglekelp have you? Well, it\'s your lucky day, because the answer to that very important question is a very affirmative YES! Think you could gather up twenty more?",
    ["O"] = "Bring 20 stranglekelp to Private Draxlegauge at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Stranglekelp!",
  },
  [8505] = {
    ["D"] =
    "$C, the purple lotus is a flower with a plentitude of uses. I am here at the request of the Alliance as an authority on those applications, to preserve the herbs collected and to ensure that their war effort acquires enough purple lotus to sustain whatever function they plan for it.$B$BI would like for you to travel out into the world and return to me with some of these flowers. Is that something that you can do?",
    ["O"] = "Bring 20 Purple Lotus to Master Nightsong at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Purple Lotus!",
  },
  [8506] = {
    ["D"] =
    "Welcome back $C. Our collection grows, but even now we have a need for additional purple lotus. If it is still within your power to gather more of the herb, I entreat you to do so and return them to me here.",
    ["O"] = "Bring 20 purple lotus to Master Nightsong at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Purple Lotus!",
  },
  [8507] = {
    ["D"] =
    "Greetings, $N.  Before I assign you to more involved tasks in the war, you\'ll need to do your share of field duty.$B$BYou will find Captain Blackanvil\'s Ironforge Brigade outside Hive\'Zora.$B$BReport to him or his lieutenant, Janela Stouthammer and come back to me.  I shall have a more advanced assignment for you ready.$B$BOh and please do us a favor and stay away from the Orgrimmar Legion.  We\'ve been forced to keep the two forces well apart from one another due to mutual animosity.",
    ["O"] =
    "Report for duty at the Ironforge Brigade post near Hive\'Zora.  Prepare your Unsigned Field Duty Papers and obtain Signed Field Duty Papers from Captain Blackanvil and return to Windcaller Kaldon at Cenarion Hold in Silithus.$B$BNote: Healing or casting beneficial spells on a member of the Ironforge Brigade will flag you for PvP.",
    ["T"] = "Field Duty",
  },
  [8508] = {
    ["T"] = "Field Duty Papers",
  },
  [8509] = {
    ["D"] =
    "I\'ll keep it simple and to the point, $C. The Alliance needs to collect a large quantity of Arthas\' Tears for the Ahn\'Qiraj war effort. Don\'t ask me what for; I\'m just following orders. But I\'d like you to gather up as many of the herbs as you can and bring them back to me here. Are you willing to do that?",
    ["O"] = "Bring 20 Arthas\' Tears to Sergeant Major Germaine at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Arthas\' Tears!",
  },
  [8510] = {
    ["D"] =
    "Ok, so it looks like I still need more Arthas\' Tears. I would imagine that you will be able to find them in the general location that you gathered them up for me last time. The quicker we get these, the faster we can start up the offensive against the forces at Ahn\'Qiraj.$B$BYou gonna help us out again $C?",
    ["O"] = "Bring 20 arthas\' tears to Sergeant Major Germaine at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Arthas\' Tears!",
  },
  [8511] = {
    ["D"] =
    "We Stoneflayers have a long history of being skinners, $C. That\'s why the Alliance has asked my family to help out with the collection of light leather for the Ahn\'Qiraj war effort. I\'m here to see to it that the leather is tanned correctly for whatever they want to put it to use for. But we need your help.$B$BSince I have to be here doing that, I need you to go out and collect the skins, returning them to me here. What do you say,  lad , will you give it a go?",
    ["O"] = "Bring 10 Light Leather to Bonnie Stoneflayer at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Light Leather!",
  },
  [8512] = {
    ["D"] =
    "Good to see you again $N. It does appear that we need more light leather for the creation of the various war materiel. If you could bring me a stack of ten that would be just perfect.",
    ["O"] = "Bring 10 light leather to Bonnie Stoneflayer at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Light Leather!",
  },
  [8513] = {
    ["D"] =
    "Yes  sir , I have been charged with collecting and tracking all of the medium leather gathered for the war effort. If you have the wherewithal to gather medium leather, from whatever source, then please bring them to me here. I sure would appreciate a hand with this if you can spare the time.",
    ["O"] = "Bring 10 Medium Leather to Private Porter at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Medium Leather!",
  },
  [8514] = {
    ["D"] =
    "Yes  sir , looks like we\'ve collected $2063w pieces of medium leather to date. I know it\'s a lot to ask, but if you\'re still willing, I could use your help in attempting to put a dent in the rest of my quota.",
    ["O"] = "Bring 10 medium leather to Private Porter at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Medium Leather!",
  },
  [8515] = {
    ["D"] =
    "Oh boy, this is going to be great! $C, the Ahn\'Qiraj war effort is in full swing, and I\'ve been put in charge of keeping track of all of the thick leather that comes in. We\'ll make tons of things with it, but first we need to get a ton of it. And I mean that literally! That\'s where you come in.$B$BSo, do you think you can go out there and bring me back a nice, fat stack of thick leather? Do yah, do yah?!",
    ["O"] = "Bring 10 Thick Leather to Marta Finespindle at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Thick Leather!",
  },
  [8516] = {
    ["D"] =
    "Yep, the stack\'s still not high enough. $N, we still haven\'t reached our goal of $2071w thick leather. Just think of all the things that we can make with all of that leather! All kinds of armor and weapons. Stuff for inside the steam tanks and rifle scopes! Engineering goggles, and I bet if it ends up that we collect too much we could give the rest to the Horde for their zeppelins!$B$BYou gonna bring me back some more thick leather?",
    ["O"] = "Bring 10 thick leather to Marta Finespindle at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Thick Leather!",
  },
  [8517] = {
    ["D"] =
    "The war at Ahn\'Qiraj is going to be long and bloody. It is a very wise thing that the Alliance is doing by enlisting the aid of you, and those like you, to build up the materiel necessary before plunging headlong into conflict.$B$BI have been asked to head up the collection of linen bandages for the war, and I am hoping that you are going to assist me in amassing as many as we need. It is no light matter, but at least the linen bandages are the least difficult to create. Are you with us, $C?",
    ["O"] = "Bring 20 Linen Bandages to Sentinel Silversky at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Linen Bandages!",
  },
  [8518] = {
    ["D"] =
    "Ever am I amazed by the selflessness exhibited when so many would instead turn to selfishness instead. $C, I am still in need of a number of linen bandages before my assignment here is fulfilled. Will you aid me once more in the collection of those bandages?",
    ["O"] = "Bring 20 linen bandages to Sentinel Silversky at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Linen Bandages!",
  },
  [8519] = {
    ["D"] =
    "As you regain your composure and focus your gaze, you notice that something stirs within the crystal. Upon closer inspection, you realize that you are looking into the past... a memory... long forgotten.",
    ["O"] = "Learn all that you can of the past, then speak with Anachronos at the Caverns of Time in Tanaris.",
    ["T"] = "A Pawn on the Eternal Board",
  },
  [8520] = {
    ["D"] =
    "With the Ahn\'Qiraj War looming we need to do everything that we can to see to it that our soldiers have everything that they need. We\'re doing just that right here. For my part I\'ve been placed in charge of seeing to it that we collect enough silk bandages.$B$BDo you think you can help me out, $C?",
    ["O"] = "Bring 20 Silk Bandages to Nurse Stonefield at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Silk Bandages!",
  },
  [8521] = {
    ["D"] =
    "It is very kind of you to offer to help me again $C. It looks like we\'ve collected $2082w silk bandages, so we\'ll need more.",
    ["O"] = "Bring 20 silk bandages to Nurse Stonefield at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Silk Bandages!",
  },
  [8522] = {
    ["D"] =
    "Argue the merits of the war if you will, $C, but it has already been set in motion. Look around you at your family and friends, and then ask yourself what it is that you can do to see to it that if they are involved, they will have every advantage to survive the conflagration.$B$BTo that end, I am collecting runecloth bandages here from whatever source. Would you like to make a donation?",
    ["O"] = "Bring 20 Runecloth Bandages to Keeper Moonshade at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Runecloth Bandages!",
  },
  [8523] = {
    ["D"] =
    "So it is that we come to discuss pressing matters yet again $C. Once more I thank you for your previous efforts; it is not everyone who would give so selflessly. But there is still more work to do.$B$B$N, will you once more collect runecloth bandages and return them to me here?",
    ["O"] = "Bring 20 runecloth bandages to Keeper Moonshade at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Runecloth Bandages!",
  },
  [8524] = {
    ["D"] =
    "Hey there, friend! If I were to say to you, \'Don\'t you think that soldiers should have food to eat like anyone else?\', you would of course reply, \'yes\'. I agree with you 110%! I\'m glad we\'re in accord. All I need for you to do is to head out there, fish up a whole bunch of raw rainbow fin albacore, and then cook it all up and bring it back to me right here. Mmm, mmm, I can taste it already.",
    ["O"] = "Bring 20 Rainbow Fin Albacore to Slicky Gastronome at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Rainbow Fin Albacore!",
  },
  [8525] = {
    ["D"] =
    "What! You again? Well I\'ll be a monkey\'s uncle... except that I\'m a gnome. Slicky Gastronome to be precise! So you\'re back to help out again eh? Well, I can\'t say as I blame you. Don\'t you just love the smell of all of that food?$B$BEnough loitering! Get out there and bring me back more rainbow fin albacore!",
    ["O"] = "Bring 20 rainbow fin albacore to Slicky Gastronome at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Rainbow Fin Albacore!",
  },
  [8526] = {
    ["D"] =
    "Oh, how\'s it going, $C? I see that you\'re interested in maybe gathering up food for the coming war at Ahn\'Qiraj? Somehow my dad thought that it would be a good learning experience for me if I were to volunteer to help out here. Big mistake. I don\'t even like to eat meat.$B$BAnyway, if you feel like it, you could bring me back a lot of roast raptor. Apparently that\'s what all of the soldiers are going to want.",
    ["O"] = "Bring 20 Roast Raptor to Sarah Sadwhistle at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Roast Raptor!",
  },
  [8527] = {
    ["D"] =
    "Hi again $C. I can tell you\'re very excited about all of this. So I suppose you want to bring me another twenty roast raptor. Great. Well you do that. I guess I\'ll see you when you get back.",
    ["O"] = "Bring 20 roast raptor to Sarah Sadwhistle at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Roast Raptor!",
  },
  [8528] = {
    ["D"] =
    "It may not seem heroic to gather up cooked fish, but do not underestimate the value of preparation, young $C. Soldiers need to eat like anyone else, and we\'re here to do our part to make sure they have what they need once the war in Ahn\'Qiraj commences.$B$BAccordingly, I am stockpiling spotted yellowtail, a versatile source of sustenance that stores well and can be used in many different dishes. It also doesn\'t have the odor of some other saltwater fish. Are you willing to aid me in this endeavor?",
    ["O"] = "Bring 20 Spotted Yellowtail to Huntress Swiftriver at the Military Ward in Ironforge.",
    ["T"] = "The Alliance Needs Spotted Yellowtail!",
  },
  [8529] = {
    ["D"] =
    "If you\'re still willing I\'d like to send you back out to bring in another haul of spotted yellowtail, $N. I\'d imagine with the expertise you gained the first time out that this catch should be much faster and easier. Are you game?",
    ["O"] = "Bring 20 spotted yellowtail to Huntress Swiftriver at the airfield in Dun Morogh.",
    ["T"] = "The Alliance Needs More Spotted Yellowtail!",
  },
  [8532] = {
    ["D"] =
    "So glad that you\'ve decided to help out here. Not everyone would, so I need to make sure you understand what it is that I need. Copper bars, not copper ore. We don\'t have the time or people to do all of the smelting ourselves, so if you would be so kind as to take care of that, your efforts will be duly noted. Is that something that you can handle, $C?",
    ["O"] = "Bring 20 Copper Bars to Miner Cromwell at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Copper Bars!",
  },
  [8533] = {
    ["D"] =
    "Back so soon? You\'ll be a real miner in no time $C. So, you already know the drill; I need you to go out, mine up a mess of copper ore, smelt it into bars and bring it back to me here. I know that\'s something you\'re capable of, the question is, are you willing?",
    ["O"] = "Bring 20 copper bars to Miner Cromwell in Durotar.",
    ["T"] = "The Horde Needs More Copper Bars!",
  },
  [8534] = {
    ["D"] =
    "We\'ve sent our best scouts deep into the silithid hives to gather intelligence.  Scout Azenel has been watching the silithid movements at Hive\'Zora for several days now.  Find her and obtain a written report.  We need to be able to act on that information as soon as possible, $N.",
    ["O"] =
    "Contact Cenarion Scout Azenel inside Hive\'Zora and return the Hive\'Zora Scout Report to Windcaller Proudhorn at Cenarion Hold.  You must also bring Tactical Task Briefing VI in order to complete this quest.",
    ["T"] = "Hive\'Zora Scout Report",
  },
  [8535] = {
    ["D"] =
    "The Twilight\'s Hammer and the elemental nobles they worship present a formidable threat to our operations in Silithus.  With the new enemies we\'re facing inside Ahn\'Qiraj, we cannot afford to lower our guard to our enemies outside.$B$BFind a way to summon and destroy a Hoary Templar and report to Bor Wildmane.",
    ["O"] =
    "Summon and slay a Hoary Templar and report back to Bor Wildmane in Cenarion Hold.  You must also bring Tactical Task Briefing IV in order to complete this quest.",
    ["T"] = "Hoary Templar",
  },
  [8536] = {
    ["D"] =
    "The Twilight\'s Hammer and the elemental nobles they worship present a formidable threat to our operations in Silithus.  With the new enemies we\'re facing inside Ahn\'Qiraj, we cannot afford to lower our guard to our enemies outside.$B$BFind a way to summon and destroy an Earthen Templar and report to Bor Wildmane.",
    ["O"] =
    "Summon and slay an Earthen Templar and report back to Bor Wildmane in Cenarion Hold.  You must also bring Tactical Task Briefing III in order to complete this quest.",
    ["T"] = "Earthen Templar",
  },
  [8537] = {
    ["D"] =
    "The Twilight\'s Hammer and the elemental nobles they worship present a formidable threat to our operations in Silithus.  With the new enemies we\'re facing inside Ahn\'Qiraj, we cannot afford to lower our guard to our enemies outside.$B$BFind a way to summon and destroy a Crimson Templar and report to Bor Wildmane.",
    ["O"] =
    "Summon and slay a Crimson Templar and report back to Bor Wildmane in Cenarion Hold.  You must also bring Tactical Task Briefing II in order to complete this quest.",
    ["T"] = "Crimson Templar",
  },
  [8538] = {
    ["D"] =
    "The links between the Twilight\'s Hammer and the Abyssal Council are proving to be more important than we had expected.$B$BWe believe the elemental nobles known as the Abyssal Dukes are one of the primary force organizing the Twilight\'s Hammer cultists.  Find a way to lure the four Abyssal Dukes into our plane of existence and destroy them!$B$BYour dedication and prowess in past assignments have led us to choose you for this particular assignment.  We are certain you will succeed in this endeavor.",
    ["O"] =
    "Find a way to summon and slay the Duke of Cynders, the Duke of Fathoms, the Duke of Zephyrs and the Duke of Shards and report back to Commander Mar\'alith in Cenarion Hold.  You must also bring Tactical Task Briefing V in order to complete this quest.",
    ["T"] = "The Four Dukes",
  },
  [8539] = {
    ["D"] =
    "Reinforcements have been called on to join the assault on Hive\'Zora.  You have been selected to target Hive\'Zora hive sisters.  Report back to Commander Mar\'alith after completing your task.",
    ["O"] =
    "Slay 30 Hive\'Zora Hive Sisters and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing V in order to complete this quest.",
    ["T"] = "Target: Hive\'Zora Hive Sisters",
  },
  [8540] = {
    ["D"] =
    "The mounted division of the Cenarion Hold guard is in short supply of ornate mithril boots.  Procure a batch and deliver them immediately to Captain Vish Kozus in Cenarion Hold.",
    ["O"] =
    "Bring 3 Ornate Mithril Boots to Vish Kozus, Captain of the Guard at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing II in order to complete this quest.",
    ["T"] = "Boots for the Guard",
  },
  [8541] = {
    ["D"] =
    "The Cenarion Hold guard is in short supply of grinding stones.  Procure a batch and deliver them immediately to Captain Vish Kozus in Cenarion Hold.",
    ["O"] =
    "Bring 10 Dense Grinding Stones, 10 Solid Grinding Stones and 10 Heavy Grinding Stones to Vish Kozus, Captain of the Guard at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing III in order to complete this quest.",
    ["T"] = "Grinding Stones for the Guard",
  },
  [8542] = {
    ["D"] =
    "Lok\'tar, $R, I\'m sure you already know that we\'re going to war at Ahn\'Qiraj with the insects. But first the Warchief has decided that we\'re going to do something called \'prepare\'. Though I\'d rather be sharpening weapons and hammering armor into shape, I\'m proud to have been chosen to be in charge of tin bar collection here. But I cannot do that without your help.$B$BSo I need you to go out and make tin bars and bring them back to me here. I think I\'m going to need more than I can count.",
    ["O"] = "Bring 20 Tin Bars to Grunt Maug at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Tin Bars!",
  },
  [8543] = {
    ["D"] =
    "Very good, I see that you are serious about the war. I\'m a little edgy waiting for it to start though, which means I\'m going to get angry if you don\'t start bringing in the goods faster. Maybe I can just practice on you instead.$B$BHar! Maybe not, \'cuz then who would bring me back the tin bars?",
    ["O"] = "Bring 20 tin bars to Grunt Maug in Durotar.",
    ["T"] = "The Horde Needs More Tin Bars!",
  },
  [8544] = {
    ["D"] =
    "It is said among us that the ornate shoulder armor worn by the mortal races started as an attempt to emulate the wings of a dragon.$B$BBring me the bindings worn by the highest Qiraji leaders and I shall shape them into a set of pauldrons more dreadful than even the wings of Nefarian himself!",
    ["O"] =
    "Bring the Qiraji Bindings of Command, 2 Idols of Night, 5 Stone Scarabs and 5 Clay Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Neutral reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Conqueror\'s Spaulders",
  },
  [8545] = {
    ["D"] =
    "$C, the war it is comin\' and the only thing we can do is prepare for it. That be where you and I can help each other, mon. Ya see, they put me in charge of collectin\' all the mithril bars we be needin\' ta build for all the things we gonna need. An I still be needin\' more!$B$BSo, I be hopin\' that you can get out there an mine us up some mithril, then smelt it into bars. Sound like something you can do for us?",
    ["O"] = "Bring 20 Mithril Bars to Senior Sergeant T\'kelah at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Mithril Bars!",
  },
  [8548] = {
    ["D"] =
    "The badges you collect from performing combat, logistics and tactical assignments for Cenarion Hold are more than just for show, $N.$B$BYou\'d be wise to hold on to them.  As you prove your loyalty to our organization I can offer you some of the gear we reserve for our closest allies in exchange for those badges.",
    ["O"] =
    "Bring 5 Cenarion Combat Badges, 3 Cenarion Logistics Badges and 7 Cenarion Tactical Badges to Vargus at Cenarion Hold in Silithus.  You must also attain Friendly reputation with Cenarion Circle to be able to complete this quest.",
    ["T"] = "Volunteer\'s Battlegear",
  },
  [8549] = {
    ["D"] =
    "It is said that every generation must face a defining trial. I fear the Ahn\'Qiraj War will be the crucible in which our mettle is tested. So we prepare, and in so doing find what we are made of.$B$BI have volunteered to help the Horde by gathering as much peacebloom as possible, so that it can be made into potions for the war. I hope that you are here to lend me your aid. If so, then I need you to bring back to me a good quantity of the herb. Will you assist me, $C?",
    ["O"] = "Bring 20 Peacebloom to Herbalist Proudfeather at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Peacebloom!",
  },
  [8551] = {
    ["D"] =
    "I used to sail a ship from here all the way to Ratchet, in Kalimdor.  I was a successful captain with a sterling reputation.$B$BUntil...$B$BThose cursed sea giants ruined me!  They smashed my ship, killed my crew, and set me on a lifeboat to Booty Bay.  And one of the giants, Gorlash, stole my Captain\'s Chest.  He said he wanted it for a snuffbox.  The nerve!$B$BI hear Gorlash wanders the coast east of here.  Find him and get back my chest!  Do that, and you\'ll have earned a captain\'s gratitude.",
    ["O"] = "Bring Smotts\' Chest to Hecklebury Smotts in Booty Bay.",
    ["T"] = "The Captain\'s Chest",
  },
  [8552] = {
    ["D"] = "This fine sash has the letters \"HS\" embroidered along its hem.",
    ["O"] = "Return the Monogrammed Sash to its owner.",
    ["T"] = "The Monogrammed Sash",
  },
  [8553] = {
    ["D"] =
    "After I lost my first ship to those giants, I bought another.  Named Smotts\' Revenge, I filled it with supplies and crew, and set out to find the villains.  I found them, but...they beat me.  They smashed Smotts\' Revenge, killed my second crew and set me on another lifeboat.$B$BThis time another of the giants, Negolash, stole my cutlass.$B$BFace Negolash and bring me my cutlass!$B$BSpeak with Sprogger.  He was my cook on the Smotts\' Revenge, and survived the last attack.  He can help you find the giant.",
    ["O"] = "Speak with Sprogger.",
    ["T"] = "The Captain\'s Cutlass",
  },
  [8554] = {
    ["D"] =
    "Negolash is a hungry giant.$B$BWhen the giants destroyed our ship, Negolash went straight for my kitchen.  He wasn\'t hungry for crew like the other giants.  Negolash wanted wine...and my Barbecued Buzzard Wings.  They\'re my specialty, and I had to go all the way to the Badlands for the recipe!$B$BIf you want to lure the giant, then get some wine and a heap of buzzard wings.  Put them in our old lifeboat, southeast of here along the coast.  When Negolash smells all that food, he\'ll come for sure!",
    ["O"] =
    "Bring 10 Barbecued Buzzard Wings and 5 bottles of Junglevine Wine to Captain Smotts\' Lifeboat.$B$BKill Negolash, and bring Smotts\' Cutlass to Captain Smotts in Stranglethorn.",
    ["T"] = "Facing Negolash",
  },
  [8555] = {
    ["T"] = "The Charge of the Dragonflights",
  },
  [8556] = {
    ["D"] =
    "The rings worn by the Qiraji lieutenants are rumored to grant them formidable abilities.  The corrupted gems that adorn them could, in theory, be swapped out with more pure materials to create uncorrupted versions of the rings.$B$BThe gems that adorn Qiraji idols would work quite well, as their quality is superior.$B$BBring me the ring and idols and I\'ll create a powerful ring for you, $C.",
    ["O"] =
    "Bring 1 Qiraji Magisterial Ring, 2 Lambent Idols, 5 Bronze Scarabs and 5 Ivory Scarabs to Windcaller Yessendra in Silithus.  You must also attain Honored reputation with Cenarion Circle to complete this quest.",
    ["T"] = "Signet of Unyielding Strength",
  },
  [8557] = {
    ["D"] =
    "I\'m glad to hear you\'re aiding us in our attack on Ahn\'Qiraj, $N.  I can make you a protective item that\'ll be of assistance in the fight against our enemy, $C.$B$BI shall need a Qiraji drape, which I\'ll resize for you of course.  I\'ll also need idols and scarabs which I\'ll use to create a suitable clasp.$B$BI promise you won\'t be disappointed.",
    ["O"] =
    "Bring 1 Qiraji Martial Drape, 2 Onyx Idols, 5 Silver Scarabs and 5 Bone Scarabs to Keyl Swiftclaw in Silithus.  You must also obtain Revered reputation with Cenarion Circle to complete this quest.",
    ["T"] = "Drape of Unyielding Strength",
  },
  [8558] = {
    ["D"] =
    "The Qiraji and their servants wield items made with the rarest and finest materials: bones from gargantuan ancient creatures, gems from the depths of the earth, metals pure and strong.$B$BJust the sight of Qiraji artifacts fills me with an urge to practice my craft with their shattered and smelted pieces.  Prove your allegiance to the Circle, $N, and I will make you a powerful weapon from the finest Qiraji materials.",
    ["O"] =
    "Bring 1 Qiraji Spiked Hilt, 2  Alabaster Idols, 5 Crystal Scarabs and 5 Stone Scarabs to Warden Haro in Silithus.  You must also attain Exalted reputation with Cenarion Circle to complete this quest.",
    ["T"] = "Sickle of Unyielding Strength",
  },
  [8559] = {
    ["D"] =
    "Qiraji magic is strong and ancient.  The most powerful qiraji wield items of such might, they\'d give pause even to a dragon.$B$BBring me the qiraji bindings of command and other minor components by and I\'ll create a set of powerful boots for you.$B$BYou will find them useful in the fight against the enemy.",
    ["O"] =
    "Bring the Qiraji Bindings of Command, 2 Idols of War, 5 Ivory Scarabs and 5 Gold Scarabs to Kandrostrasz in Ahn\'Qiraj.  This quest also requires Neutral faction with the Brood of Nozdormu.",
    ["T"] = "Conqueror\'s Greaves",
  },
  [8560] = {
    ["D"] =
    "You seek to prove your worth to my kind, mortal?  Very well, perhaps we can be of mutual assistance.$B$BThe ancient sandworm, Ouro, is a being of legendary power.  He is rumored to have been created by the Old God himself as a mockery of life.$B$BHis skin is unnatural... thick, nearly impregnable, yet it\'s flexible and allows him to move with the speed and grace of a much smaller creature.$B$BBring me a sample of his skin along with other minor components and I shall craft you leggings of great power.",
    ["O"] =
    "Bring Ouro\'s Intact Hide, 2 Idols of Death, 5 Bronze Scarabs and 5 Ivory Scarabs to Kandrostrasz inside Ahn\'Qiraj. You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Conqueror\'s Legguards",
  },
  [8561] = {
    ["D"] =
    "The Twin Emperors... their incessant whispers are slowly taking a toll on my sanity.  They mock me, knowing I cannot step further into their domain to save my brother Arygos.$B$BIn my visions I see their monstrous faces adorned by powerful crowns.  But I will have my revenge... I will transmute these symbols of Qiraji power to ones better suited to our needs.$B$BBring me the components I require, $N.  I will give you a headpiece of unmatched power.",
    ["O"] =
    "Bring Vek\'nilash\'s Circlet, 2 Idols of the Sun, 5 Stone Scarabs and 5 Crystal Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Conqueror\'s Crown",
  },
  [8562] = {
    ["D"] =
    "The unmentionable Old God slowly awakens from his slumber beneath Ahn\'Qiraj.  The terrible fate that awaits Azeroth could come in days or years; time has no meaning for beings of his power.$B$BWhen the stars are favorable, he will lash out against all living beings with terrible wrath.  You must find him before then and find a way to bring his existence to an end.$B$BDo this and bring me a piece of his husk.  I shall grant you armor no mortal has ever worn... armor fit for one who has slain a god!",
    ["O"] =
    "Bring the the Carapace of the Old God, 2 Idols of War, 5 Silver Scarabs and 5 Bone Scarabs to Vethsera inside Ahn\'Qiraj.  You must also attain Honored reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Conqueror\'s Breastplate",
  },
  [8572] = {
    ["D"] =
    "The badges you collect from performing combat, logistics and tactical assignments for Cenarion Hold are more than just for show, $N.$B$BYou\'d be wise to hold on to them.  As you prove your loyalty to our organization I can offer you some of the gear we reserve for our closest allies in exchange for those badges.",
    ["O"] =
    "Bring 7 Cenarion Combat Badges, 4 Cenarion Logistics Badges and 4 Cenarion Tactical Badges to Vargus at Cenarion Hold in Silithus.  You must also attain Honored reputation with Cenarion Circle to be able to complete this quest.",
    ["T"] = "Veteran\'s Battlegear",
  },
  [8573] = {
    ["D"] =
    "The badges you collect from performing combat, logistics and tactical assignments for Cenarion Hold are more than just for show, $N.$B$BYou\'d be wise to hold on to them.  As you prove your loyalty to our organization I can offer you some of the gear we reserve for our closest allies in exchange for those badges.",
    ["O"] =
    "Bring 15 Cenarion Combat Badges, 20 Cenarion Logistics Badges, 20 Cenarion Tactical Badges and 1 Mark of Cenarius to Vargus at Cenarion Hold in Silithus.  You must also attain Exalted reputation with Cenarion Circle to be able to complete this quest.",
    ["T"] = "Champion\'s Battlegear",
  },
  [8574] = {
    ["D"] =
    "The badges you collect from performing combat, logistics and tactical assignments for Windcaller Proudhorn are more than just for show, $N.$B$BYou\'d be wise to hold on to them.  As you prove your loyalty to our organization I can offer you some of the gear we reserve for our closest allies in exchange for those badges.",
    ["O"] =
    "Bring 15 Cenarion Combat Badges, 20 Cenarion Logistics Badges, 17 Cenarion Tactical Badges and 1 Mark of Remulos to Vargus at Cenarion Hold in Silithus.  You must also attain Revered reputation with Cenarion Circle to be able to complete this quest.",
    ["T"] = "Stalwart\'s Battlegear",
  },
  [8575] = {
    ["D"] = "You cannot understand a single word on this ledger. You don\'t even know what language it is written in!",
    ["O"] = "Deliver Azuregos\'s Magical Ledger to Narain Soothfancy in Tanaris.",
    ["T"] = "Azuregos\'s Magical Ledger",
  },
  [8576] = {
    ["T"] = "Translating the Ledger",
  },
  [8577] = {
    ["D"] =
    "If I am to translate anything, I will need my scrying goggles. Unfortunately, those were stolen quite some time ago by my ex-best friend forever, Stewvul. He broke my heart in five places and then left me here to rot.$B$BWith the help of my trusty crystal ball, I\'ve isolated his whereabouts to either the Greymane Wall in Silverpine or what appears to be a portal world in the Outland that is currently being overrun by the Burning Legion. You\'re going to have to track him down and get my goggles back, $N!",
    ["O"] =
    "Narain Soothfancy wants you to find his ex-best friend forever (BFF), Stewvul, and take back the scrying goggles that Stewvul stole from him.",
    ["T"] = "Stewvul, Ex-B.F.F.",
  },
  [8578] = {
    ["D"] =
    "$B$BYou just want his scrying goggles? Great! That will be no problem... Just give me a minute to... Hey! Where the... Dagnabbit!$B$BWell, there\'s some bad news and some worse news. The bad news is that I lost the goggles. The worse news is that I lost them when I was nosing around in the Molten Core last month. Yep, the Molten Core... I guess that concludes our business! Bye!",
    ["O"] = "Find Narain\'s Scrying Goggles and return them to Narain Soothfancy in Tanaris.",
    ["T"] = "Scrying Goggles? No Problem!",
  },
  [8580] = {
    ["D"] =
    "Hey, $C. Ya you, mon! There be a whole mess of firebloom the Horde thinkin\' they need for this Ahn\'Qiraj war effort. Maybe they put it in nice things that go boom? Maybe they give it to the Alliance as fuel for their steam tanks? Who knows? Not Pele\'keiki!$B$BPele\'keiki know this though... he know you gonna help him out and bring back lots of the firebloom, right, mon?",
    ["O"] = "Bring 20 Firebloom to Batrider Pele\'keiki at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Firebloom!",
  },
  [8582] = {
    ["D"] =
    "The purple lotus, $C, is a reagent in a great many potions, elixirs and oils, some of which will be of use to us at Ahn\'Qiraj. We\'re going to need to create an immense number of those potions for the war effort. And I\'m going to experiment to find more uses for the lotus as well. But to do all of that I\'m going to need a great quantity of the flower.$B$BThat\'s where you come in. Go out into the field and collect up as many purple lotuses as you can. Is this something that you are willing to do for us?",
    ["O"] = "Bring 20 Purple Lotus to Apothecary Jezel at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Purple Lotus!",
  },
  [8584] = {
    ["D"] =
    "If there is one thing that you should know about me, it is this: NEVER ask me about my business! I work with things you simply cannot understand. Like for example: Do you know what a psychotronic muzzledorf is? Of course you don\'t! And that\'s why we leave the planning to me and the fetching to you.$B$BAs I said earlier, if this is going to work, we\'re going to need a 500 pound chicken.$B$BHead to Gadgetzan and speak with Dirge Quikcleave - he\'ll get you started on finding a suitable specimen.",
    ["O"] = "Narain Soothfancy in Tanaris wants you to speak with Dirge Quikcleave in Gadgetzan.",
    ["T"] = "Never Ask Me About My Business",
  },
  [8586] = {
    ["D"] =
    "My recipe is complete! What I need from you now is some rocket fuel and deeprock salt. I\'ll handle the spices and the meat you brought me will cover the rest.$B$BAfter you bring me what I asked for, the chicken will be ready to take back to Narain.",
    ["O"] = "Dirge Quikcleave in Gadgetzan wants you to bring him 20 Goblin Rocket Fuel and 20 Deeprock Salt.",
    ["T"] = "Dirge\'s Kickin\' Chimaerok Chops",
  },
  [8587] = {
    ["D"] =
    "I\'m a goblin of my word, kid. Here\'s your 500 pound chicken.$B$BWhat a gnome wants with a 500 pound chicken, I\'ll never know...$B$B$B$BProbably to sleep in it... Dirty gnomes...",
    ["O"] = "Deliver the 500 Pound Chicken to Narain Soothfancy in Tanaris.",
    ["T"] = "Return to Narain",
  },
  [8588] = {
    ["D"] =
    "Since we\'re preparing for war, it might be best if we get all of the goods we need first, don\'t you think, mon? One of the staples of the war materiel that we\'re producing is heavy leather. We\'ll use it for just about everything, from reinforcement to armor, and good old plain tarps too.$B$BBut first we need to get our hands on more of it. That\'s your job, $C. Sharpen your knife and bring me back a bundle. Then we\'ll talk further.",
    ["O"] = "Bring 10 Heavy Leather to Skinner Jamani at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Heavy Leather!",
  },
  [8590] = {
    ["D"] =
    "I\'m glad that you decided to speak to me about this, $C. It looks like the Horde\'s preparations for the upcoming Ahn\'Qiraj War are in full swing. But you and I still need to do our part.$B$BI\'ve been asked to collect a great number of thick leather skins for use in all manner of war materiel, and I need you to help me by going out there and gathering them up. There\'s honor and the gratitude of the Horde in it for you should you decide to help. Will you?",
    ["O"] = "Bring 10 Thick Leather to Sergeant Umala at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Thick Leather!",
  },
  [8592] = {
    ["D"] =
    "The Twin Emperors... their incessant whispers are slowly taking a toll on my sanity.  They mock me, knowing I cannot step further into their domain to save my brother Arygos.$B$BIn my visions I see their monstrous faces adorned by powerful crowns.  But I will have my revenge... I will transmute these symbols of Qiraji power to ones better suited to our needs.$B$BBring me the components I require, $N.  I will give you a headpiece of unmatched power.",
    ["O"] =
    "Bring Vek\'nilash\'s Circlet, 2 Idols of the Sage, 5 Silver Scarabs and 5 Bone Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Tiara of the Oracle",
  },
  [8593] = {
    ["D"] =
    "You seek to prove your worth to my kind, mortal?  Very well, perhaps we can be of mutual assistance.$B$BThe ancient sandworm, Ouro, is a being of legendary power.  He is rumored to have been created by the Old God himself as a mockery of life.$B$BHis skin is unnatural... thick, nearly impregnable, yet it\'s flexible and allows him to move with the speed and grace of a much smaller creature.$B$BBring me a sample of his skin along with other minor components and I shall craft you leggings of great power.",
    ["O"] =
    "Bring Ouro\'s Intact Hide, 2 Idols of Life, 5 Gold Scarabs and 5 Clay Scarabs to Kandrostrasz inside Ahn\'Qiraj. You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Trousers of the Oracle",
  },
  [8594] = {
    ["D"] =
    "It is said among us that the ornate shoulder armor worn by the mortal races started as an attempt to emulate the wings of a dragon.$B$BBring me the bindings worn by the highest Qiraji leaders and I shall shape them into a set of pauldrons more dreadful than even the wings of Nefarian himself!",
    ["O"] =
    "Bring the Qiraji Bindings of Command, 2 Idols of Rebirth, 5 Silver Scarabs and 5 Ivory Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Neutral reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Mantle of the Oracle",
  },
  [8596] = {
    ["D"] =
    "Qiraji magic is strong and ancient.  The most powerful qiraji wield items of such might, they\'d give pause even to a dragon.$B$BBring me the qiraji bindings of command and other minor components by and I\'ll create a set of powerful boots for you.$B$BYou will find them useful in the fight against the enemy.",
    ["O"] =
    "Bring the Qiraji Bindings of Command, 2 Idols of Death, 5 Bronze Scarabs and 5 Gold Scarabs to Kandrostrasz in Ahn\'Qiraj.  This quest also requires Neutral faction with the Brood of Nozdormu.",
    ["T"] = "Footwraps of the Oracle",
  },
  [8597] = {
    ["D"] =
    "I knew that book would come in handy some day! Thankfully, I had the wit and foresight to stow it somewhere safe.$B$BDon\'t worry, it\'s in a place that nobody could ever hope to find it! I needed a gyrocopter just to get there the first time. Unfortunately I crashed it on the beach on my way back. It was through that accident that I gained these super-gnomish psychic powers!$B$BLook for my crashed gyrocopter somewhere on Land\'s End Beach and swim south from there! You\'ll know the spot when you see it!",
    ["O"] = "Find Narain Soothfancy\'s book, buried on an island in the South Seas.",
    ["T"] = "Draconic for Dummies",
  },
  [8598] = {
    ["D"] =
    "$B$BWe\'ve got your precious book, gnome. If you ever want to see it again, you\'ll do exactly as we ask.$B$B<A detailed set of instructions is listed, spanning 3 pages.>$B$BBring the money and come alone!",
    ["O"] = "Return the Ransom Letter to Narain Soothfancy in Tanaris.",
    ["T"] = "rAnS0m",
  },
  [8599] = {
    ["D"] =
    "It isn\'t often that I get visitors. As a matter of fact, the last time I had a visitor was when I rescued that dear, sweet gnome from the wreckage of the crashed flying machine.$B$B$B$BDo you know him? Narain? Narain Soothfancy? Oh it would mean so much to me if somebody would deliver a message to him for me. I must tell him how I feel! I know it\'s love! I just know it!$B$BCould you possibly deliver a message to Narain? I would be forever indebted to you!",
    ["O"] = "Take Meridith\'s Love Letter to Narain Soothfancy in Tanaris.",
    ["T"] = "Love Song for Narain",
  },
  [8600] = {
    ["D"] =
    "I find that the fit of the knife in your palm is more important than the edge on it. Even the dullest blade can be made to cut if pressure is being properly applied through it, wouldn\'t you agree, $C? But you and I don\'t have such problems as we maintain the sharpest of edges, yes?$B$BWell, no matter, I have a task for you. In service to the Horde, and to do your part for the Ahn\'Qiraj war effort, I want you to return to me with a number of rugged leather skins. This is something that you will do, no?",
    ["O"] = "Bring 10 Rugged Leather to Doctor Serratus at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Rugged Leather!",
  },
  [8602] = {
    ["D"] =
    "It is said among us that the ornate shoulder armor worn by the mortal races started as an attempt to emulate the wings of a dragon.$B$BBring me the bindings worn by the highest Qiraji leaders and I shall shape them into a set of pauldrons more dreadful than even the wings of Nefarian himself!",
    ["O"] =
    "Bring the Qiraji Bindings of Dominance, 2 Idols of Life, 5 Gold Scarabs and 5 Crystal Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Neutral reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Stormcaller\'s Pauldrons",
  },
  [8603] = {
    ["D"] =
    "The unmentionable Old God slowly awakens from his slumber beneath Ahn\'Qiraj.  The terrible fate that awaits Azeroth could come in days or years; time has no meaning for beings of his power.$B$BWhen the stars are favorable, he will lash out against all living beings with terrible wrath.  You must find him before then and find a way to bring his existence to an end.$B$BDo this and bring me a piece of his husk.  I shall grant you armor no mortal has ever worn... armor fit for one who has slain a god!",
    ["O"] =
    "Bring the the Husk of the Old God, 2 Idols of Death, 5 Stone Scarabs and 5 Crystal Scarabs to Vethsera inside Ahn\'Qiraj.  You must also attain Honored reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Vestments of the Oracle",
  },
  [8604] = {
    ["D"] =
    "Greetings, $C. In preparation for the war at Ahn\'Qiraj, I am here coordinating the Horde\'s efforts at gathering wool bandages. Unfortunately, out in the field, our soldiers cannot afford to rely upon the presence of a healer to keep them alive. Trust me, I know first hand. Thus, we\'re putting together all of these first aid kits for them.$B$BIf you have the time, I need many wool bandages. Return them to me here and I will see to it that you are properly rewarded.",
    ["O"] = "Bring 20 Wool Bandages to Healer Longrunner at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Wool Bandages!",
  },
  [8606] = {
    ["D"] =
    "I\'ve got it! Here\'s what we\'re going to do. I\'m going to fill a sack up with rocks and you\'re going to make the drop. I know it said that I should make the delivery and I\'m going to - sort of.$B$B$B$BYes, you will do just fine. Take this turban, robe, and sack of rocks and head to the drop off point in Winterspring.$B$BI\'ve included everything you need in this special kit. When they show up to pick up the goods, snuff them out! That will teach them to mess with Narain!",
    ["O"] =
    "Narain Soothfancy in Tanaris wants you to travel to Winterspring and place the Bag of Gold at the drop off point documented by the booknappers.",
    ["T"] = "Decoy!",
  },
  [8607] = {
    ["D"] =
    "I trust that you are speaking to me because you are going to help with the collection I have been entrusted to? Good! By whatever means, and I do mean whatever, I wish for you to gather up a good number of mageweave bandages. Fresh would be nice, but not absolutely necessary. Return them to me here, $C, and I will personally see to it that you are properly rewarded.",
    ["O"] = "Bring 20 Mageweave Bandages to Lady Callow at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Mageweave Bandages!",
  },
  [8609] = {
    ["D"] =
    "It appears inevitable that the Horde and Alliance are on a collision course for war at Ahn\'Qiraj. Surprisingly, it is not a war with each other, but rather with the silithid, and whatever force controls them. Also surprisingly, both sides are doing their part to gather the resources necessary to wage a successful war.$B$BI am collecting runecloth bandages to distribute to the soldiers, but I won\'t be successful without assistance, hopefully yours. Is this something that you can aid me with, $C?",
    ["O"] = "Bring 20 Runecloth Bandages to Stoneguard Clayhoof at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Runecloth Bandages!",
  },
  [8611] = {
    ["D"] =
    "I\'m not standing here just to get a nice tan, $C. There are war preparations to be made. If we\'re going to crush those bugs at Ahn\'Qiraj then we need to be ready, and that includes food too!$B$BThey have me gathering and salting lean wolf steaks here for the upcoming war. But since I need to stay here to take care of all of this, I need you to go out, kill some wolves and then cook up the meat into lean wolf steaks and bring them back to me here. You got all that?",
    ["O"] = "Bring 20 Lean Wolf Steaks to Bloodguard Rawtar at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Lean Wolf Steaks!",
  },
  [8613] = {
    ["D"] =
    "It be a nice day for fishin\', don\'t\'cha think mon? Good thing, cuz I be needin\' a lot of fish it lookin\' like. The Horde, they askin\' me to be in charge of collectin\' a ton of the spotted yellowtail for them. They say they needin\' it for the war they getting\' ready for at Ahn\'Qiraj. I say to them I do the best I can. So I be needin\' to get some help. You gonna be helpin\' me, $C?",
    ["O"] = "Bring 20 Spotted Yellowtail to Fisherman Lin\'do at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Spotted Yellowtail!",
  },
  [8615] = {
    ["D"] =
    "The Ahn\'Qiraj war effort is an immense undertaking, $C. All of the materials being gathered here, whether it is metal for weapons, or food to eat, are all as important as the other. For, if you haven\'t eaten in days you will not have the strength to lift your axe when it matters.$B$BThus, we gather what food we can. I am collecting baked salmon, a dish that was chosen both for its sustenance and its ability to keep well. Can you aid me with this task, $C?",
    ["O"] = "Bring 20 Baked Salmon to Chief Sharpclaw at the Valley of Spirits in Orgrimmar.",
    ["T"] = "The Horde Needs Baked Salmon!",
  },
  [8619] = {
    ["T"] = "Morndeep the Elder",
  },
  [8620] = {
    ["D"] =
    "I should have known. My arch-enemy, Doctor Weavil, up to his old tricks! And now, thanks to your failure in Winterspring, Doctor Weavil has destroyed my book! How are you going to save the world now, hero?$B$BThe note I received stated that the only known copy of \"Draconic for Dummies: Volume II\" was ripped into 8 parts and scattered to the wind! If you somehow manage to find those missing chapters, use this magical binding to put them back together and return to me.",
    ["O"] =
    "Recover the 8 lost chapters of Draconic for Dummies and combine them with the Magical Book Binding and return the completed book of Draconic for Dummies: Volume II to Narain Soothfancy in Tanaris.",
    ["T"] = "The Only Prescription",
  },
  [8621] = {
    ["D"] =
    "Qiraji magic is strong and ancient.  The most powerful qiraji wield items of such might, they\'d give pause even to a dragon.$B$BBring me the qiraji bindings of dominance and other minor components and I\'ll create a set of powerful boots for you.$B$BYou will find them useful in the fight against the enemy.",
    ["O"] =
    "Bring the Qiraji Bindings of Dominance, 2 Idols of the Sage, 5 Bronze Scarabs and 5 Clay Scarabs to Kandrostrasz in Ahn\'Qiraj.  This quest also requires Neutral faction with the Brood of Nozdormu.",
    ["T"] = "Stormcaller\'s Footguards",
  },
  [8622] = {
    ["D"] =
    "The unmentionable Old God slowly awakens from his slumber beneath Ahn\'Qiraj.  The terrible fate that awaits Azeroth could come in days or years; time has no meaning for beings of his power.$B$BWhen the stars are favorable, he will lash out against all living beings with terrible wrath.  You must find him before then and find a way to bring his existence to an end.$B$BDo this and bring me a piece of his husk.  I shall grant you armor no mortal has ever worn... armor fit for one who has slain a god!",
    ["O"] =
    "Bring the Carapace of the Old God, 2 Idols of the Sage, 5 Silver Scarabs and 5 Bone Scarabs to Vethsera inside Ahn\'Qiraj.  You must also attain Honored reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Stormcaller\'s Hauberk",
  },
  [8623] = {
    ["D"] =
    "The Twin Emperors... their incessant whispers are slowly taking a toll on my sanity.  They mock me, knowing I cannot step further into their domain to save my brother Arygos.$B$BIn my visions I see their monstrous faces adorned by powerful crowns.  But I will have my revenge... I will transmute these symbols of Qiraji power to ones better suited to our needs.$B$BBring me the components I require, $N.  I will give you a headpiece of unmatched power.",
    ["O"] =
    "Bring Vek\'lor\'s Diadem, 2 Idols of Rebirth, 5 Stone Scarabs and 5 Crystal Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Stormcaller\'s Diadem",
  },
  [8624] = {
    ["D"] =
    "You seek to prove your worth to my kind, mortal?  Very well, perhaps we can be of mutual assistance.$B$BThe ancient sandworm, Ouro, is a being of legendary power.  He is rumored to have been created by the Old God himself as a mockery of life.$B$BHis skin is unnatural... thick, nearly impregnable, yet it\'s flexible and allows him to move with the speed and grace of a much smaller creature.$B$BBring me a sample of his skin along with other minor components and I shall craft you leggings of great power.",
    ["O"] =
    "Bring the Skin of the Great Sandworm, 2 Idols of Strife, 5 Bronze Scarabs and 5 Ivory Scarabs to Kandrostrasz inside Ahn\'Qiraj. You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Stormcaller\'s Leggings",
  },
  [8626] = {
    ["D"] =
    "Qiraji magic is strong and ancient.  The most powerful qiraji wield items of such might, they\'d give pause even to a dragon.$B$BBring me the qiraji bindings of command and other minor components by and I\'ll create a set of powerful boots for you.$B$BYou will find them useful in the fight against the enemy.",
    ["O"] =
    "Bring the Qiraji Bindings of Command, 2 Idols of Life, 5 Stone Scarabs and 5 Bone Scarabs to Kandrostrasz in Ahn\'Qiraj.  This quest also requires Neutral faction with the Brood of Nozdormu.",
    ["T"] = "Striker\'s Footguards",
  },
  [8627] = {
    ["D"] =
    "The unmentionable Old God slowly awakens from his slumber beneath Ahn\'Qiraj.  The terrible fate that awaits Azeroth could come in days or years; time has no meaning for beings of his power.$B$BWhen the stars are favorable, he will lash out against all living beings with terrible wrath.  You must find him before then and find a way to bring his existence to an end.$B$BDo this and bring me a piece of his husk.  I shall grant you armor no mortal has ever worn... armor fit for one who has slain a god!",
    ["O"] =
    "Bring the the Carapace of the Old God, 2 Idols of the Sage, 5 Silver Scarabs and 5 Bone Scarabs to Vethsera inside Ahn\'Qiraj.  You must also attain Honored reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Avenger\'s Breastplate",
  },
  [8628] = {
    ["D"] =
    "The Twin Emperors... their incessant whispers are slowly taking a toll on my sanity.  They mock me, knowing I cannot step further into their domain to save my brother Arygos.$B$BIn my visions I see their monstrous faces adorned by powerful crowns.  But I will have my revenge... I will transmute these symbols of Qiraji power to ones better suited to our needs.$B$BBring me the components I require, $N.  I will give you a headpiece of unmatched power.",
    ["O"] =
    "Bring Vek\'lor\'s Diadem, 2 Idols of Rebirth, 5 Stone Scarabs and 5 Crystal Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Avenger\'s Crown",
  },
  [8629] = {
    ["D"] =
    "You seek to prove your worth to my kind, mortal?  Very well, perhaps we can be of mutual assistance.$B$BThe ancient sandworm, Ouro, is a being of legendary power.  He is rumored to have been created by the Old God himself as a mockery of life.$B$BHis skin is unnatural... thick, nearly impregnable, yet it\'s flexible and allows him to move with the speed and grace of a much smaller creature.$B$BBring me a sample of his skin along with other minor components and I shall craft you leggings of great power.",
    ["O"] =
    "Bring the Skin of the Great Sandworm, 2 Idols of Strife, 5 Bronze Scarabs and 5 Ivory Scarabs to Kandrostrasz inside Ahn\'Qiraj. You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Avenger\'s Legguards",
  },
  [8630] = {
    ["D"] =
    "It is said among us that the ornate shoulder armor worn by the mortal races started as an attempt to emulate the wings of a dragon.$B$BBring me the bindings worn by the highest Qiraji leaders and I shall shape them into a set of pauldrons more dreadful than even the wings of Nefarian himself!",
    ["O"] =
    "Bring the Qiraji Bindings of Dominance, 2 Idols of Life, 5 Crystal Scarabs and 5 Gold Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Neutral reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Avenger\'s Pauldrons",
  },
  [8631] = {
    ["D"] =
    "You seek to prove your worth to my kind, mortal?  Very well, perhaps we can be of mutual assistance.$B$BThe ancient sandworm, Ouro, is a being of legendary power.  He is rumored to have been created by the Old God himself as a mockery of life.$B$BHis skin is unnatural... thick, nearly impregnable, yet it\'s flexible and allows him to move with the speed and grace of a much smaller creature.$B$BBring me a sample of his skin along with other minor components and I shall craft you leggings of great power.",
    ["O"] =
    "Bring Ouro\'s Intact Hide, 2 Idols of the Sage, 5 Silver Scarabs and 5 Bone Scarabs to Kandrostrasz inside Ahn\'Qiraj. You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Enigma Leggings",
  },
  [8632] = {
    ["D"] =
    "The Twin Emperors... their incessant whispers are slowly taking a toll on my sanity.  They mock me, knowing I cannot step further into their domain to save my brother Arygos.$B$BIn my visions I see their monstrous faces adorned by powerful crowns.  But I will have my revenge... I will transmute these symbols of Qiraji power to ones better suited to our needs.$B$BBring me the components I require, $N.  I will give you a headpiece of unmatched power.",
    ["O"] =
    "Bring Vek\'nilash\'s Circlet, 2 Idols of Night, 5 Bronze Scarabs and 5 Ivory Scarabs to Andorgos in Ahn\'Qiraj.  You must also attain Friendly reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Enigma Circlet",
  },
  [8633] = {
    ["D"] =
    "The unmentionable Old God slowly awakens from his slumber beneath Ahn\'Qiraj.  The terrible fate that awaits Azeroth could come in days or years; time has no meaning for beings of his power.$B$BWhen the stars are favorable, he will lash out against all living beings with terrible wrath.  You must find him before then and find a way to bring his existence to an end.$B$BDo this and bring me a piece of his husk.  I shall grant you armor no mortal has ever worn... armor fit for one who has slain a god!",
    ["O"] =
    "Bring the Husk of the Old God, 2 Idols of the Sun, 5 Gold Scarabs and 5 Clay Scarabs to Vethsera inside Ahn\'Qiraj.  You must also attain Honored reputation with the Brood of Nozdormu to complete this quest.",
    ["T"] = "Enigma Robes",
  },
  [8634] = {
    ["D"] =
