  [8687] = {
    ["D"] =
    "Reinforcements have been called on to join the assault on Hive\'Zora.  You have been selected to target Hive\'Zora tunnelers.  Report back to Commander Mar\'alith after completing your task.",
    ["O"] =
    "Slay 30 Hive\'Zora Tunnelers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing VII in order to complete this quest.",
    ["T"] = "Target: Hive\'Zora Tunnelers",
