  },
  [8763] = {
    ["D"] =
    "Listen... I\'m not really supposed to be telling you this, but since you\'re the hero of the day and all...$B$BThere\'s fresh holly everywhere this time of the year, but it never lasts.  We\'ve got a machine that preserves holly - it never goes bad!  We use it to spice up the holiday... and profits during the summer!$B$BI\'ll let you use the preserver, but only if you\'re a master cook.  You\'ll need some deeprock salt and two, three, oh let\'s say five gold.  It\'ll net you a nice batch that\'s yours to keep.",
    ["O"] =
    "Bring 1 Deeprock Salt and 5 gold coins to any Holly Preserver machine, upon which you will receive 5 Preserved Holly.",
    ["T"] = "The Hero of the Day",
  },
  [8764] = {
    ["T"] = "The Changing of Paths - Protector No More",
  },
  [8765] = {
    ["T"] = "The Changing of Paths - Invoker No More",
  },
  [8766] = {
    ["T"] = "The Changing of Paths - Conqueror No More",
  },
  [8767] = {
    ["T"] = "A Gently Shaken Gift",
  },
  [8768] = {
    ["T"] = "A Gaily Wrapped Present",
  },
  [8769] = {
    ["T"] = "A Ticking Present",
  },
  [8770] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Ashi where your primary target will consist of Hive\'Ashi defenders.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Slay 30 Hive\'Ashi Defenders and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing I in order to complete this quest.",
    ["T"] = "Target: Hive\'Ashi Defenders",
  },
  [8771] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Ashi where your primary target will consist of Hive\'Ashi sandstalkers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Slay 30 Hive\'Ashi Sandstalkers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing II in order to complete this quest.",
    ["T"] = "Target: Hive\'Ashi Sandstalkers",
  },
  [8772] = {
    ["D"] =
    "Reinforcements have been called on to join the assault on Hive\'Zora.  You have been selected to target Hive\'Zora waywatchers.  Report back to Commander Mar\'alith after completing your task.",
    ["O"] =
    "Slay 30 Hive\'Zora Waywatchers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing VI in order to complete this quest.",
    ["T"] = "Target: Hive\'Zora Waywatchers",
  },
  [8773] = {
    ["D"] =
    "Reinforcements have been called on to join the assault on Hive\'Zora.  You have been selected to target Hive\'Zora reavers.  Report back to Commander Mar\'alith after completing your task.",
    ["O"] =
    "Slay 30 Hive\'Zora Reavers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing IV in order to complete this quest.",
    ["T"] = "Target: Hive\'Zora Reavers",
  },
  [8774] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Regal where your primary target will consist of the Hive\'Regal ambushers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Kill 30 Hive\'Regal Ambushers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing VIII in order to complete this quest.",
    ["T"] = "Target: Hive\'Regal Ambushers",
  },
  [8775] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Regal where your primary target will consist of the airborne Hive\'Regal spitfires.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Kill 30 Hive\'Regal Spitfires and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing IX in order to complete this quest.",
    ["T"] = "Target: Hive\'Regal Spitfires",
  },
  [8776] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Regal where your primary target will consist of the Hive\'Regal slavemakers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Kill 30 Hive\'Regal Slavemakers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing X in order to complete this quest.",
    ["T"] = "Target: Hive\'Regal Slavemakers",
  },
  [8777] = {
    ["D"] =
    "As the war effort mounts, the silithid presence in the area presents an ever increasing threat to our operations.  You\'ve been selected to partake on an assault on Hive\'Regal where your primary target will consist of Hive\'Regal burrowers.$B$BReport back to Commander Mar\'alith after your task is completed.",
    ["O"] =
    "Kill 30 Hive\'Regal Burrowers and report back to Commander Mar\'alith at Cenarion Hold in Silithus.  You must also bring Combat Task Briefing XI in order to complete this quest.",
    ["T"] = "Target: Hive\'Regal Burrowers",
  },
  [8778] = {
    ["D"] =
    "The Ironforge Brigade has put in an unusual request for highly... volatile... components.  Gather them and bring them to Mr. Nozzlespring from the Ironforge Brigade.",
    ["O"] =
    "Bring 6 Oils of Immolation, 5 Goblin Rocket Fuel and 10 Dense Blasting Powder to Arcanist Nozzlespring near Hive\'Zora in Silithus.  You must also bring Logistics Task Briefing IV in order to complete this quest.",
    ["T"] = "The Ironforge Brigade Needs Explosives!",
  },
  [8779] = {
    ["D"] =
    "Geologist Larksbane\'s studies have proven to be of tremendous value to our operations in Silithus.  She has recently requested scrying materials to be used in her research.$B$BPlease gather these materials and deliver them to her directly so that she may continue her research.",
    ["O"] =
    "Bring 1 Large Brilliant Shard, 1 Large Radiant Shard and 1 Huge Emerald to Geologist Larksbane at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing V in order to complete this quest.",
    ["T"] = "Scrying Materials",
  },
  [8780] = {
    ["D"] =
    "The Ironforge Brigade\'s supply of armor kits in the battlefield is running dangerously low.  Obtain a batch and deliver them to Janela Stouthammer at the Ironforge Brigade\'s outpost outside Hive\'Zora.",
    ["O"] =
    "Bring 8 Rugged Armor Kits and 8 Heavy Armor Kits to Janela Stouthammer at the Ironforge Brigade Outpost near Hive\'Zora in Silithus.  You must also bring Logistics Task Briefing VII in order to complete this quest.",
    ["T"] = "Armor Kits for the Field",
  },
  [8781] = {
    ["D"] =
    "The Ironforge Brigade has been a worthy ally in our fight in Silithus.  Unfortunately, many of their supplies were lost on their way here.  Procure a batch of weapons and deliver them to Janela Stouthammer near Hive\'Zora.",
    ["O"] =
    "Bring 2 Moonsteel Broadswords to Janela Stouthammer at the Ironforge Brigade Outpost outside of Hive\'Zora.  You must also bring Logistics Task Briefing VI in order to complete this quest.",
    ["T"] = "Arms for the Field",
  },
  [8782] = {
    ["D"] =
    "The latest influx of volunteers has caused a shortage of uniforms.  Procure a batch of uniform materials and bring them to Windcaller Proudhorn.",
    ["O"] =
    "Bring 1 Mooncloth, 2 Bolts of Runecloth and 1 Ironweb Spider Silk to Windcaller Proudhorn at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing VIII in order to complete this quest.",
    ["T"] = "Uniform Supplies",
  },
  [8783] = {
    ["D"] =
    "Vargus, Cenarion Hold\'s blacksmith, has requested enchanted materials to be used in the crafting of powerful weapons for our forces.  Obtain these and bring them directly to Vargus so that Cenarion Hold\'s troops may continue to be well equipped.",
    ["O"] =
    "Bring 2 Enchanted Thorium Bars and 2 Enchanted Leather to Vargus at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing IX in order to complete this quest.",
    ["T"] = "Extraordinary Materials",
  },
  [8784] = {
    ["D"] =
    "You have discovered an ancient Qiraji artifact! Perhaps one of the dragons near the entrance of the temple would have a use for this relic.",
    ["O"] = "Take the Ancient Qiraji Artifact to the dragons hiding near the entrance of the temple.",
    ["T"] = "Secrets of the Qiraji",
  },
  [8785] = {
    ["D"] =
    "The Orgrimmar Legion has put in a request for several unusual ingredients.  Given their current performance in Silithus, we\'d like to comply with their request as soon as possible.  Gather the materials and bring them to the troll called Shai.",
    ["O"] =
    "Bring 6 Powerful Mojo, 6 Flasks of Big Mojo and 8 Oils of Immolation to Shadow Priestess Shai near Hive\'Regal in Silithus.  You must also bring Logistics Task Briefing IV in order to complete this quest.",
    ["T"] = "The Orgrimmar Legion Needs Mojo!",
  },
  [8786] = {
    ["D"] =
    "The Orgrimmar Legion has put in a request for additional weapons that we haven\'t been able to provide at the moment.  Obtain the weapons they\'ve requested and bring them to Merok Longstride outside of Hive\'Regal.",
    ["O"] =
    "Bring 3 Massive Iron Axes to Merok Longstride at the Orgrimmar Legion camp outside of Hive\'Regal.  You must also bring Logistics Task Briefing VI in order to complete this quest.",
    ["T"] = "Arms for the Field",
  },
  [8787] = {
    ["D"] =
    "The brave volunteers of the Orgrimmar Legion have arrived to Silithus to aid us in our cause.  Their supplies of armor kits were somehow lost in the trip.  Obtain a batch of armor kits and deliver them to Merok Longstride at the location of the Orgrimmar Legion camp.",
    ["O"] =
    "Bring 8 Rugged Armor Kits and 8 Heavy Armor Kits to Merok Longstride near Hive\'Regal.  You must also bring Logistics Task Briefing VII in order to complete this quest.",
    ["T"] = "Armor Kits for the Field",
  },
  [8788] = {
    ["T"] = "A Gently Shaken Gift",
  },
  [8789] = {
    ["D"] =
    "We have not sat idly by for a millennium, $N.$B$BWe have watched these beasts feast on their own when they have exhausted their utility. We have listened as they have plotted and schemed to destroy our world. And we have learned of their own internal treachery.$B$BWeaknesses exist and we know how to use those weaknesses to our advantage.$B$BFind and bring me their ceremonial armaments: Combined with the element created from the volatility of their own God, they will become a force of reckoning.",
    ["O"] =
    "Arygos in the Temple of Ahn\'Qiraj will create Elementium Infused Armaments for you should you bring him Imperial Qiraji Armaments and 3 Elementium Ore.",
    ["T"] = "Imperial Qiraji Armaments",
  },
  [8790] = {
    ["D"] =
    "Arygos theorizes that the element which is born of conflicts between the Old Gods and their minions is also extremely deadly to them under the right conditions. I speak of Elementium, mortal.$B$BFind and bring me Imperial Qiraji Regalia and the toxic element and I shall infuse weapons of great power.",
    ["O"] =
    "Merithra of the Dream in the Temple of Ahn\'Qiraj will create Elementium Infused Armaments for you should you bring her Imperial Qiraji Regalia and 3 Elementium Ore.",
    ["T"] = "Imperial Qiraji Regalia",
  },
  [8791] = {
    ["D"] =
    "A terrible menace has been laid to rest. The cruel Ossirian has been vanquished.$B$BThe denizens of Kalimdor would be relieved to know of this victory. Take Ossirian\'s head and present it to Commander Mar\'alith of Cenarion Hold.",
    ["O"] = "Deliver the Head of Ossirian the Unscarred to Commander Mar\'alith at Cenarion Hold in Silithus.",
    ["T"] = "The Fall of Ossirian",
  },
  [8792] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Horde needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Warlord Gorchuk. What do you say, <class>? Will you help out with the vital preparations?",
    ["O"] = "Speak with Warlord Gorchuk in Orgrimmar\'s Valley of Spirits.",
    ["T"] = "The Horde Needs Your Help!",
  },
  [8793] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Horde needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Warlord Gorchuk. What do you say, $C? Will you help out with the vital preparations?",
    ["O"] = "Speak with Warlord Gorchuk in Orgrimmar\'s Valley of Spirits.",
    ["T"] = "The Horde Needs Your Help!",
  },
  [8794] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Horde needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Warlord Gorchuk. What do you say, $C? Will you help out with the vital preparations?",
    ["O"] = "Speak with Warlord Gorchuk in Orgrimmar\'s Valley of Spirits.",
    ["T"] = "The Horde Needs Your Help!",
  },
  [8795] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Alliance needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Field Marshal Snowfall. What do you say, <class>? Will you help out with the vital preparations?",
    ["O"] = "Speak with Field Marshal Snowfall in Ironforge\'s Military Ward.",
    ["T"] = "The Alliance Needs Your Help!",
  },
  [8796] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Alliance needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Field Marshal Snowfall. What do you say, $C? Will you help out with the vital preparations?",
    ["O"] = "Speak with Field Marshal Snowfall in Ironforge\'s Military Ward.",
    ["T"] = "The Alliance Needs Your Help!",
  },
  [8797] = {
    ["D"] =
    "Hello, I\'m glad that you\'ve decided to hear me out. The Alliance needs all of the help that it can get to prepare for the Ahn\'Qiraj War, and that means that we need you! Even now as we speak, official collectors are gathering the necessary material needed for the upcoming war, but we won\'t be able to meet our goals without your assistance, $N!$B$BYou should go speak with the guy in charge, Field Marshal Snowfall. What do you say, $C? Will you help out with the vital preparations?",
    ["O"] = "Speak with Field Marshal Snowfall in Ironforge\'s Military Ward.",
    ["T"] = "The Alliance Needs Your Help!",
  },
  [8798] = {
    ["T"] = "A Yeti of Your Own",
  },
  [8799] = {
    ["D"] =
    "Listen... I\'m not really supposed to be telling you this, but since you\'re the hero of the day and all...$B$BThere\'s fresh holly everywhere this time of the year, but it never lasts.  We\'ve got a machine that preserves holly - it never goes bad!  We use it to spice up the holiday... and profits during the summer!$B$BI\'ll let you use the preserver, but only if you\'re a master cook.  You\'ll need some deeprock salt and two, three, oh let\'s say five gold.  It\'ll net you a nice batch that\'s yours to keep.",
    ["O"] =
    "Bring 1 Deeprock Salt and 5 gold coins to the Holly Preserver machine, upon which you will receive 5 Preserved Holly.",
    ["T"] = "The Hero of the Day",
  },
  [8800] = {
    ["D"] =
    "As you complete the tasks you\'re assigned in the war you\'ll want to talk to Vargus, the blacksmith.  Show him any badges you\'ve earned along the way. He\'ll provide you with gear to match your level of commitment to our cause.",
    ["O"] = "Talk to Vargus at Cenarion Hold in Silithus.",
    ["T"] = "Cenarion Battlegear",
  },
  [8801] = {
    ["D"] =
    "The walls of Ahn\'Qiraj tremble. A force of evil, older than the world itself, has been destroyed.$B$BAs you look at the remnants of the colossal abomination your heart nearly freezes. Even in death you can feel the legacy of C\'Thun\'s evil around you.$B$BYou have done what was thought to be impossible.$B$BYou grab at an eye stalk of the fiend, stowing it safely in your pack.$B$BTake the Eye of C\'Thun to the dragons in the next chamber.",
    ["O"] = "Take the Eye of C\'Thun to Caelastrasz in the Temple of Ahn\'Qiraj.",
    ["T"] = "C\'Thun\'s Legacy",
  },
  [8802] = {
    ["D"] =
    "To the Caverns of Time you go,  Lord $N. Anachronos awaits your return. Give him the eye of C\'Thun as he will undoubtedly wish to place it in his master\'s collection.",
    ["O"] = "Take the Eye of C\'Thun to Anachronos at the Caverns of Time.",
    ["T"] = "The Savior of Kalimdor",
  },
  [8803] = {
    ["T"] = "A Festive Gift",
  },
  [8804] = {
    ["D"] =
    "With the arrival of fresh recruits to Cenarion Hold comes the problem of keeping them alive in the desert.  Dehydration as well as numerous poisonous creatures present a serious threat to inexperienced volunteers.  Gather the supplies necessary for a desert survival kit and bring them to Calandrath in Cenarion Hold.",
    ["O"] =
    "Bring 4 Globes of Water, 4 Powerful Anti-Venom and 4 Smoked Desert Dumplings to Calandrath at the inn in Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing I in order to complete this quest.",
    ["T"] = "Desert Survival Kits",
  },
  [8805] = {
    ["D"] =
    "The mounted division of the Cenarion Hold guard is in short supply of ornate mithril boots.  Procure a batch and deliver them immediately to Captain Vish Kozus in Cenarion Hold.",
    ["O"] =
    "Bring 3 Ornate Mithril Boots to Vish Kozus, Captain of the Guard at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing II in order to complete this quest.",
    ["T"] = "Boots for the Guard",
  },
  [8806] = {
    ["D"] =
    "The Cenarion Hold guard is in short supply of grinding stones.  Procure a batch and deliver them immediately to Captain Vish Kozus in Cenarion Hold.",
    ["O"] =
    "Bring 10 Dense Grinding Stones, 10 Solid Grinding Stones and 10 Heavy Grinding Stones to Vish Kozus, Captain of the Guard at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing III in order to complete this quest.",
    ["T"] = "Grinding Stones for the Guard",
  },
  [8807] = {
    ["D"] =
    "Geologist Larksbane\'s studies have proven to be of tremendous value to our operations in Silithus.  She has recently requested scrying materials to be used in her research.$B$BPlease gather these materials and deliver them to her directly so that she may continue her research.",
    ["O"] =
    "Bring 1 Large Brilliant Shard, 1 Large Radiant Shard and 1 Huge Emerald to Geologist Larksbane at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing V in order to complete this quest.",
    ["T"] = "Scrying Materials",
  },
  [8808] = {
    ["D"] =
    "The latest influx of volunteers has caused a shortage of uniforms.  Procure a batch of uniform materials and bring them to Windcaller Proudhorn.",
    ["O"] =
    "Bring 1 Mooncloth, 2 Bolts of Runecloth and 1 Ironweb Spider Silk to Windcaller Proudhorn at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing VIII in order to complete this quest.",
    ["T"] = "Uniform Supplies",
  },
  [8809] = {
    ["D"] =
    "Vargus, Cenarion Hold\'s blacksmith, has requested enchanted materials to be used in the crafting of powerful weapons for our forces.  Obtain these and bring them directly to Vargus so that Cenarion Hold\'s troops may continue to be well equipped.",
    ["O"] =
    "Bring 2 Enchanted Thorium Bars and 2 Enchanted Leather to Vargus at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing IX in order to complete this quest.",
    ["T"] = "Extraordinary Materials",
  },
  [8810] = {
    ["D"] =
    "Our supply of bandages in the battlefield is running dangerously low after the recent casualties we have incurred.  Obtain a batch of first-aid supplies and deliver them to Windcaller Proudhorn in Cenarion Hold.",
    ["O"] =
    "Bring 30 Heavy Runecloth Bandages, 30 Heavy Silk Bandages and 30 Heavy Mageweave Bandages to Windcaller Proudhorn at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing X in order to complete this quest.",
    ["T"] = "Bandages for the Field",
  },
