  [8826] = {
    ["T"] = "Ten Commendation Signets",
  },
  [8827] = {
    ["D"] =
    "I hear Greatfather Winter - with the generous support of Smokeywood Pastures - has put presents for everyone under the tree in Ironforge. I wish I could go, but I\'ve got to look after the PX-238 Winter Wondervolt.$B$BBut you should definitely check it out. I\'m sure Greatfather Winter has some presents with your name on them.",
    ["O"] = "Speak with Greatfather Winter. He is located near the Smokywood Pastures vendor area in Ironforge.",
    ["T"] = "Winter\'s Presents",
  },
  [8828] = {
    ["D"] =
    "I hear Great-father Winter - with the generous support of Smokeywood Pastures - has put presents for everyone under the tree in Orgrimmar. I wish I could go, but I\'ve got to look after the PX-238 Winter Wondervolt.$B$BBut you should definitely check it out. I\'m sure Great-father Winter has some presents with your name on them.",
    ["O"] = "Speak with Great-father Winter. He is located near the Smokywood Pastures vendor area in Orgrimmar.",
    ["T"] = "Winter\'s Presents",
  },
  [8829] = {
    ["D"] =
    "The Twilight\'s Hammer operates through innumerable layers of secrecy and deceit.  While their actions are carried out in our world, they are planned in a place we have not yet been able to reach.$B$BWe\'ve come to believe that the stones the Twilight\'s Hammer uses to summon their superiors allow for two-way transportation.  To attempt to use them in this manner, we must replicate - to every last detail - a twilight emissary\'s robe.$B$BGather the necessary materials and bring them to Aurel Goldleaf, $N.",
    ["O"] =
    "Bring a Skin of Shadow, 3 Frayed Abomination Stitchings and 1 Twilight Cultist Robe to Aurel Goldleaf at Cenarion Hold in Silithus.  You must also bring Logistics Task Briefing XI in order to complete this quest.",
    ["T"] = "The Ultimate Deception",
  },
  [8830] = {
    ["T"] = "One Commendation Signet",
  },
  [8831] = {
