  [8848] = {
    ["T"] = "Fifteen Signets for War Supplies",
  },
  [8853] = {
    ["T"] = "Fifteen Signets for War Supplies",
  },
  [8857] = {
    ["D"] =
    "I\'m looking for battle hardened adventurers willing and able to get a fresh husk sample from the fallen Colossus of Ashi to Oglethorpe in Booty Bay. No, no, I wouldn\'t want you to go anywhere near that thing\'s corpse. Just take one of my samples and make it snappy. These things are no good to him rotten!",
    ["O"] = "Take the Colossus of Ashi\'s Husk to Oglethorpe Obnoticus in Booty Bay.",
    ["T"] = "Secrets of the Colossus - Ashi",
  },
  [8858] = {
    ["D"] =
    "There ain\'t nothin\' I\'d like more than to stuff this bug husk down Oilfist\'s fat face... Cept, I\'m stuck here collectin\' samples from that overgrown cockroach. I\'ll be here \'till the wee mornin\' hours given the size o\' that thing.$B$BTake this here sample to Oilfist fer me and do it fast, $C. He\'s payin\' BIG!$B$BYar, Thorium Point - it be in the Searin\' Gorge.",
    ["O"] = "Take the Colossus of Regal\'s Husk to Overseer Oilfist in Searing Gorge.",
    ["T"] = "Secrets of the Colossus - Regal",
  },
  [8859] = {
    ["D"] =
    "My servants were nearly killed in their efforts to recover this sample. You absolutely must hurry! Lord Maxwell Tyrosus eagerly awaits a fresh husk sample. He believes that the secrets of this Colossus could help us in the war against the Scourge!$B$BWhy are you still here!? To Light\'s Hope! Yes, you will be rewarded handsomely for your efforts...",
    ["O"] =
    "Take the Colossus of Zora\'s Husk to Lord Maxwell Tyrosus at Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "Secrets of the Colossus - Zora",
  },
  [8860] = {
    ["D"] =
    "Stormwind is holding a celebration for the new year!  All day long today you can get free booze, and at night they\'ll put on a firework show!  It should be pretty nice... but Booty Bay is also having a party today; I bet it\'ll be even better!$B$BWell anyway, Innkeeper Allison in Stormwind needs a supply of Smoky Wood Pasture fare to help feed all the party goers.  Can you do me a favor and deliver it!$B$BThanks, $N!  Innkeeper Allison is in the Gilded Rose, in the Trade District of Stormwind.",
    ["O"] = "Bring the Smokywood Supplies to Innkeeper Allison in Stormwind.",
    ["T"] = "New Year Celebrations!",
  },
  [8861] = {
    ["D"] =
    "Thunder Bluff is holding a celebration for the new year!  All day you\'ll find free booze there, and at night they\'ll put on a firework show!$B$BIt should be pretty nice... but Booty Bay is also having a party today; I bet it\'ll be even better!$B$BWell anyway, Innkeeper Pala in Thunder Bluff needs a supply of Smoky Wood Pasture fare to help feed all the party goers.  Can you do me a favor and deliver it!$B$BThanks, $N!  Innkeeper Pala is in the inn near the bridge to Hunter\'s Rise.",
    ["O"] = "Bring the Smokywood Supplies to Innkeeper Pala in Thunder Bluff.",
    ["T"] = "New Year Celebrations!",
  },
  [8862] = {
    ["T"] = "Elune\'s Candle",
  },
  [8863] = {
    ["T"] = "Festival Dumplings",
  },
  [8864] = {
    ["T"] = "Festive Lunar Dresses",
  },
  [8865] = {
    ["T"] = "Festive Lunar Pant Suits",
  },
  [8866] = {
    ["T"] = "Bronzebeard the Elder",
  },
  [8867] = {
    ["D"] =
    "Every year the druids of Moonglade hold a celebration of our city\'s great triumph over an ancient evil.$B$BWe celebrate the wisdom of our elders, share in magnificent feasts and of course... shoot fireworks!$B$BFor a small donation you can purchase colorful rockets from our vendor.  Try using some of the launchers around here, $N.",
    ["O"] =
    "Launch 8 Lunar Fireworks and 2 Cluster Fireworks and return to a Lunar Festival Harbinger at any capital city.",
    ["T"] = "Lunar Fireworks",
  },
  [8868] = {
    ["D"] =
    "The beast Omen was once a hero of this world.  A wolf of great strength and fortune, Omen fought beside the heroes of the War of the Ancients until he succumbed to demonic magics.  Turning against his allies, he raged across Azeroth and carried death and terror in his wake.$B$BFinally defeated here, in Moonglade, Omen now sleeps among the silt of Lake Elune\'ara.  But each new year, during the festival, he stirs...$B$BGather cohorts, $N, and summon and defeat the beast Omen.  Earn the blessing of Elune!",
    ["O"] = "Summon Omen, defeat him and gain Elune\'s Blessing.  Return to Valadar Starsong in Nighthaven",
    ["T"] = "Elune\'s Blessing",
  },
  [8870] = {
    ["D"] =
    "It\'s that time of the year, $N!  The Cenarion Circle invites all denizens of Azeroth to partake in our celebration of the Lunar Festival.  You will find the Lunar Festival Harbinger in this very city at a location marked by a blessed circle of moonlight.  She can tell you more about the holiday.",
    ["O"] =
    "Talk to the Lunar Festival Harbinger in the Mystic Ward of Ironforge.  You can also talk to Lunar Festival Harbingers in other capital cities.",
    ["T"] = "The Lunar Festival",
  },
  [8871] = {
    ["D"] =
    "It\'s that time of the year, $N!  The Cenarion Circle invites all denizens of Azeroth to partake in our celebration of the Lunar Festival.  You will find the Lunar Festival Harbinger in this very city at a location marked by a blessed circle of moonlight.  She can tell you more about the holiday.",
    ["O"] =
    "Talk to the Lunar Festival Harbinger in the Park District in Stormwind.  You can also talk to Lunar Festival Harbingers in other capital cities.",
    ["T"] = "The Lunar Festival",
  },
  [8872] = {
