  [8957] = {
    ["D"] =
    "Valthalak\'s soul was stored in this amulet.  In our greed we foolishly split it into three parts, not knowing the curse that would await us.$B$BThe only way to stop Valthalak\'s spell is to put the amulet back together.  Return to Mokvar and tell him that Bodley is his only hope for finding the remaining pieces.  Speak to him about any rewards you\'ve arranged for.$B$BI, for once, shall rest in peace.  I wish you the best of luck; you shall need every bit of it!",
    ["O"] = "Return to Mokvar in Orgimmar with a set of Boots of Elements, Kilt of Elements and Pauldrons of Elements.",
    ["T"] = "Anthion\'s Parting Words",
  },
  [8958] = {
    ["D"] =
    "Valthalak\'s soul was stored in this amulet.  In our greed we foolishly split it into three parts, not knowing the curse that would await us.$B$BThe only way to stop Valthalak\'s spell is to put the medallion back together.  Return to Deliana and tell her that Bodley is her only hope for finding the remaining pieces.  Speak to her about any rewards you\'ve arranged for.$B$BI, for once, shall rest in peace.  I wish you the best of luck; you shall need every bit of it!",
    ["O"] = "Return to Deliana in Ironforge with a set of Dreadmist Sandals, Dreadmist Leggings and Dreadmist Mantle.",
    ["T"] = "Anthion\'s Parting Words",
  },
  [8959] = {
    ["D"] =
    "Valthalak\'s soul was stored in this amulet.  In our greed we foolishly split it into three parts, not knowing the curse that would await us.$B$BThe only way to stop Valthalak\'s spell is to put the medallion back together.  Return to Deliana and tell her that Bodley is her only hope for finding the remaining pieces.  Speak to her about any rewards you\'ve arranged for.$B$BI, for once, shall rest in peace.  I wish you the best of luck; you shall need every bit of it!",
    ["O"] = "Return to Deliana in Ironforge with a set of Boots of Valor, Legplates of Valor and Spaulders of Valor.",
    ["T"] = "Anthion\'s Parting Words",
  },
  [8960] = {
    ["D"] =
    "So we need to recover the rest of the medallion?  Finding Bodley\'s going to be a bit of a headache.  He went back to Blackrock Mountain to attempt to re-enter Blackrock Spire and never came back.$B$BI\'d suggest taking the goblin\'s ghost revealing device with you, as I fear the worst might have happened.",
    ["O"] =
    "Travel to Blackrock Mountain and use the Extra-Dimensional Ghost Revealer to find Bodley near Blackrock Spire.",
    ["T"] = "Bodley\'s Unfortunate Fate",
  },
  [8961] = {
    ["D"] =
    "In order to summon Lord Valthalak we\'re first going to need to gather the other two-thirds of the amulet. To do that we need to get a brazier and some special coals to burn in it.$B$BThere are three nobles of fire, Lord Incedius in Blackrock Depths, Pyroguard Emberseer in Blackrock Spire and The Duke of Cynders in Silithus, with what we need. Collect from each a piece of their remains, and then return to me with a Hallowed Brazier, which can be purchased from the Argent Dawn if you are honored by them.",
    ["O"] =
    "Gather the Incendicite of Incendius, the Ember of Emberseer and the Cinder of Cynders, along with a Hallowed Brazier, and return them to Bodley inside Blackrock Mountain.",
    ["T"] = "Three Kings of Flame",
  },
  [8962] = {
    ["D"] =
    "$C, listen closely. Now that we have the brazier, and the means to light it, we still need another component to suffuse it with; something that will provide a focus strong enough to entice the spirit of my deceased, former comrade.$B$BMor Grayhoof, our most prominent druid, had many close friends amongst the Cenarion Circle, some of which have fallen to the silithid. I need you to retrieve some Druidical Remains from the silithid that inhabit the environs of Hive\'Regal in southeastern Silithus.",
    ["O"] = "Acquire Druidical Remains and return them to Bodley inside Blackrock Mountain.",
    ["T"] = "Components of Importance",
  },
  [8963] = {
    ["D"] =
    "$C, listen closely. Now that we have the brazier, and the means to light it, we still need another component to suffuse it with; something that will provide a focus strong enough to entice the spirit of my deceased, former comrade.$B$BIsalien, our priestess, grew up in Winterspring at Starbreeze Village. I need you to gather a Starbreeze Village Relic from the Frostmaul giants of Frostwhisper Gorge in southern Winterspring, who are known for raiding to the north from time to time.",
    ["O"] = "Acquire a Starbreeze Village Relic and return it to Bodley inside Blackrock Mountain.",
    ["T"] = "Components of Importance",
  },
  [8964] = {
    ["D"] =
    "$C, listen closely. Now that we have the brazier, and the means to light it, we still need another component to suffuse it with; something that will provide a focus strong enough to summon the remains of my deceased, former comrades.$B$BThe siblings, Jarien and Sothos, were believers in the way of the Scarlet Crusade. They aspired to knighthood within that vile organization. Go to Tyr\'s Hand in Eastern Plaguelands and retrieve a Brilliant Sword of Zealotry from the praetorians there.",
    ["O"] = "Retrieve a Brilliant Sword of Zealotry and return it to Bodley inside Blackrock Mountain.",
    ["T"] = "Components of Importance",
  },
  [8965] = {
    ["D"] =
    "$C, listen closely. Now that we have the brazier, and the means to light it, we still need another component to suffuse it with; something that will provide a focus strong enough to entice the spirit of my deceased, former comrade.$B$BAn ogre necromancer that traveled with us, Kormok, delighted in summoning forth the souls of the banished dead of Purgation Isle, off the south coast of the Hillsbrad Foothills. Go there and retrieve some Soul Ashes of the Banished from their remains.",
    ["O"] = "Obtain Soul Ashes of the Banished and return them to Bodley inside Blackrock Mountain.",
    ["T"] = "Components of Importance",
  },
  [8966] = {
    ["D"] =
    "My friend, Mor Grayhoof, was the first to fall victim to possession of a piece of Lord Valthalak\'s amulet, and the corrupting spirit fragment that it contains. After stealing Valthalak\'s spellbook and amulet, we fled for our lives from the upper portion of Blackrock Spire. Along the way, Mor fell into the lower portion of the spire.$B$BLater, we discovered that he survived the fall, only to be captured and tortured by War Master Voone. A few spectral assassins snuck in and slew him right in front of Voone.",
    ["O"] =
    "Use the Brazier of Beckoning to summon forth the spirit of Mor Grayhoof and slay him. Return to Bodley inside Blackrock Mountain with the Left Piece of Lord Valthalak\'s Amulet and the Brazier of Beckoning.",
    ["T"] = "The Left Piece of Lord Valthalak\'s Amulet",
  },
  [8967] = {
    ["D"] =
    "It became known to us in later days, as we were doing what we could ourselves to survive, that Isalien, a night elf priestess of our company, had gone to the night elvic ancestral city, now known as Dire Maul. From what we gathered, she went there both for personal reasons and also to unlock the secrets of the piece of the amulet that she had in her possession.$B$BShe didn\'t quite make it, though. Word got back to us that she was ambushed at the Shrine of Eldretharr by Alzzin the Wildshaper and his forces.",
    ["O"] =
    "Use the Brazier of Beckoning to summon forth the spirit of Isalien and slay her. Return to Bodley inside Blackrock Mountain with the Left Piece of Lord Valthalak\'s Amulet and the Brazier of Beckoning.",
    ["T"] = "The Left Piece of Lord Valthalak\'s Amulet",
  },
  [8969] = {
    ["D"] =
    "Now we have what we need, so it\'s time to discuss who it is that you\'ll be summoning.$B$BKormok was ok for an ogre, right up until he turned to necromancy. After that, things got creepy for just about everyone in the outfit. It was no surprise then when he took his piece of the amulet and returned to his new home, Scholomance.$B$BBut even there, or perhaps especially there, he was not safe from the spectral assassins. They slew him right in front of his master, Ras Frostwhisper.",
    ["O"] =
    "Use the Brazier of Beckoning to summon forth the spirit of Kormok and slay him. Return to Bodley inside Blackrock Mountain with the Left Piece of Lord Valthalak\'s Amulet and the Brazier of Beckoning.",
    ["T"] = "The Left Piece of Lord Valthalak\'s Amulet",
  },
  [8970] = {
    ["D"] =
    "As I was saying, $C, in my living years I flirted with becoming a diviner. But, there really wasn\'t as much profit in it as you might imagine, mostly because it\'s dangerous and the reagents are rare and expensive. However, I do know enough to be able to pinpoint the final piece of the amulet, and the spirit of my former comrade along with it.$B$BThis is where you come in, $N. I need you to go to Alcaz Island off the coast of Dustwallow Marsh and collect Bloodkelp from the Strashaz naga that live there.",
    ["O"] = "Gather 20 Bloodkelp from the Strashaz naga and then return to Bodley inside Blackrock Mountain.",
    ["T"] = "I See Alcaz Island In Your Future...",
  },
  [8977] = {
    ["D"] =
    "It\'s been great working with you, $N.  Here is the finished product.$B$BI hope it helps you in your current endeavors.  And hey, if you don\'t mind, help spread the word.  I wouldn\'t mind having more customers!",
    ["O"] = "Bring the Extra-Dimensional Ghost Revealer  to Deliana in Ironforge.",
    ["T"] = "Return to Deliana",
  },
  [8978] = {
    ["D"] =
    "It\'s been great working with you, $N.  Here is the finished product.$B$BI hope it helps you in your current endeavors.  And hey, if you don\'t mind, help spread the word.  I wouldn\'t mind having more customers!",
    ["O"] = "Return to Mokvar in Orgrimmar with the Extra-Dimensional Ghost Revealer.",
    ["T"] = "Return to Mokvar",
  },
  [8979] = {
    ["D"] =
    "I believe I know the cause of this recent behavior. Have you smelled the new fragrance on the wind, over the stink of the canals? The new colognes and perfumes that have come into fashion?$B$BOur thinking has been clouded by some foul alchemy.$B$BThere is only one way to be sure - bring a bottle of cologne and perfume to my friend, Apothecary Zinge. The Royal Apothecary Society will find the truth.$B$BI will reimburse you for their purchase when you return.",
    ["O"] = "Bring 1 Cologne Bottle and 1 Perfume Bottle to Apothecary Zinge in the Undercity\'s Apothecarium.",
    ["T"] = "Fenstad\'s Hunch",
  },
  [8980] = {
    ["D"] =
    "This is unexpected. It looks like Fenstad might be on to something after all. I found traces of substances used in mind control potions.$B$BIt isn\'t unheard of for perfumes to have some of this, but a few of the ingredients I detected... This is serious alchemy, along the abilities of a member of the Royal Apothecary Society.",
    ["O"] = "Return to Fenstad Argyle outside the bank in the Undercity.",
    ["T"] = "Zinge\'s Assessment",
  },
  [8981] = {
    ["T"] = "Gift Giving",
  },
  [8982] = {
    ["D"] =
    "We must find who the supplier is. I noticed Apothecary Katrina with a bottle of the perfume tucked in her pack. She told me that she purchased it from Norman, the innkeeper.",
    ["O"] = "Speak with Innkeeper Norman in the Undercity.",
    ["T"] = "Tracing the Source",
  },
  [8983] = {
    ["D"] =
    "Something\'s wrong with my product? Well, I\'ve never seen so many people wanting something so badly.$B$BI bought my supply from a merchant named Mara Rennick. She\'s new in town.$B$BShe mentioned she had some goods she had to deliver to the tailor in the Mage Quarter.",
    ["O"] = "Speak with Mara Rennick at the tailor\'s shop in the Undercity\'s Mage Quarter.",
    ["T"] = "Tracing the Source",
  },
  [8984] = {
    ["D"] =
    "Look, the actions of a rogue apothecary are not my concern. If he\'s undermining our efforts, then let me be the first to point you in the right direction$B$BIf he\'s innocent, then he\'s got nothing to hide, right?$B$BI purchased the goods from Apothecary Staffron Lerent. He\'s working in a secluded area past Ravenholdt Manor in the hills over Hillsbrad. To be honest with you, I thought he was a little odd.",
    ["O"] = "Find Apothecary Staffron Lerent in the Hillsbrad Foothills past Ravenholdt Manor.",
    ["T"] = "The Source Revealed",
  },
  [8985] = {
    ["D"] =
    "$C, listen closely. Now that we have the location of the last amulet piece, we still need another component to suffuse the brazier with; something that will provide a focus strong enough to entice the spirit of my deceased, former comrade.$B$BIsalien, our priestess, grew up in Winterspring at Starbreeze Village. I need you to gather a Starbreeze Village Relic from the Frostmaul giants of Frostwhisper Gorge in southern Winterspring, who are known for raiding to the north from time to time.",
    ["O"] = "Acquire a Starbreeze Village Relic and return it to Bodley inside Blackrock Mountain.",
    ["T"] = "More Components of Importance",
  },
  [8986] = {
    ["D"] =
    "$C, listen closely. Now that we have the location of the last amulet piece, we still need another component to suffuse the brazier with; something that will provide a focus strong enough to entice the spirit of my deceased, former comrade.$B$BMor Grayhoof, our most prominent druid, had many close friends amongst the Cenarion Circle, some of which have fallen to the silithid. I need you to retrieve some Druidical Remains from the silithid that inhabit the environs of Hive\'Regal in southeastern Silithus.",
    ["O"] = "Acquire Druidical Remains and return them to Bodley inside Blackrock Mountain.",
    ["T"] = "More Components of Importance",
  },
  [8987] = {
    ["D"] =
    "$C, listen closely. Now that we have the location of the last amulet piece, we still need another component to suffuse the brazier with; something that will provide a focus strong enough to summon the remains of my deceased, former comrades.$B$BThe siblings, Jarien and Sothos, were believers in the way of the Scarlet Crusade. They aspired to knighthood within that vile organization. Go to Tyr\'s Hand in Eastern Plaguelands and retrieve a Brilliant Sword of Zealotry from the praetorians there.",
    ["O"] = "Retrieve a Brilliant Sword of Zealotry and return it to Bodley inside Blackrock Mountain.",
