  [9085] = {
    ["D"] =
    "After you bring down the defenses of the Scourge summoning circles that have appeared in the zones under attack, you will be able to confront the acolytes who protect them.$B$BIn truth, these are not men. They are shadows, some of the Lich King\'s most frightening creatures. They can be revealed using the necrotic runes they carry, and then destroyed with magic or strength of arms.",
    ["O"] =
    "Go to a summoning circle and kill a Shadow of Doom, then return to Commander Thomas Helleran at Light\'s Hope Chapel in Eastern Plaguelands.",
    ["T"] = "Shadows of Doom",
  },
  [9086] = {
    ["D"] =
    "Many heroes fell in the last war and many continue to perish at the hands of the Scourge to this day. From the corpses of the fallen, the armor is stripped and taken back to Naxxramas to be used for unknown purposes.$B$BRecover the desecrated armor and wartorn armor scraps and supply to me the other material components I require and I will craft Dreamwalker armor.",
    ["O"] =
    "Rayne at Light\'s Hope Chapel in the Eastern Plaguelands will make a Dreamwalker Tunic if you bring her the following: 1 Desecrated Tunic, 25 Wartorn Leather Scraps, 6 Cured Rugged Hides and 2 Nexus Crystals.",
    ["T"] = "Dreamwalker Tunic",
  },
  [9087] = {
    ["D"] =
