  [9110] = {
    ["D"] =
    "I make no pretenses, maggot. The darkness Plagueheart items hold could very well destroy the both of us. That is why the price is so high. If I\'m going to die, it\'s going to be as a rich man.$B$BAnd I don\'t give an ounce of gnoll spit how you die, only that you do as I ask. Bring me what I require and we will both benefit - or die; but I\'ve already explained this...",
    ["O"] =
    "Mataus the Wrathcaster at Light\'s Hope Chapel in the Eastern Plaguelands will make Plagueheart Bindings if you bring him the following: 1 Desecrated Bindings, 6 Wartorn Cloth Scraps, 1 Arcane Crystal and 1 Nexus Crystal.",
    ["T"] = "Plagueheart Bindings",
  },
  [9118] = {
    ["D"] =
    "$B$BBlessed  boy, have you found the vestments of the fallen? The poor souls whose last breaths were taken on the field of battle - stripped of everything including their dignity.$B$BBring me the desecrated remnants of the departed along with reagents of purification and you shall know faith.",
    ["O"] =
    "Father Inigo Montoy at Light\'s Hope Chapel in the Eastern Plaguelands will make Bindings of Faith if you bring him the following: 1 Desecrated Bindings, 6 Wartorn Cloth Scraps, 1 Arcane Crystal and 1 Nexus Crystal.",
    ["T"] = "Bindings of Faith",
  },
  [9120] = {
    ["D"] =
    "The phylactery is all that remains of the master of Naxxramas. Your better judgment dictates that you destroy the phylactery, preventing the lich from ever reforming. Thankfully, you seldom listen to that internal voice of reason.$B$BSomeone at Light\'s Hope will pay you hugely for this artifact. Who cares if Kel\'Thuzad regenerates to full power?",
    ["O"] = "Take the Phylactery of Kel\'Thuzad to Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "The Fall of Kel\'Thuzad",
  },
  [9121] = {
    ["D"] =
    "In the thick of Plaguewood lies the entrance to the dread citadel of Naxxramas. Previously, all attempts to enter had been stymied by the magical wards placed upon the rune portal. That is, until now.$B$BWe have devised a way to gain entry via arcane cloaking - an old cantrip of the Kirin Tor with a few modifications of my own. Since your dedication to the cause of the Dawn is somewhat lacking, $N, the price will be high. You may decline and choose to return when you are revered or exalted for a discount.",
    ["O"] =
    "Archmage Angela Dosantos at Light\'s Hope Chapel in the Eastern Plaguelands wants 5 Arcane Crystals, 2 Nexus Crystals, 1 Righteous Orb and 60 gold pieces. You must also be Honored with the Argent Dawn.",
    ["T"] = "The Dread Citadel - Naxxramas",
  },
  [9122] = {
    ["D"] =
    "In the thick of Plaguewood lies the entrance to the dread citadel of Naxxramas. Previously, all attempts to enter had been stymied by the magical wards placed upon the rune portal. That is, until now.$B$BWe have devised a way to gain entry via a permanent arcane cloaking of sorts - an old cantrip of the Kirin Tor with a few modifications of my own. With that said, the cloaking is costly. Since your dedication to the cause of the Dawn is admirable, we are willing to incur some of those costs.",
    ["O"] =
    "Archmage Angela Dosantos at Light\'s Hope Chapel in the Eastern Plaguelands wants 2 Arcane Crystals, 1 Nexus Crystal and 30 gold pieces. You must also be Revered with the Argent Dawn.",
    ["T"] = "The Dread Citadel - Naxxramas",
  },
  [9123] = {
    ["D"] =
    "In the thick of Plaguewood lies the entrance to the dread citadel of Naxxramas. Previously, all attempts to enter had been stymied by the magical wards placed upon the rune portal. That is, until now.$B$BWe have devised a way to gain entry via a permanent arcane cloaking of sorts - an old cantrip of the Kirin Tor with a few modifications of my own. With that said, the cloaking is costly; however, your dedication to the cause of the Dawn is unwavering! We will waive all cost associations.",
    ["O"] =
    "Archmage Angela Dosantos at Light\'s Hope Chapel in the Eastern Plaguelands will grant you Arcane Cloaking at no cost. You must be Exalted with the Argent Dawn.",
    ["T"] = "The Dread Citadel - Naxxramas",
  },
  [9124] = {
    ["D"] =
    "How would you like to earn yourself one of these shiny coins?$B$B$B$BI\'ve got a little problem that you might be able to help me with, $N. You see, I make Cryptstalker armor for those daft enough to venture into Naxxramas. While they supply me with the core material requirements for the armor, I always run out of the crypt fiend parts. Bring me back a bundle of parts and I\'ll pay you with an insignia - usable at the quartermaster.",
    ["O"] = "Huntsman Leopold at Light\'s Hope Chapel in the Eastern Plaguelands wants 30 Crypt Fiend Parts.",
    ["T"] = "Cryptstalker Armor Doesn\'t Make Itself...",
  },
  [9125] = {
    ["T"] = "Crypt Fiend Parts",
  },
  [9126] = {
    ["D"] =
    "Don Julio\'s Bonescythe armor pattern requires bone fragments - a lot of bone fragments. While those crazy enough to venture into Naxxramas provide me with enough of the core materials to make the armor, I\'m always looking for more Scourge bone fragments.$B$BSo what do you think? Interested in getting your hands dirty and destroying some Scourge at the same time? It\'s a win-win situation.",
    ["O"] = "Rohan the Assassin at Light\'s Hope Chapel in the Eastern Plaguelands wants 30 Bone Fragments.",
    ["T"] = "Bonescythe Digs",
  },
  [9127] = {
    ["T"] = "Bone Fragments",
  },
  [9128] = {
    ["D"] =
    "Greetings, adventurer! Are you interested in some work? I pay those under my employ with insignias. These insignias can be used at the Quartermaster to purchase items of power.$B$BAll I need you to do is bring me as many core of elements as you can carry. The more the better!$B$BYou\'ll find them on elementals of varying shapes and sizes that exist across our world.",
    ["O"] = "Archmage Angela Dosantos at Light\'s Hope Chapel in the Eastern Plaguelands wants 30 Core of Elements.",
    ["T"] = "The Elemental Equation",
  },
  [9129] = {
    ["T"] = "Core of Elements",
  },
  [9131] = {
    ["D"] =
    "Have you ever seen Dreadnaught armor, $C? No, of course you haven\'t. You\'re still a  boy - a tyke. Let me tell you, it is glorious.$B$BYou\'re probably asking yourself what any of this has to do with you, right? I\'ll tell you what, scrub; I need Dark Iron scraps and I\'m willing to pay to get my hands on as many as possible.$B$BI need the scraps to put together sets of Dreadnaught for our champions. Bring me scraps and get paid.",
    ["O"] = "Korfax at Light\'s Hope Chapel in the Eastern Plaguelands wants 30 Dark Iron Scraps.",
    ["T"] = "Binding the Dreadnaught",
  },
  [9132] = {
    ["T"] = "Dark Iron Scraps",
  },
  [9136] = {
    ["D"] =
    "I make a special type of armor for the brave heroes that enter Naxxramas known as Dreamwalker. They are able to provide me with most of the materials I require but I am always looking for those able to retrieve savage fronds from the flora of our world.$B$BYou may think of this job as beneath you, but without the fronds, the armor could not be made.$B$BI am also in a unique position to pay you with an insignia of your choice as both the Dawn and the Crusade supply me with funds.",
    ["O"] = "Rayne at Light\'s Hope Chapel in the Eastern Plaguelands wants 30 Savage Fronds.",
    ["T"] = "Savage Flora",
  },
  [9137] = {
    ["T"] = "Savage Fronds",
  },
  [9141] = {
    ["D"] =
    "You want a writ? What? Do you expect me to hand you a highly sought after work order just for showing up? I think not, scrub. Crafters from around the world bid for jobs here at the front lines.$B$BIf you want a work order, you\'ll have to show me that you\'re willing to bleed for the cause. Bring me a valor token and we\'ll talk.$B$BAnd there\'s only one way to get your grubby little scrub mitts on those - get to killin\'.",
    ["O"] =
    "Dispatch Commander Metz at Light\'s Hope Chapel in the Eastern Plaguelands wants an Argent Dawn Valor Token.",
    ["T"] = "They Call Me \"The Rooster\"",
  },
  [9153] = {
    ["D"] =
    "The floating necropolises of the Scourge plague the lands of Horde and Alliance alike. Tanaris, the Blasted Lands, Winterspring and the Burning Steppes are blanketed in the shadows of the flying fortresses.$B$BOnly through our combined efforts will they be turned away.$B$BThe necropolises are supported by magical circles at various points in the invaded areas. We have determined that destroying the mindless hordes that surround these circles will destroy their defenses.",
    ["O"] =
    "Check your map to find an area under Scourge attack. Go there and damage a necropolis by defeating the Scourge around them. Return 10 of their Necrotic Runes to Commander Thomas Helleran at Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "Under the Shadow",
  },
  [9165] = {
    ["D"] =
    "Without the help of adventurers, my caravan would have never made it! Scourge were coming out of the woodwork to try and stop us from getting here.$B$B$B$BNow we need to wait here for Field Marshal Chambers to arrive. He\'ll sign your writ of safe passage to take back to Dispatch Commander Metz at Light\'s Hope Chapel.$B$BAnd $N, watch what you say around Chambers. He\'s the \'bite off your head and spit down your wind pipe\' type of guy - except that he\'ll actually do it...",
    ["O"] =
    "Deliver the signed Writ of Safe Passage to Dispatch Commander Metz at Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "Writ of Safe Passage",
  },
  [9178] = {
    ["D"] =
    "The bearer of this writ is entitled to payment in the form of an insignia of their choice upon completion of the contracted work order.$B$BWork Order BS-091:$B$B120 Dense Weightstones.$B$BAll filled orders should be delivered to Packmaster Stonebruiser at Light\'s Hope Chapel in the Eastern Plaguelands.$B$BContract is null and void if tampered with or damaged.$B$B-Dispatch Commander Metz, The Argent Dawn",
    ["O"] =
    "Deliver 120 Dense Weightstones and the Craftsman\'s Writ - Dense Weightstone - to Packmaster Stonebruiser at Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "Craftsman\'s Writ - Dense Weightstone",
  },
  [9179] = {
    ["D"] =
    "The bearer of this writ is entitled to payment in the form of an insignia of their choice upon completion of the contracted work order.$B$BWork Order BS-428:$B$B3 Imperial Plate Chests.$B$BAll filled orders should be delivered to Packmaster Stonebruiser at Light\'s Hope Chapel in the Eastern Plaguelands.$B$BContract is null and void if tampered with or damaged.$B$B-Dispatch Commander Metz, The Argent Dawn",
    ["O"] =
    "Deliver 3 Imperial Plate Chests and the Craftsman\'s Writ - Imperial Plate Chest - to Packmaster Stonebruiser at Light\'s Hope Chapel in the Eastern Plaguelands.",
    ["T"] = "Craftsman\'s Writ - Imperial Plate Chest",
  },
  [9181] = {
    ["D"] =
