  [9208] = {
    ["D"] =
    "Zanza can create many ancient troll enchantments with proper components! Have you heard of the Savage Guard? No, of course you haven\'t. Your mind is addled with the inferior elven magic.$B$BBring me an arcanum of elven creation so that I may destroy the aberration. Do this and the Savage Guard will be yours.",
    ["O"] = "Zanza the Restless in Zul\'Gurub wants an Arcanum of Protection.",
    ["T"] = "The Savage Guard - Arcanum of Protection",
  },
  [9209] = {
    ["D"] =
    "Zanza can create many ancient troll enchantments with proper components! Have you heard of the Savage Guard? No, of course you haven\'t. Your mind is addled with the inferior elven magic.$B$BBring me an arcanum of elven creation so that I may destroy the aberration. Do this and the Savage Guard will be yours.",
    ["O"] = "Zanza the Restless in Zul\'Gurub wants an Arcanum of Rapidity.",
    ["T"] = "The Savage Guard - Arcanum of Rapidity",
  },
  [9210] = {
    ["D"] =
    "Zanza can create many ancient troll enchantments with proper components! Have you heard of the Savage Guard? No, of course you haven\'t. Your mind is addled with the inferior elven magic.$B$BBring me an arcanum of elven creation so that I may destroy the aberration. Do this and the Savage Guard will be yours.",
    ["O"] = "Zanza the Restless in Zul\'Gurub wants an Arcanum of Focus.",
    ["T"] = "The Savage Guard - Arcanum of Focus",
  },
  [9211] = {
    ["D"] =
    "Ah, the Ice Guard. It is a thin sheen of protective magic that covers certain pieces of equipment. Those that do battle with creatures of frost and ice will gain increased protection from their attacks by using the Ice Guard.$B$BAs with all things the Wrathcaster creates, there is a price - a price that I will not lower, regardless of how much you whimper. Interested?",
    ["O"] =
    "Mataus the Wrathcaster at Light\'s Hope Chapel in the Eastern Plaguelands wants 10 Insignia of the Crusade and 30 gold.",
    ["T"] = "The Ice Guard",
  },
  [9213] = {
    ["D"] =
    "A creation of genius! Much like the Ice Guard, the Shadow Guard employs a thin sheen of protective magic that covers certain pieces of equipment. And like the Ice Guard, the Shadow Guard is going to cost you a good amount of money.$B$B$B$BInterested?",
    ["O"] =
    "Mataus the Wrathcaster at Light\'s Hope Chapel in the Eastern Plaguelands wants 10 Insignia of the Crusade and 30 gold.",
    ["T"] = "The Shadow Guard",
  },
  [9221] = {
    ["D"] =
    "Greetings, friend. Have you insignias of the Dawn or the Crusade that you would like to redeem for items of power?$B$BI must warn you; purchases made at a friendly reputation with the Dawn come with a hefty surcharge. I would advise that you gain a better reputation with the Dawn before moving forward with your plans.",
    ["O"] =
    "For 30 Insignias of the Dawn and 30 Insignias of the Crusade you may choose an item from the Argent Dawn\'s treasure cache.",
    ["T"] = "Superior Armaments of Battle - Friend of the Dawn",
  },
  [9222] = {
    ["D"] =
    "Greetings, friend. Have you insignias of the Dawn or the Crusade that you would like to redeem for items of great power?$B$BI must warn you; purchases made at a friendly reputation with the Dawn come with an extremely hefty surcharge. I would advise that you gain a better reputation with the Dawn before moving forward with your plans.",
    ["O"] =
    "For 110 Insignias of the Dawn and 110 Insignias of the Crusade you may choose an item from the Argent Dawn\'s treasure cache.",
    ["T"] = "Epic Armaments of Battle - Friend of the Dawn",
  },
  [9223] = {
    ["D"] =
    "Greetings, friend. Have you insignias of the Dawn or the Crusade that you would like to redeem for items of power?$B$BI must warn you; purchases made at honored reputation with the Dawn come with a fairly prohibitive surcharge. I would advise that you gain a better reputation with the Dawn before moving forward with your plans.",
    ["O"] =
    "For 20 Insignias of the Dawn and 20 Insignias of the Crusade you may choose an item from the Argent Dawn\'s treasure cache.",
    ["T"] = "Superior Armaments of Battle - Honored Amongst the Dawn",
  },
