    ["D"] =
    "Greetings, friend. Have you insignias of the Dawn or the Crusade that you would like to redeem for items of great power?$B$BI must warn you; epic purchases made at revered reputation with the Dawn are still quite expensive. I would advise that you gain a better reputation with the Dawn before moving forward with your plans.",
    ["O"] =
    "For 45 Insignias of the Dawn and 45 Insignias of the Crusade you may choose an item from the Argent Dawn\'s treasure cache.",
    ["T"] = "Epic Armaments of Battle - Revered Amongst the Dawn",
  },
  [9226] = {
    ["D"] =
    "Greetings, friend. Have you insignias of the Dawn or the Crusade that you would like to redeem for items of power?$B$BItems offered to those revered amongst the Dawn are priced quite reasonably. I encourage you to make a purchase!",
    ["O"] =
    "For 7 Insignias of the Dawn and 7 Insignias of the Crusade you may choose an item from the Argent Dawn\'s treasure cache.",
    ["T"] = "Superior Armaments of Battle - Revered Amongst the Dawn",
