  [9323] = {
    ["D"] =
    "Our celebration of the flame is spread throughout the land, $C. Not a single place remains untouched by the heat of this holiday, and the strongest fires burn a brilliant blue. Seek them out.$B$BYou\'ll find one just north of Blackrock Spire. The others are located deep within the Eastern Plaguelands near a decrepit town, along the road to the cliffs within the mountainous Hinterlands, and on the way to the Dark Portal within the Blasted Lands.$B$BReturn once your journey is done.",
    ["O"] =
    "Visit the Fire Festival camps located in Blasted Lands, Eastern Plaguelands, the Hinterlands and Searing Gorge, then speak with the Festival Flamekeeper.",
    ["T"] = "Wild Fires in the Eastern Kingdoms",
  },
  [9324] = {
    ["D"] =
    "This flame, stolen from the heart of Orgrimmar itself, floods you with warmth. This raw power is foreign to you, but the Loremaster might know more...",
    ["O"] = "Return the Flame of Orgrimmar to the Festival Loremaster.",
    ["T"] = "Stealing Orgrimmar\'s Flame",
  },
  [9325] = {
    ["D"] =
    "This flame, stolen from the shaman of Thunder Bluff, floods you with warmth. This raw power is foreign to you, but the Loremaster might know more...",
    ["O"] = "Return the Flame of Thunder Bluff to the Festival Loremaster.",
    ["T"] = "Stealing Thunder Bluff\'s Flame",
  },
  [9326] = {
